-- Poems batch 366
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('aba4216f-85a5-4ad1-8ed3-75ba89a9b216','擬寒山寺  其一四一','釋懷深','宋','宋诗','song-poetry','','[]','入寺設僧齋，先且問客食。',48,'全唐诗/poet.song.81000.json','["入寺設僧齋，先且問客食。", "一味不可口，滿座皆啾唧。", "回顧憍陳如，鉢盂未嘗濕。", "恁麽說齋僧，有名而無實。"]'),
('03c5baaf-26af-4e3f-a7f7-55cd5c8ceec2','擬寒山寺  其一四二','釋懷深','宋','宋诗','song-poetry','','[]','辛苦置田園，歲收五千斛。',48,'全唐诗/poet.song.81000.json','["辛苦置田園，歲收五千斛。", "死了付兒孫，兒孫享其福。", "忌辰飯十僧，紙錢燒一束。", "人生爲子孫，所得何纖粟。"]'),
('41d08653-0720-4ca6-b866-b2612b5b19c5','擬寒山寺  其一四三','釋懷深','宋','宋诗','song-poetry','','[]','一年五千斛，十年計五萬。',48,'全唐诗/poet.song.81000.json','["一年五千斛，十年計五萬。", "不知十年間，所作何事辦。", "暴殄天物多，也好自思算。", "福若不消磨，除君是鐵漢。"]'),
('06014e68-5bc1-4b2c-bf3c-8be24f8d75d2','擬寒山寺  其一四四','釋懷深','宋','宋诗','song-poetry','','[]','人人要便宜，個個覓小利。',48,'全唐诗/poet.song.81000.json','["人人要便宜，個個覓小利。", "所爭能幾何，失卻大人體。", "饒人福自來，瞞人禍自至。", "此理甚分明，尚猶不瞥地。"]'),
('91c14acb-0b02-4b7e-9507-f21de0cc6b19','擬寒山寺  其一四五','釋懷深','宋','宋诗','song-poetry','','[]','傅大士種瓜，瓜熟人偷竊。',48,'全唐诗/poet.song.81000.json','["傅大士種瓜，瓜熟人偷竊。", "以籃熱園中，與偷便提挈。", "偷兒感此情，再拜心服悅。", "無爭與莫爭，盡向慈門攝。"]'),
('54c9a5e4-ea63-48fa-97df-6523a0fdcc1a','誡殺偈十首  其一','釋懷深','宋','宋诗','song-poetry','','[]','利刀活斫當腰斷，前脚猶能跳躑行。',32,'全唐诗/poet.song.81000.json','["利刀活斫當腰斷，前脚猶能跳躑行。", "看著衆生如是苦，異時果報不多爭。"]'),
('3a79e936-f210-4eed-b29b-82bf688ef94c','誡殺偈十首  其二','釋懷深','宋','宋诗','song-poetry','','[]','暇蟆蚾形模醜，咂矢爭蛆臭穢多。',31,'全唐诗/poet.song.81000.json','["暇蟆蚾形模醜，咂矢爭蛆臭穢多。", "涴卻娘生清凈口，只應笑倒老維摩。"]'),
('ef592ae8-5be3-49cd-bf22-4ed13bf6422e','誡殺偈十首  其三','釋懷深','宋','宋诗','song-poetry','','[]','蜆子師螺街市食，小人咀嚼繞臺盤。',32,'全唐诗/poet.song.81000.json','["蜆子師螺街市食，小人咀嚼繞臺盤。", "近來豪貴尊榮者，嗜好成風總一般。"]'),
('305b3582-6a70-48e3-b70f-c6318b5fc14d','誡殺偈十首  其四','釋懷深','宋','宋诗','song-poetry','','[]','吳人信向更無加，可惜時中善願差。',32,'全唐诗/poet.song.81000.json','["吳人信向更無加，可惜時中善願差。", "手掐數珠忙念佛，一邊叫喚買魚蝦。"]'),
('ccd5e204-8e2a-42ff-826b-81c25e0bebdf','誡殺偈十首  其五','釋懷深','宋','宋诗','song-poetry','','[]','聞說刀兵已皺眉，貪生畏死是人知。',32,'全唐诗/poet.song.81000.json','["聞說刀兵已皺眉，貪生畏死是人知。", "如何不恤他身苦，斬斫烹炮無厭時。"]'),
('f656734b-9532-4d57-9a0b-d49a5243a8f4','偈一百二十首  其一','釋懷深','宋','宋诗','song-poetry','','[]','不奈諸人苦再三，薄緣終是自多慚。',32,'全唐诗/poet.song.81000.json','["不奈諸人苦再三，薄緣終是自多慚。", "晨猿夜鶴應相笑，特地伸頭人鬧籃。"]'),
('a6ef44b5-463b-4dd3-ab13-510fe8ebbcca','偈一百二十首  其二','釋懷深','宋','宋诗','song-poetry','','[]','塵埋古鏡久偷安，匿耀潛輝度歲寒。',32,'全唐诗/poet.song.81000.json','["塵埋古鏡久偷安，匿耀潛輝度歲寒。", "今日光明藏不得，虛堂高掛任君看。"]'),
('aba7033e-896b-45c7-8b84-e95314af73d0','偈一百二十首  其三','釋懷深','宋','宋诗','song-poetry','','[]','摩竭當年獨掩關，銀山鐵壁莫追攀。',32,'全唐诗/poet.song.81000.json','["摩竭當年獨掩關，銀山鐵壁莫追攀。", "如今大施門開也，魔佛休分聽往還。"]'),
('1c403baf-61d0-40df-b6a7-d7b472daac75','偈一百二十首  其四','釋懷深','宋','宋诗','song-poetry','','[]','數間茅屋不堪憂，底事來爲粥飯頭。',32,'全唐诗/poet.song.81000.json','["數間茅屋不堪憂，底事來爲粥飯頭。", "賴有劫初鈴子在，隨貧隨富自風流。"]'),
('3e7a0966-6337-4b71-bf42-b9446eea184c','偈一百二十首  其五','釋懷深','宋','宋诗','song-poetry','','[]','年年此日是重陽，籬菊如聞去歲香。',32,'全唐诗/poet.song.81000.json','["年年此日是重陽，籬菊如聞去歲香。", "莫笑枝條太枯槁，從今別有好商量。"]'),
('3fbb1058-edc2-48c5-830a-1288d8be43cf','偈一百二十首  其六','釋懷深','宋','宋诗','song-poetry','','[]','門福一著，商量即錯。',20,'全唐诗/poet.song.81000.json','["門福一著，商量即錯。", "明眼衲僧，無繩自縛。"]'),
('69a86789-223a-4b7d-a770-df94f7138e2e','偈一百二十首  其七','釋懷深','宋','宋诗','song-poetry','','[]','資福一竅，最玄最妙。',20,'全唐诗/poet.song.81000.json','["資福一竅，最玄最妙。", "直下會得，教儞冷笑。"]'),
('b09f51ce-75bd-481c-b944-db985fbb58de','偈一百二十首  其八','釋懷深','宋','宋诗','song-poetry','','[]','有問有答周遮，無言無說話墮。',28,'全唐诗/poet.song.81000.json','["有問有答周遮，無言無說話墮。", "直饒頑石點頭，爭似歸堂向火。"]'),
('9b780348-e597-4acc-a5d5-f4d4c044a1a0','偈一百二十首  其九','釋懷深','宋','宋诗','song-poetry','','[]','失卻欄中白象兒，臨風笑倒老峨嵋。',32,'全唐诗/poet.song.81000.json','["失卻欄中白象兒，臨風笑倒老峨嵋。", "街頭措大無精鑒，一夜燈前賦雪詩。"]'),
('29aeb90a-d78f-4179-9d7a-e05d7019a900','偈一百二十首  其一○','釋懷深','宋','宋诗','song-poetry','','[]','春風掃盡庭前雪，暖日催開枝上花。',32,'全唐诗/poet.song.81000.json','["春風掃盡庭前雪，暖日催開枝上花。", "物物頭頭皆漏泄，莫教心地亂如麻。"]'),
('69afeea1-eaf8-4734-9ea2-825d97695bb2','偈一百二十首  其一一','釋懷深','宋','宋诗','song-poetry','','[]','衲僧不用看他燈，自有從前一盞明。',32,'全唐诗/poet.song.81000.json','["衲僧不用看他燈，自有從前一盞明。", "壞衲蒙頭面壁坐，靈光射破鐵圍城。"]'),
('0aaf69a8-94d5-4a1e-b996-3cb45aa70fbf','偈一百二十首  其一二','釋懷深','宋','宋诗','song-poetry','','[]','萬劫輪回妄想在，一心纔歇死生休。',32,'全唐诗/poet.song.81000.json','["萬劫輪回妄想在，一心纔歇死生休。", "佛魔是甚閑家具，撒手懸崖得自由。"]'),
('a3cd5f17-8de6-45d7-80ea-426936be935e','偈一百二十首  其一三','釋懷深','宋','宋诗','song-poetry','','[]','學道做工夫，正如人鑿井。',24,'全唐诗/poet.song.81000.json','["學道做工夫，正如人鑿井。", "一日見泉源，平生用不盡。"]'),
('fa871cb8-3eb3-4532-bc9c-5fadfc0ff315','偈一百二十首  其一四','釋懷深','宋','宋诗','song-poetry','','[]','仲春天氣喜初晴，燕語彫梁有好聲。',32,'全唐诗/poet.song.81000.json','["仲春天氣喜初晴，燕語彫梁有好聲。", "曾得玄沙當日意，便能日午打三更。"]'),
('872aea71-ba65-4c44-a5a5-cf3a65503162','偈一百二十首  其一五','釋懷深','宋','宋诗','song-poetry','','[]','漚生漚滅幾千回，只爲金剛眼不開。',32,'全唐诗/poet.song.81000.json','["漚生漚滅幾千回，只爲金剛眼不開。", "一日愛河波浪息，始知無去亦無來。"]'),
('0898679f-38da-4a87-b131-da0ab0606c4b','偈一百二十首  其一六','釋懷深','宋','宋诗','song-poetry','','[]','病瘳鶴骨瘦稜稜，說妙談玄總不能。',32,'全唐诗/poet.song.81000.json','["病瘳鶴骨瘦稜稜，說妙談玄總不能。", "賴有同行木上座，是渠強健更惺惺。"]'),
('5414b550-4282-47fe-895a-ca75a138876b','偈一百二十首  其一七','釋懷深','宋','宋诗','song-poetry','','[]','古人貧不及，今人富太過。',74,'全唐诗/poet.song.81000.json','["古人貧不及，今人富太過。", "唯有慈受叟，家風不恁麽。", "有油便點燈，有炭便向火。", "無油無炭時，大家黑處坐。", "坐得骨臀痛，長伸兩脚臥。", "天明起來喫粥，說甚迷逢達磨。"]'),
('a6b96d72-7c69-4c93-93fd-5b5bc0f3e35f','偈一百二十首  其一八','釋懷深','宋','宋诗','song-poetry','','[]','道在何曾在間然，休分城市與林泉。',32,'全唐诗/poet.song.81000.json','["道在何曾在間然，休分城市與林泉。", "重來痂法棲禪處，依舊清風滿目前。"]'),
('1134683f-6a98-467e-8590-2a1176724e5b','偈一百二十首  其一九','釋懷深','宋','宋诗','song-poetry','','[]','今朝一陽生，明日便數九。',48,'全唐诗/poet.song.81000.json','["今朝一陽生，明日便數九。", "張三依舊肥，李四從來瘠。", "喫盡天下藥，舊病依前有。", "用盡自家心，笑破他人口。"]'),
('810f1411-eee7-434c-a06d-5cdb2e21b34c','偈一百二十首  其二○','釋懷深','宋','宋诗','song-poetry','','[]','一夜翻空大雪，玉殿銀樓皎潔。',28,'全唐诗/poet.song.81000.json','["一夜翻空大雪，玉殿銀樓皎潔。", "曉來庭際無人，莫道山僧不說。"]'),
('93436e18-41de-4fbb-800c-21aa87582256','偈一百二十首  其二一','釋懷深','宋','宋诗','song-poetry','','[]','東風吹盡曉天雲，大地山河總變春。',32,'全唐诗/poet.song.81000.json','["東風吹盡曉天雲，大地山河總變春。", "不用當門書大吉，個中無鬼亦無神。"]'),
('44c74494-d7d9-4b07-9ebd-71c9c815a4db','偈一百二十首  其二二','釋懷深','宋','宋诗','song-poetry','','[]','雲門劄，資福收。',50,'全唐诗/poet.song.81000.json','["雲門劄，資福收。", "一擒一縱，各有來由。", "昨夜春風吹樹尾，曉來紅日上雲頭。", "翻笑雙林傅大士，卻道橋流水不流。"]'),
('d7c1242d-a84c-4e19-abc8-fd8d7b0e6820','偈一百二十首  其二三','釋懷深','宋','宋诗','song-poetry','','[]','夜來燈燭鬬熒煌，多少衆生徹曉忙。',32,'全唐诗/poet.song.81000.json','["夜來燈燭鬬熒煌，多少衆生徹曉忙。", "究竟不知燈是火，昧卻靈臺一點光。"]'),
('56c2fa02-53da-4812-bb3e-d9e2f096dc87','偈一百二十首  其二四','釋懷深','宋','宋诗','song-poetry','','[]','今朝喫粥太晚，徐六街頭擔飯。',56,'全唐诗/poet.song.81000.json','["今朝喫粥太晚，徐六街頭擔飯。", "只知打鼓陞堂，不覺又是喫飯。", "喫粥了喫飯，喫飯了喫粥。", "清風月下守株人，涼兔漸遙春草綠。"]'),
('c22d02e1-e8d3-445f-b4e3-52b9879b2368','偈一百二十首  其二五','釋懷深','宋','宋诗','song-poetry','','[]','太平山下曾相見，撫掌呵呵笑臉開。',32,'全唐诗/poet.song.81000.json','["太平山下曾相見，撫掌呵呵笑臉開。", "莫怪嘉聲騰萬口，杖藜方自日邊來。"]'),
('eb4bf8ef-cb55-4778-84e1-402c16c35ceb','偈一百二十首  其二六','釋懷深','宋','宋诗','song-poetry','','[]','金輪御世乾坤永，玉燭調時宇宙明。',32,'全唐诗/poet.song.81000.json','["金輪御世乾坤永，玉燭調時宇宙明。", "桃李無言春爛熳，不知何以報昇平。"]'),
('5f771408-bc0d-4496-b254-c96a7f976025','偈一百二十首  其二七','釋懷深','宋','宋诗','song-poetry','','[]','流注真常幾萬回，虛空無去亦無來。',32,'全唐诗/poet.song.81000.json','["流注真常幾萬回，虛空無去亦無來。", "個中何地容生死，打破當堂明鏡統。"]'),
('e5a64e01-4dfd-440f-b91f-cedcca2db04a','偈一百二十首  其二八','釋懷深','宋','宋诗','song-poetry','','[]','天面雁橫七八點，海門日上兩三竿。',32,'全唐诗/poet.song.81000.json','["天面雁橫七八點，海門日上兩三竿。", "祖師心印分明在，自是時人不解看。"]'),
('065d80a1-cfab-4a31-a019-b05cf3bd341a','偈一百二十首  其二九','釋懷深','宋','宋诗','song-poetry','','[]','心境頓消融，方明色與空。',24,'全唐诗/poet.song.81000.json','["心境頓消融，方明色與空。", "欲識本來體，青山白雲中。"]'),
('5f75c2a2-2c22-4618-98c0-d04f6a20f7ea','偈一百二十首  其三○','釋懷深','宋','宋诗','song-poetry','','[]','心境頓消融，方明色與空。',26,'全唐诗/poet.song.81000.json','["心境頓消融，方明色與空。", "欲識本來體，海裏使風山上船。"]'),
('0ff96eb1-19b4-49a7-a3d0-1adf1fd8081e','偈一百二十首  其三一','釋懷深','宋','宋诗','song-poetry','','[]','四維上下白漫漫，玉殿瓊樓正好看。',32,'全唐诗/poet.song.81000.json','["四維上下白漫漫，玉殿瓊樓正好看。", "任是黑風吹海立，渠儂門戶不相干。"]'),
('36b84ebe-6e4a-4a13-baab-34e6c34c4e5d','偈一百二十首  其三二','釋懷深','宋','宋诗','song-poetry','','[]','時人皆拜歲，山僧不賀年。',48,'全唐诗/poet.song.81000.json','["時人皆拜歲，山僧不賀年。", "孟春猶寒在，日月幾曾遷。", "去年今日後，今日去年年。", "新舊不同者，誰後復誰先。"]'),
('24f0601b-c77c-4198-90b1-b109ac4ef780','偈一百二十首  其三三','釋懷深','宋','宋诗','song-poetry','','[]','時人皆拜歲，山僧也賀年。',48,'全唐诗/poet.song.81000.json','["時人皆拜歲，山僧也賀年。", "光明一點在，從聽二輪遷。", "順俗高叉手，和光小說禪。", "個中如會得，佛祖本無傳。"]'),
('9a3528b0-3832-4c43-86e3-80c2eae662e6','偈一百二十首  其三四','釋懷深','宋','宋诗','song-poetry','','[]','三年住此空花相，今日歸歟水月同。',60,'全唐诗/poet.song.81000.json','["三年住此空花相，今日歸歟水月同。", "去住不須論彼此，人生萬事轉頭空。", "修習空花萬行，宴坐水月道場。", "降伏鏡裏魔軍，成就夢中佛事。"]'),
('49519654-d86a-442c-85f1-815de674625a','偈一百二十首  其三五','釋懷深','宋','宋诗','song-poetry','','[]','九重天上官家敕，喚起西菴瞌睡人。',32,'全唐诗/poet.song.81000.json','["九重天上官家敕，喚起西菴瞌睡人。", "爲瑞爲祥人莫問，金毛師子玉麒麟。"]'),
('99b154b2-6727-4c9f-8d3d-4fc43768cb9f','偈一百二十首  其三六','釋懷深','宋','宋诗','song-poetry','','[]','？忻得計掩深關，口醭心灰一味閑。',32,'全唐诗/poet.song.81000.json','["？忻得計掩深關，口醭心灰一味閑。", "自笑行藏無料處，又隨緣業過焦山。"]'),
('92b9c790-48a5-4fca-aded-c5028924bc29','偈一百二十首  其三七','釋懷深','宋','宋诗','song-poetry','','[]','一室寥寥是何物，三賢十聖竭頭參。',32,'全唐诗/poet.song.81000.json','["一室寥寥是何物，三賢十聖竭頭參。", "衲僧不會風前句，擬欲思量落二三。"]'),
('2316cde0-78d9-4e77-bc2d-475ddb16508c','偈一百二十首  其三八','釋懷深','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','白蘋紅蓼岸邊秋，短槳輕帆與自由。',32,'全唐诗/poet.song.81000.json','["白蘋紅蓼岸邊秋，短槳輕帆與自由。", "要會到這一句子，長江依舊水東流。"]'),
('862ed70f-ccc5-4c1b-8295-28f204a60b4a','偈一百二十首  其三九','釋懷深','宋','宋诗','song-poetry','','[]','十一月二十，喚做大冬日。',59,'全唐诗/poet.song.81000.json','["十一月二十，喚做大冬日。", "張三賀鄭婆，李四拜王七。", "早辰到夜，費盡平生力。", "唯有衲僧家，不打者鼓笛。", "鐵額崑崙兒，通身黑如漆。"]'),
('1fbca5e1-277e-4d42-8812-b1dc5af00daf','偈一百二十首  其四○','釋懷深','宋','宋诗','song-poetry','','[]','瞿曇學道時，菩提樹下坐。',68,'全唐诗/poet.song.81000.json','["瞿曇學道時，菩提樹下坐。", "忽爾見明星，漆桶便打破。", "纔打破始信，從前燈是火。", "今人學道不悟道，義路推尋外邊討。", "更說從來無悟迷，大似團圝吞卻棗。"]'),
('9eb6ff4a-a689-43e5-ac7a-acc0d90b4a12','偈一百二十首  其四一','釋懷深','宋','宋诗','song-poetry','','[]','今日端午謝街坊，時節因緣要舉揚。',32,'全唐诗/poet.song.81000.json','["今日端午謝街坊，時節因緣要舉揚。", "莫問腕頭纏百索，且將粽子喫沙糖。"]'),
('0daf8233-4d6b-4b8d-b0fd-6d95e9c61a09','偈一百二十首  其四二','釋懷深','宋','宋诗','song-poetry','','[]','是柱不見柱，一句超今古。',24,'全唐诗/poet.song.81000.json','["是柱不見柱，一句超今古。", "夜來石公山，有個歡喜處。"]'),
('88fb9c3b-c0f8-4130-893b-678ecd0023f3','偈一百二十首  其四三','釋懷深','宋','宋诗','song-poetry','','[]','焦山句句是藥，祇要時人安樂。',56,'全唐诗/poet.song.81000.json','["焦山句句是藥，祇要時人安樂。", "費盡巴豆砒霜，轉見七零八落。", "諸人步步是病，終日頭旋眼運。", "祇管以火救火，不解頭正尾正。"]'),
('e8d41fd5-d635-42bd-be8b-05932c602ab3','偈一百二十首  其四四','釋懷深','宋','宋诗','song-poetry','','[]','宗門標致久凄涼，佛鑑山頭又坐亡。',32,'全唐诗/poet.song.81000.json','["宗門標致久凄涼，佛鑑山頭又坐亡。", "昨夜燈前即屈指，不知誰解整頹綱。"]'),
('871aa009-e8e7-4c7a-92de-b60fd06990ad','偈一百二十首  其四五','釋懷深','宋','宋诗','song-poetry','','[]','惆悵鍾山老水牯，去住縱橫無必固。',100,'全唐诗/poet.song.81000.json','["惆悵鍾山老水牯，去住縱橫無必固。", "拔禊抽釘二十年，咬盡生薑呷盡醋。", "有時貧，有時富，誰會南山狗咬虎。", "紛紛衲子數如麻，不知誰解吞蓬句，聽取焦山重指注。", "若道鍾山有句，大似如藤倚樹。", "若道鍾山無句，正是沈埋佛祖。"]'),
('45ef28c5-c5f8-4853-a12a-f086fd9c7937','偈一百二十首  其四六','釋懷深','宋','宋诗','song-poetry','','[]','江月照，松風吹，永夜清霄何所爲。',32,'全唐诗/poet.song.81000.json','["江月照，松風吹，永夜清霄何所爲。", "若是曹溪門下客，相逢不必更揚眉。"]'),
('86b4d525-8246-47f1-9ce4-90ca04e7a094','偈一百二十首  其四七','釋懷深','宋','宋诗','song-poetry','','[]','扁舟何事渡江來，林底相逢笑臉開。',32,'全唐诗/poet.song.81000.json','["扁舟何事渡江來，林底相逢笑臉開。", "鹽米不須重話會，要須舌上起風雷。"]'),
('9079136a-8f66-4b11-9c95-987dbe60cf1f','偈一百二十首  其四八','釋懷深','宋','宋诗','song-poetry','','[]','有一皆伎倆，盡是人妄想。',24,'全唐诗/poet.song.81000.json','["有一皆伎倆，盡是人妄想。", "少府打手力，笑殺韓官長。"]'),
('c405d08d-8942-499d-bd3c-c806a99957a0','偈一百二十首  其四九','釋懷深','宋','宋诗','song-poetry','','[]','佛從大悲心，流出十二部。',212,'全唐诗/poet.song.81000.json','["佛從大悲心，流出十二部。", "瑯函與玉軸，遍滿河沙數。", "言言皆妙藥，字字超今古。", "譬如優曇花，百劫難遭遇。", "又如大明燈，能破黑暗處。", "又如智慧力，能斷無明樹。", "又如瓔珞珠，能使人豐富。", "茫茫塵世人，急急走如兔。", "不覺老到來，未嘗開眼覷。", "獨有花評事，信向頗堅固。", "命我無心人，轉此諸佛語。", "浮生一百年，正如草頭露。", "上牀鞋履別，保朝不保暮。", "少喫兩塊肉，多燒香一炷。", "羊鹿牛三車，皆行此條路。", "鶴態雲蹤不定居，白沙一別半年餘。", "焦山脚下重相見，記得當時事也無。"]'),
('09e36669-f55e-4b25-bcd8-5340101c0c59','偈一百二十首  其五○','釋懷深','宋','宋诗','song-poetry','','[]','焦山熱肺腸，有事便要了。',52,'全唐诗/poet.song.81000.json','["焦山熱肺腸，有事便要了。", "今歲閏九月，來年春氣早。", "頂門三隻眼，常要光皎皎。", "照顧溈山水牯牛，莫教喫卻他人草。"]'),
('039768a8-40a0-4e25-acbf-4913e0721828','偈一百二十首  其五一','釋懷深','宋','宋诗','song-poetry','','[]','焦山僻在海門邊，得到其中是夙緣。',32,'全唐诗/poet.song.81000.json','["焦山僻在海門邊，得到其中是夙緣。", "要會相逢一句子，春風依舊似當年。"]'),
('2e538b8d-2574-4a60-b450-ebf139bd009e','偈一百二十首  其五二','釋懷深','宋','宋诗','song-poetry','','[]','春色無高下，春雷動地音。',24,'全唐诗/poet.song.81000.json','["春色無高下，春雷動地音。", "翻空一夜雨，滴破祖師心。"]'),
('78167051-b1e8-4ede-8e10-c97a7ff389ac','偈一百二十首  其五三','釋懷深','宋','宋诗','song-poetry','','[]','焦山無變豹，一味勸人休。',48,'全唐诗/poet.song.81000.json','["焦山無變豹，一味勸人休。", "衆生顛倒甚，撥火覓浮漚。", "石鞏駕弓箭，俱胝竪指頭。", "直下歇得去，都如椀脫丘。"]'),
('2b62b62b-25b2-40a3-a3f5-df520a0da7eb','偈一百二十首  其五四','釋懷深','宋','宋诗','song-poetry','','[]','迷時境上千般有，悟去心中一物無。',32,'全唐诗/poet.song.81000.json','["迷時境上千般有，悟去心中一物無。", "若會笑聲還似哭，方知生與死同途。"]'),
('244b4403-ff94-4e5f-aa52-4a850feacdbd','偈一百二十首  其五五','釋懷深','宋','宋诗','song-poetry','','[]','動絃別曲，葉落知秋。',48,'全唐诗/poet.song.81000.json','["動絃別曲，葉落知秋。", "隔牆見角，便知是牛。", "伶俐衲僧，纔眨眼商量，已落第三籌。", "休休，不如無事掛心頭。"]'),
('e21a5f07-7b38-464b-88f7-5d050f3564ab','偈一百二十首  其五六','釋懷深','宋','宋诗','song-poetry','','[]','吾有一言，絕慮忘緣。',20,'全唐诗/poet.song.81000.json','["吾有一言，絕慮忘緣。", "巧說不得，祇要心傳。"]'),
('641a5a7d-12cb-46c5-a1de-6b720d9129ea','偈一百二十首  其五七','釋懷深','宋','宋诗','song-poetry','','[]','我笑禪和子，茫茫能地頭。',24,'全唐诗/poet.song.81000.json','["我笑禪和子，茫茫能地頭。", "隨人語脈轉，何日得心休。"]'),
('e518d7fc-e9e4-4ef0-b47c-4ac86d5ed5f5','偈一百二十首  其五八','釋懷深','宋','宋诗','song-poetry','','[]','滔滔生死海無涯，綠鬢朱顔未足誇。',32,'全唐诗/poet.song.81000.json','["滔滔生死海無涯，綠鬢朱顔未足誇。", "五藴山頭雲散後，不知明月落誰家。"]'),
('8be2dd68-19b3-411f-ae67-ccc091436330','偈一百二十首  其五九','釋懷深','宋','宋诗','song-poetry','','[]','不是境，亦非心，喚作佛時也陸沈。',56,'全唐诗/poet.song.81000.json','["不是境，亦非心，喚作佛時也陸沈。", "個中本自無階級，切忌無階級處尋。", "總不尋，過尤深，打破雲門飯袋子，方知赤土是黄金。"]'),
('7309b06e-0b7c-42ee-a667-72e5b6e4ea0d','偈一百二十首  其六○','釋懷深','宋','宋诗','song-poetry','','[]','紅杏枝頭小雨乾，東風特地作春寒。',32,'全唐诗/poet.song.81000.json','["紅杏枝頭小雨乾，東風特地作春寒。", "祖師門戶無遮障，祇要時人著眼看。"]'),
('959f58f7-191e-4ca0-8144-51266e6c2faa','偈一百二十首  其六一','釋懷深','宋','宋诗','song-poetry','','[]','四年兩受官家敕，玉璨珠華耀海門。',32,'全唐诗/poet.song.81000.json','["四年兩受官家敕，玉璨珠華耀海門。", "鼓舞堯風聊自愧，不知何以答君恩。"]'),
('1e278783-933f-48ef-abc1-0a0ae1b6b94d','偈一百二十首  其六二','釋懷深','宋','宋诗','song-poetry','','[]','隈巖傍水養衰殘，不謂虛名落世間。',32,'全唐诗/poet.song.81000.json','["隈巖傍水養衰殘，不謂虛名落世間。", "到此更無迴避處，只應笑倒石公山。"]'),
('720507c1-4442-4f4c-85df-0e4039fc2d5f','偈一百二十首  其六三','釋懷深','宋','宋诗','song-poetry','','[]','虎穴門前曾宴坐，龍牀角畔去談禪。',32,'全唐诗/poet.song.81000.json','["虎穴門前曾宴坐，龍牀角畔去談禪。", "睹人莫苦生離思，風月從來共一天。"]'),
('9876f4a0-5ac8-40d5-af08-e6346b7e0c1d','偈一百二十首  其六四','釋懷深','宋','宋诗','song-poetry','','[]','住亦隨緣去是常，山林城市兩無妨。',32,'全唐诗/poet.song.81000.json','["住亦隨緣去是常，山林城市兩無妨。", "白雲本是無心物，一任風吹入帝鄉。"]'),
('ba4cf465-1664-4ee5-8ac9-f47be9726ead','偈一百二十首  其六五','釋懷深','宋','宋诗','song-poetry','','[]','一居丈室，家風壁立。',36,'全唐诗/poet.song.81000.json','["一居丈室，家風壁立。", "把斷重關，有誰敢入。", "直饒鐵眼銅睛漢，也是門頭戶底人。"]'),
('835bc0e0-ced9-4f70-83bd-61415b65cfce','偈一百二十首  其六六','釋懷深','宋','宋诗','song-poetry','','[]','物物頭頭不覆藏，須彌高廣露堂堂。',32,'全唐诗/poet.song.81000.json','["物物頭頭不覆藏，須彌高廣露堂堂。", "要知此曲無音韻，更對薰風舞一場。"]'),
('008552cf-0987-43c7-b34f-5e0cb9b5d331','偈一百二十首  其六七','釋懷深','宋','宋诗','song-poetry','','[]','氣息纔通不可收，一回拈起一回羞。',32,'全唐诗/poet.song.81000.json','["氣息纔通不可收，一回拈起一回羞。", "威音王外難分雪，殃及兒孫卒未休。"]'),
('31238289-349d-4813-9417-5f1efab939ae','偈一百二十首  其六八','釋懷深','宋','宋诗','song-poetry','','[]','今年兩次逢端午，不須更打劃船鼓。',60,'全唐诗/poet.song.81000.json','["今年兩次逢端午，不須更打劃船鼓。", "金剛門外笑呵呵，一夜通身汗如雨。", "汗如雨，不須言，犀牛扇子亦陡然。", "舊山多積雪，歸去是何年。"]'),
('d0ea179b-0f30-4fa7-8c79-e0ac94ea1d85','偈一百二十首  其六九','釋懷深','宋','宋诗','song-poetry','','[]','一切有爲法，如夢幻泡影。',71,'全唐诗/poet.song.81000.json','["一切有爲法，如夢幻泡影。", "如露亦如電，應作如是觀。", "釋迦老子，只知其一，不知其二。", "幻化空身即法身，個中無染亦無塵。", "拈匙把筯如明了，掃地燒香不倩人。"]'),
('1914d186-6400-4b96-afe4-baf1cf03d7e4','偈一百二十首  其七○','釋懷深','宋','宋诗','song-poetry','','[]','趙州住院二十年，折脚禪床欠一邊。',128,'全唐诗/poet.song.81000.json','["趙州住院二十年，折脚禪床欠一邊。", "灰頭土面半饑餓，苦澀家風今古傳。", "翻笑今人做長老，恰似官人問職田。", "職田多，我便去，免見鉢盂無著處。", "職田少，我不去，生怕沒鹽兼沒醋。", "禪門難得好兒孫，正眼近來如掃土。", "慧林首座久韜藏，箇中果熟自然香。", "大海釣魚拚得失，空船歸去也無妨。"]'),
('dfc91aec-cde7-441e-8d97-e87622b25663','偈一百二十首  其七一','釋懷深','宋','宋诗','song-poetry','','[]','一鉢迢迢歷數州，朱門白屋信緣求。',32,'全唐诗/poet.song.81000.json','["一鉢迢迢歷數州，朱門白屋信緣求。", "如今繭足歸來也，自在溈山一牯牛。"]'),
('03c577bb-393a-4eba-aa0e-8e0fb11433df','偈一百二十首  其七二','釋懷深','宋','宋诗','song-poetry','','[]','拍手相逢笑不休，本來無證亦無修。',32,'全唐诗/poet.song.81000.json','["拍手相逢笑不休，本來無證亦無修。", "人人盡是阿羅漢，何必天台雁蕩求。"]'),
('b58da767-1ab3-41f1-9571-4efbcd5b8f9f','偈一百二十首  其七三','釋懷深','宋','宋诗','song-poetry','','[]','長夏無別趣，調和羹一釜。',48,'全唐诗/poet.song.81000.json','["長夏無別趣，調和羹一釜。", "滋味頗馨香，剛地成點污。", "口是禍之門，舌是斬身斧。", "陪卻三斤鐵，只因看錮鏴。"]'),
('2558e352-64dd-4639-9b6c-4aa8c3a5ee8a','偈一百二十首  其七四','釋懷深','宋','宋诗','song-poetry','','[]','慧林小院子，恰似一隻船。',84,'全唐诗/poet.song.81000.json','["慧林小院子，恰似一隻船。", "終日行上水，須得衆人牽。", "出入底出入，說禪底說禪。", "做飯底做飯，打眠底打眠。", "有時甜似蜜，有時苦如連。", "恁麽度衆生，笑倒老金仙。", "若問西來意，令人肚裏煎。"]'),
('208adeb4-111e-441a-a6d2-55a892896287','偈一百二十首  其七五','釋懷深','宋','宋诗','song-poetry','','["\u6ed5\u738b\u9601"]','滕王閣畔遙招手，汴水堤邊未點頭。',32,'全唐诗/poet.song.81000.json','["滕王閣畔遙招手，汴水堤邊未點頭。", "要得錦鱗來上釣，大家撐動木蘭舟。"]'),
('28a5c1b8-6df9-475c-8b17-dde822aa5d8a','偈一百二十首  其七六','釋懷深','宋','宋诗','song-poetry','','[]','以法傳心，似衣表信。',36,'全唐诗/poet.song.81000.json','["以法傳心，似衣表信。", "黄梅山頭，白蓮峰頂。", "分付曹溪路上人，一模鑄就黄金印。"]'),
('89c584bb-3367-46eb-9f23-c7e9df9cc597','偈一百二十首  其七七','釋懷深','宋','宋诗','song-poetry','','[]','今朝四月十五，已見炎炎酷暑。',86,'全唐诗/poet.song.81000.json','["今朝四月十五，已見炎炎酷暑。", "只宜搖扇飲水，豈可譚今引古。", "卻請九仙長老，傾些清涼法雨。", "衆中釘觜禪和，便好出來進步。", "問教口似磉盤，始信長老難做。", "親長老，自照顧，發機須是千鈞弩。"]'),
('c9436070-50ac-44c7-84b5-0f1692c68bea','偈一百二十首  其七八','釋懷深','宋','宋诗','song-poetry','','[]','慧林投老入紅塵，俯仰三年成跺權。',32,'全唐诗/poet.song.81000.json','["慧林投老入紅塵，俯仰三年成跺權。", "自笑欲歸歸未得，時時送客出都城。"]'),
('102c20d0-7668-4721-859f-822ce4565d34','偈一百二十首  其七九','釋懷深','宋','宋诗','song-poetry','','[]','世事悠悠，不如山丘。',56,'全唐诗/poet.song.81000.json','["世事悠悠，不如山丘。", "青松散日，碧澗長流。", "山雲當幕，夜月爲鈎。", "臥藤蘿下，塊石枕頭。", "饑餐混飲渾無事，自在溈山水牯牛。"]'),
('674906c2-bef1-41d7-ace8-5c6488e197e1','偈一百二十首  其八○','釋懷深','宋','宋诗','song-poetry','','[]','著黑衣，護黑柱。',70,'全唐诗/poet.song.81000.json','["著黑衣，護黑柱。", "虎不食斑，惡傷其侶。", "云何獅子身中蟲，終朝返食獅子血。", "忍痛金毛不作聲，箇中滋味難分雪。", "從咬囓，願爾回光返照時，始信虛空無兩舌。"]'),
('51cc5eab-e7ba-47e9-95aa-7b847b546123','偈一百二十首  其八一','釋懷深','宋','宋诗','song-poetry','','[]','下初死卻爺共娘，二十餘興年割不斷。',65,'全唐诗/poet.song.81000.json','["下初死卻爺共娘，二十餘興年割不斷。", "今朝打破骨董箱，請我陞堂舉公案。", "古靈平地起風波，瞌睡禪人不奈何。", "地獄天堂都莫問，大家隨例喫燠鵝。"]'),
('143c38d9-365b-4e33-9eda-860be2bc8307','偈一百二十首  其八二','釋懷深','宋','宋诗','song-poetry','','[]','佛病與祖病，衆生心上疑。',84,'全唐诗/poet.song.81000.json','["佛病與祖病，衆生心上疑。", "情塵一念脫，消散如風吹。", "試問諸病源，起滅從何依。", "來從何所來，去向何所歸。", "若能直下見，苦痛無毫釐。", "不見維摩老，文殊問疾時。", "聚頭說藥方，失卻獅子兒。"]'),
('243e0fa0-4852-4d20-a0a3-b506f6aa1ee8','偈一百二十首  其八三','釋懷深','宋','宋诗','song-poetry','','[]','得者長生，服之不死。',51,'全唐诗/poet.song.81000.json','["得者長生，服之不死。", "神農不知名，耆婆無處討。", "破除佛祖病，掃蕩無明煩惱。", "物物頭頭不覆藏，靈光洞耀何人曉。"]'),
('dc263acf-df23-47a5-8991-54d9a83da568','偈一百二十首  其八四','釋懷深','宋','宋诗','song-poetry','','[]','過去事如夢，了然無罅縫。',72,'全唐诗/poet.song.81000.json','["過去事如夢，了然無罅縫。", "要當做夢時，便作覺時用。", "未來事如電，有無不可見。", "莫將希望心，昧卻娘生面。", "見在事如雲，目前仿佛有。", "安得東南風，吹散西山口。"]'),
('848eb129-d74c-4f5e-8ca5-ff0afccb0ac1','偈一百二十首  其八五','釋懷深','宋','宋诗','song-poetry','','[]','十年做長老，今年鬧吵吵。',88,'全唐诗/poet.song.81000.json','["十年做長老，今年鬧吵吵。", "思量世間事，佛也不可曉。", "昨日買箇卦，卜道來年好。", "財帛星入門，虛耗鬼去了。", "知事與頭首，各著些孔竅。", "盛點兩甌茶，多陪一面笑。", "大家說些快活禪，免教拄杖生煩惱。"]'),
('d879961e-0d35-47b6-9ba9-cce8532204d9','偈一百二十首  其八六','釋懷深','宋','宋诗','song-poetry','','[]','大悲時時降生，諸佛頭頭無間。',28,'全唐诗/poet.song.81000.json','["大悲時時降生，諸佛頭頭無間。", "者裏裂破面門，薦取通身手眼。"]'),
('cfca0ce2-4d8a-4d98-b2ad-407b8302d2f9','偈一百二十首  其八七','釋懷深','宋','宋诗','song-poetry','','[]','時節因緣自有由，知音千里遠相求。',32,'全唐诗/poet.song.81000.json','["時節因緣自有由，知音千里遠相求。", "寒山陌上纔招手，拾得溪邊已點頭。"]'),
('3035ab9a-3fc0-4013-9525-1c4eff41d122','偈一百二十首  其八八','釋懷深','宋','宋诗','song-poetry','','[]','五葉花敷大地春，泥牛鞭起著精神。',32,'全唐诗/poet.song.81000.json','["五葉花敷大地春，泥牛鞭起著精神。", "好將一葦堂前曲，舉向東州路上人。"]'),
('b2032631-333a-4ea8-9936-b26ce5c3fbbe','偈一百二十首  其八九','釋懷深','宋','宋诗','song-poetry','','[]','曉來雨過地無塵，綠暗紅疏爛熳春。',32,'全唐诗/poet.song.81000.json','["曉來雨過地無塵，綠暗紅疏爛熳春。", "拄杖花開人不會，等閑昧卻本來身。"]'),
('ae76672d-4c4a-4229-a9a0-bf1d9847084d','偈一百二十首  其九○','釋懷深','宋','宋诗','song-poetry','','[]','春睡不知曉，覺來天已光。',48,'全唐诗/poet.song.81000.json','["春睡不知曉，覺來天已光。", "七條衣未著，五味粥先香。", "宰相雞鳴起，凡夫徹夜忙。", "不知禪和子，將底報君王。"]'),
('d1f2bc00-6267-4c6d-a83c-534e76f7fe25','偈一百二十首  其九一','釋懷深','宋','宋诗','song-poetry','','[]','白日人事勞攘，夜裏只了瞌睡。',28,'全唐诗/poet.song.81000.json','["白日人事勞攘，夜裏只了瞌睡。", "忘記安排說禪，且望諸人不罪。"]'),
('c9b332bd-0d73-46ee-9cd6-eb7877e37efd','偈一百二十首  其九二','釋懷深','宋','宋诗','song-poetry','','[]','千般說，萬般喻，特地令人轉不悟。',32,'全唐诗/poet.song.81000.json','["千般說，萬般喻，特地令人轉不悟。", "西風昨夜泄天機，鬰鬰黄花香滿路。"]'),
('d21042b9-171f-4104-8183-aa27dc928682','偈一百二十首  其九三','釋懷深','宋','宋诗','song-poetry','','[]','欣逢誕聖時，無以報明主。',52,'全唐诗/poet.song.81000.json','["欣逢誕聖時，無以報明主。", "唯憑一炷香，更擊三通鼓。", "唱起太平歌，共行向上路。", "只願堯天日月長，待見黄河清萬度。"]'),
('0ce1ce34-63f7-4f04-850f-dc2ab232de65','偈一百二十首  其九四','釋懷深','宋','宋诗','song-poetry','','[]','北風如箭射庭除，冷落禪門一物無。',96,'全唐诗/poet.song.81000.json','["北風如箭射庭除，冷落禪門一物無。", "多謝諸人相暖熱，殷勤爲我作開爐。", "老僧來慧林，四見書雲節。", "不解巧逢迎，豈敢多饒舌。", "瞋即聽你瞋，拙即從我拙。", "要透祖師關，放教心地歇。", "若不歇，臘月三十日，一時都敗闕。"]'),
('16f1c4fc-f11b-469f-b34c-87676d432de2','偈一百二十首  其九五','釋懷深','宋','宋诗','song-poetry','','[]','十年持釣在江湖，蒻笠簑衣只自如。',32,'全唐诗/poet.song.81000.json','["十年持釣在江湖，蒻笠簑衣只自如。", "忽爾竿頭浮子動，等閑釣得一頭魚。"]'),
('6a950e26-fbcd-4072-9f53-d4530195ca7e','偈一百二十首  其九六','釋懷深','宋','宋诗','song-poetry','','[]','慧林鐵饅頭，做來年已久。',48,'全唐诗/poet.song.81000.json','["慧林鐵饅頭，做來年已久。", "不是不拈出，自是人不受。", "覷著齒牙寒，咬著眉頭皺。", "不是張鵬舉，誰人敢下口。"]'),
('81820f98-039d-4118-b65b-c237032ab47d','偈一百二十首  其九七','釋懷深','宋','宋诗','song-poetry','','[]','祖師妙訣，頭頭漏泄。',53,'全唐诗/poet.song.81000.json','["祖師妙訣，頭頭漏泄。", "衆生日用不知，只管強生分別。", "豈不見靈雲陌上桃花，趙州指出庭前柏。", "別別，正似紅爐一點雪。"]'),
('0051f5f3-88c4-496c-8775-146ff3fb1aa5','偈一百二十首  其九八','釋懷深','宋','宋诗','song-poetry','','[]','夜來看上元，一覺到天曉。',24,'全唐诗/poet.song.81000.json','["夜來看上元，一覺到天曉。", "紙被暖如春，被底呵呵笑。"]'),
('0ad42610-fee5-463d-bd8e-1e31560889e3','偈一百二十首  其九九','釋懷深','宋','宋诗','song-poetry','','[]','寒食清明都過了，野桃紅杏已凋零。',32,'全唐诗/poet.song.81000.json','["寒食清明都過了，野桃紅杏已凋零。", "多時不聽簷頭雨，特地令人憶鏡清。"]'),
('61fde575-735f-4277-bc6b-212619eb69be','偈一百二十首  其一○○','釋懷深','宋','宋诗','song-poetry','','[]','十方同聚會，箇箇學無爲。',24,'全唐诗/poet.song.81000.json','["十方同聚會，箇箇學無爲。", "此是選佛場，心空及第歸。"]'),
('ce01f6d1-107f-48ce-a9e9-5cfee9a5ef24','偈一百二十首  其一○一','釋懷深','宋','宋诗','song-poetry','','[]','四海五湖人，慧林同禁足。',48,'全唐诗/poet.song.81000.json','["四海五湖人，慧林同禁足。", "譬如學牧牛，身心要淳熟。", "常耕自己田，莫犯他人穀。", "一句若參差，九旬何面目。"]'),
('6f4e7af1-876e-4058-9baa-709f7ebd35b0','偈一百二十首  其一○二','釋懷深','宋','宋诗','song-poetry','','[]','萬法是心光，諸緣唯性曉。',24,'全唐诗/poet.song.81000.json','["萬法是心光，諸緣唯性曉。", "衲僧恁麽會，鑽頭入荒草。"]'),
('ced3dd8a-2784-4298-be93-5c9b5c9e4dfe','偈一百二十首  其一○三','釋懷深','宋','宋诗','song-poetry','','[]','身心一如，身外無餘。',20,'全唐诗/poet.song.81000.json','["身心一如，身外無餘。", "便恁麽會，緣木求魚。"]'),
('a8dc2e78-0b87-4aa3-8f83-146972981c94','偈一百二十首  其一○四','釋懷深','宋','宋诗','song-poetry','','[]','寒來共向無煙火，飯了同烹雪色茶。',32,'全唐诗/poet.song.81000.json','["寒來共向無煙火，飯了同烹雪色茶。", "飽食高眠無一事，不知何以報官家。"]'),
('5c67b0f0-9636-4ee4-92c0-ccbb5db999c6','偈一百二十首  其一○五','釋懷深','宋','宋诗','song-poetry','','[]','布施門開非一朝，雲山千里肯辭勞。',64,'全唐诗/poet.song.81000.json','["布施門開非一朝，雲山千里肯辭勞。", "塵中欲聽無生曲，座上先橫智慧刀。", "貼肉汗衫容易施，有心道者卻難消。", "願公福似鄱臺塔，一層高了一層高。"]'),
('0533b5e7-ba1b-4daf-a27c-81b92f8618df','偈一百二十首  其一○六','釋懷深','宋','宋诗','song-poetry','','[]','盛暑隆寒相繼來，慧林四見地爐開。',64,'全唐诗/poet.song.81000.json','["盛暑隆寒相繼來，慧林四見地爐開。", "衲僧向火知方便，切忌團圝守死灰。", "恁麽恁麽即易，不恁麽不恁麽卻難。", "直教枯木再生花，任是寒灰重起焰。"]'),
('ee2ece03-db6f-40e3-abb2-616bcba59e55','偈一百二十首  其一○七','釋懷深','宋','宋诗','song-poetry','','[]','火焰時時轉法輪，廣長舌相耀乾坤。',32,'全唐诗/poet.song.81000.json','["火焰時時轉法輪，廣長舌相耀乾坤。", "衲僧不會轉身句，爍破娘生舊面門。"]'),
('6746b5e7-02de-468f-9e38-72457af8b478','偈一百二十首  其一○八','釋懷深','宋','宋诗','song-poetry','','[]','水中鹽味，色裏膠青。',20,'全唐诗/poet.song.81000.json','["水中鹽味，色裏膠青。", "決定是有，不見其形。"]'),
('0b60e067-856b-4f5b-9cec-d412ee3e844c','偈一百二十首  其一○九','釋懷深','宋','宋诗','song-poetry','','[]','炭頭今日地爐開，澀雨慳風惱破懷。',32,'全唐诗/poet.song.81000.json','["炭頭今日地爐開，澀雨慳風惱破懷。", "老僧向火喫酸豏，誰管檀那來不來。"]'),
('644c03fa-d127-4cab-b9f4-22c351c7127a','偈一百二十首  其一一○','釋懷深','宋','宋诗','song-poetry','','[]','皓月團團照碧天，鰲山燈火不須然。',32,'全唐诗/poet.song.81000.json','["皓月團團照碧天，鰲山燈火不須然。", "吾皇恭儉人心樂，自有嘆聲四海傳。"]'),
('9b2e569f-a544-4c1b-85b6-fd0ec163abe6','偈一百二十首  其一一一','釋懷深','宋','宋诗','song-poetry','','[]','憶昔在山日，眠雲並枕石。',24,'全唐诗/poet.song.81000.json','["憶昔在山日，眠雲並枕石。", "如今城裏居，欲去去不得。"]'),
('293b9a2d-fed9-4289-bb5b-e1170e72d171','偈一百二十首  其一一二','釋懷深','宋','宋诗','song-poetry','','[]','日暖旌旗壯鳳城，聖君勤儉古風清。',32,'全唐诗/poet.song.81000.json','["日暖旌旗壯鳳城，聖君勤儉古風清。", "寶刀不染匈奴血，四海從今自太平。"]'),
('ac534793-f2fd-486b-a2cc-69cf17b2cb18','偈一百二十首  其一一三','釋懷深','宋','宋诗','song-poetry','','[]','順天門外古招提，爛熳春是光照錦溪。',33,'全唐诗/poet.song.81000.json','["順天門外古招提，爛熳春是光照錦溪。", "物物更無心外法，箇中能有幾人知。"]'),
('3ce85f05-25c2-4b47-8c91-4f0a794a937a','偈一百二十首  其一一四','釋懷深','宋','宋诗','song-poetry','','[]','牽率歸來口懶開，婆娑重陟舊猊臺。',32,'全唐诗/poet.song.81000.json','["牽率歸來口懶開，婆娑重陟舊猊臺。", "孤雲本是無心物，又被東風拘管來。"]'),
('2585efab-b6a0-44d1-a7ec-0e13a8601750','偈一百二十首  其一一五','釋懷深','宋','宋诗','song-poetry','','[]','夜來春睡爛如泥，禁漏聲殘總不知。',32,'全唐诗/poet.song.81000.json','["夜來春睡爛如泥，禁漏聲殘總不知。", "翻憶南泉好言語，如斯癡鈍也還稀。"]'),
('f11edb4c-b4a1-406c-b73f-1ed3d98ab668','偈一百二十首  其一一六','釋懷深','宋','宋诗','song-poetry','','[]','不唯禁足，亦乃禁口。',163,'全唐诗/poet.song.81000.json','["不唯禁足，亦乃禁口。", "不唯禁口，亦乃禁手。", "不唯禁手，亦乃禁心。", "禁心不禁口，日日嫌佛醜。", "禁口不禁手，累及眉頭皺。", "禁手不禁心，罪過轉彌深。", "禁足更禁口，蟻子銜椀走。", "禁口更禁手，垂楊生左肘。", "禁手更禁心，大地是黄金。", "要得一夏安樂，細看兩重註脚。", "山僧恁麽說話，大似不龜手之藥。", "明珠一顆價難酬，不是知音便暗投。", "翻笑藥山空費力，水清魚現不吞鈎。"]'),
('032b3057-03d5-4d3b-ad62-4b9e409eff6c','偈一百二十首  其一一七','釋懷深','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','相送無言淚滿巾，溪頭黄葉正紛紛。',48,'全唐诗/poet.song.81000.json','["相送無言淚滿巾，溪頭黄葉正紛紛。", "勸君更進一盃酒，西出陽關無故人。", "一口吸盡西江水，不知何地著離情。"]'),
('2b62a41f-fd8b-4e2d-b291-9a6c3720f332','偈一百二十首  其一一八','釋懷深','宋','宋诗','song-poetry','','[]','六年掃灑皇家寺，一日君恩得遊還。',32,'全唐诗/poet.song.81000.json','["六年掃灑皇家寺，一日君恩得遊還。", "拄杖重挑舊瓶鉢，者回信脚入青山。"]'),
