('d625736e-fed4-4f2e-8226-e8d2d3771f35','前往焦山歷代尊宿真贊 佛印禪師','釋懷深','宋','宋诗','song-poetry','','[]','水翻千偈亦輕酬，一笑甌峰萬事休。',32,'全唐诗/poet.song.81000.json','["水翻千偈亦輕酬，一笑甌峰萬事休。", "今古碧桃灣底路，幾多風月屬漁舟。"]'),
('23a52db9-9283-4420-838e-7ccb694174b9','前往焦山歷代尊宿真贊 深禪師','釋懷深','宋','宋诗','song-poetry','','[]','南山拾得劫初鈴，鄉曲誰人會此聲。',32,'全唐诗/poet.song.81000.json','["南山拾得劫初鈴，鄉曲誰人會此聲。", "撥轉海門關棙子，雲樓月殿一時成。"]'),
('af1cc9e6-2490-4959-a54a-17928577ebeb','前往焦山歷代尊宿真贊 從禪師','釋懷深','宋','宋诗','song-poetry','','[]','雪眉巖頂鶴精神，淡薄家風世少鄰。',32,'全唐诗/poet.song.81000.json','["雪眉巖頂鶴精神，淡薄家風世少鄰。", "明月蘆花藏不得，老來重跨鐵麒麟。"]'),
('1c933599-6179-4b88-9a2d-1d02011dfb89','前往焦山歷代尊宿真贊 慈受和尚自讚','釋懷深','宋','宋诗','song-poetry','','[]','因風便作海門居，釣盡波瀾未見魚。',32,'全唐诗/poet.song.81000.json','["因風便作海門居，釣盡波瀾未見魚。", "水冷雲寒歸未得，笑看新月上珊瑚。"]'),
('e09e0a6d-f6a6-4972-95f7-d82c4df1855d','前住慧林歷代禪師真贊 圓照法空禪師','釋懷深','宋','宋诗','song-poetry','','[]','大圓鏡中，真光明炬。',48,'全唐诗/poet.song.81000.json','["大圓鏡中，真光明炬。", "慈中有威，擊塗毒鼓。", "威中有慈，闢荆棘路。", "無緣飾，沒遮護。", "一切衆生，睹相而悟。"]'),
('8ab73f79-fec8-4360-bb84-3dce37564864','前住慧林歷代禪師真贊 覺海沖禪師','釋懷深','宋','宋诗','song-poetry','','[]','言簡理直，道高德重。',46,'全唐诗/poet.song.81000.json','["言簡理直，道高德重。", "無妄談笑，無妄迎送。", "衲子入門，毛髪聳動。", "密密處，莫能觀，倚天靈刃照人寒。"]'),
('1ef2024e-f249-47f6-b4af-d3dd6dcf804d','前住慧林歷代禪師真贊 佛陀遜禪師','釋懷深','宋','宋诗','song-poetry','','[]','轉方作圓，輝今耀昔。',46,'全唐诗/poet.song.81000.json','["轉方作圓，輝今耀昔。", "龍袖三關，金鎚一擊。", "五十餘年，脇不至席。", "逆鱗句，阿誰識，生死觀來如戲劇。"]'),
('6fc875e2-a26c-44d0-824b-b18662c16c13','前住慧林歷代禪師真贊 佛光正禪師','釋懷深','宋','宋诗','song-poetry','','[]','炟赫佛光，逆順無礙。',50,'全唐诗/poet.song.81000.json','["炟赫佛光，逆順無礙。", "道傳崑山，聲飛湖海。", "戲笑怒罵，皆師三昧。", "風流處，更尤佳。", "曾悟庭前栢，春風二月花。"]'),
('a2f7ab13-61f8-41c5-b1b9-bfaeb7885f53','前住慧林歷代禪師真贊 祖印悟禪師','釋懷深','宋','宋诗','song-poetry','','[]','師道平夷，師貌渾厚。',46,'全唐诗/poet.song.81000.json','["師道平夷，師貌渾厚。", "持如地心，開無妄口。", "四坐道場，一塵不受。", "節角處，沒窼臼，三眼神龜火裏走。"]'),
('b9d852c4-d7e0-4a31-9052-9b186e31e645','前住慧林歷代禪師真贊 月印禪師','釋懷深','宋','宋诗','song-poetry','','[]','凜然孤風，粲然眉目。',36,'全唐诗/poet.song.81000.json','["凜然孤風，粲然眉目。", "利劍當門，誰敢輕觸。", "脫略處，妙難傳，萬仞峰前駕鐵船。"]'),
