('aa5ec6b7-7fe9-41c8-80c9-0ed3f5da6a42','孫保義求偈','釋懷深','宋','宋诗','song-poetry','','[]','省緣知足常安樂，廣費多求損道情。',32,'全唐诗/poet.song.81000.json','["省緣知足常安樂，廣費多求損道情。", "鬧市門頭祖師意，放教心地坦然平。"]'),
('9ee8376c-62e3-47d9-bd63-1dc0c90e45ec','吳保義求偈','釋懷深','宋','宋诗','song-poetry','','[]','前日相逢欣款曲，見君胸次坦然平。',32,'全唐诗/poet.song.81000.json','["前日相逢欣款曲，見君胸次坦然平。", "祖師有箇入門句，只要時中事事輕。"]'),
('dfc9a126-c0c6-4325-ad60-431fb9cbfe98','王員外求偈','釋懷深','宋','宋诗','song-poetry','','[]','勸君不用廣貪求，隨分家緣了便休。',32,'全唐诗/poet.song.81000.json','["勸君不用廣貪求，隨分家緣了便休。", "百歲光陰能幾日，得回頭處早回頭。"]'),
('52edcc59-e32b-4c84-b111-e14cf38e983d','金大翁求偈','釋懷深','宋','宋诗','song-poetry','','[]','禮拜燒香新活計，行船種橘舊家風。',32,'全唐诗/poet.song.81000.json','["禮拜燒香新活計，行船種橘舊家風。", "欲知自己彌陀佛，便是亢山金大翁。"]'),
('2b0eb7cb-4ed6-47cf-8bdd-a73bf80ff5f4','許善友求偈','釋懷深','宋','宋诗','song-poetry','','[]','二十畝田供伏臘，無妻無妾自由身。',32,'全唐诗/poet.song.81000.json','["二十畝田供伏臘，無妻無妾自由身。", "回觀萬頃良田者，也是人間多事人。"]'),
('b75b5cbb-4952-4c66-8dc7-51c6d8c553e9','善友誦金剛經求偈','釋懷深','宋','宋诗','song-poetry','','[]','背誦金剛四十年，老來心地轉精專。',64,'全唐诗/poet.song.81000.json','["背誦金剛四十年，老來心地轉精專。", "勸渠不用憂生死，只此修行便是禪。", "便是禪，不須參，一句該通五百函。", "無我無人無壽者，塵塵剎剎笑瞿曇。"]'),
('8effffa9-634c-4d8d-942a-64771d267c59','因讀法華經至火宅喻不覺一笑因書偈示孫主簿','釋懷深','宋','宋诗','song-poetry','','[]','夢裏分明有火殃，覺來心地本清涼。',32,'全唐诗/poet.song.81000.json','["夢裏分明有火殃，覺來心地本清涼。", "三車亦爲兒童設，想見瞿曇別有方。"]'),
('4ac6186c-fc4f-4341-b065-b0a461fa67d5','答高道人二首  其一','釋懷深','宋','宋诗','song-poetry','','[]','人身正類砂盆破，三篾束縛全暫時。',32,'全唐诗/poet.song.81000.json','["人身正類砂盆破，三篾束縛全暫時。", "暑往寒來宜愛惜，莫教土上更加泥。"]'),
('d145fae3-3f56-486f-ae00-87c0239a4524','答高道人二首  其二','釋懷深','宋','宋诗','song-poetry','','[]','砂盆打破化爲塵，始是撐天拄地人。',32,'全唐诗/poet.song.81000.json','["砂盆打破化爲塵，始是撐天拄地人。", "舉世只言身是幻，不知誰是幻中人。"]'),
('ad2dbef2-7275-476d-9467-8853ed6143fb','諸道友以法愛故常至包山以偈卻之','釋懷深','宋','宋诗','song-poetry','','[]','老僧多病厭將迎，且卜西山隱姓名。',32,'全唐诗/poet.song.81000.json','["老僧多病厭將迎，且卜西山隱姓名。", "若是吾家真道友，隔湖相見最分明。"]'),
('063f8f0c-88ff-46b1-9bad-b8445ea2c939','真州檀越求偈','釋懷深','宋','宋诗','song-poetry','','[]','了即業障本來空，心如聚蟻意如風。',64,'全唐诗/poet.song.81000.json','["了即業障本來空，心如聚蟻意如風。", "未了應須還宿債，破後還將茅草蓋。", "燈籠露柱笑呵呵，好是焦山口更多。", "奉報揚子江頭水，等閑無事莫與波。"]'),
('8d0e68fa-b8a8-4b1b-92f6-e61bf8c7f83f','資福改神霄道友挽留不得師去以偈卻絕','釋懷深','宋','宋诗','song-poetry','','[]','人生聚散本無常，休把閑愁腦肚腸。',32,'全唐诗/poet.song.81000.json','["人生聚散本無常，休把閑愁腦肚腸。", "三十年後重相見，拍手呵呵笑一場。"]'),
('36804242-1b9b-4687-a9b5-be0aef8bb0c6','陞堂頌古五十二首  其一','釋懷深','宋','宋诗','song-poetry','','[]','時光迅速急如流，一別慈顔幾換我。',64,'全唐诗/poet.song.81000.json','["時光迅速急如流，一別慈顔幾換我。", "墳墓鄉關空杳杳，死生岐路兩悠悠。", "充饑乳哺恩難報，寄體懷擔力莫酬。", "想像音容無覓處，春風特地使人愁。"]'),
('5c8d621e-1c89-443b-85d5-ce767fa323fd','陞堂頌古五十二首  其二','釋懷深','宋','宋诗','song-poetry','','[]','涅槃生死兩般名，正眼觀來一性靈。',32,'全唐诗/poet.song.81000.json','["涅槃生死兩般名，正眼觀來一性靈。", "五藴山頭雲散後，大千沙界月長明。"]'),
('5f8703fd-4414-4ac8-b412-9bccbff7451a','陞堂頌古五十二首  其三','釋懷深','宋','宋诗','song-poetry','','[]','三月安居要護生，蛾蛘蟻子亂縱橫。',48,'全唐诗/poet.song.81000.json','["三月安居要護生，蛾蛘蟻子亂縱橫。", "衲僧自有轉身路，不向時人行處行。", "三條椽下清風遠，六尺單前白晝長。"]'),
('97109025-9d9e-476b-a248-e20c122fd2e3','陞堂頌古五十二首  其四','釋懷深','宋','宋诗','song-poetry','','[]','芭蕉聞雷開，還有耳麽。',64,'全唐诗/poet.song.81000.json','["芭蕉聞雷開，還有耳麽。", "葵花隨日轉，還有眼麽。", "社桑知天風，還有心麽。", "海水知天寒，還有意麽。", "無情之物，尚自知時。", "多少衲僧，一向瞌睡。"]'),
('f91f945d-1f75-490d-a79e-28706d56b8df','陞堂頌古五十二首  其五','釋懷深','宋','宋诗','song-poetry','','[]','資福爲人處，從來無異路。',36,'全唐诗/poet.song.81000.json','["資福爲人處，從來無異路。", "飯飽譬如閑，共般數擔土。", "你行我亦行，你住我亦住。"]'),
('a2e526bc-0219-4950-9871-c73311d69c4d','陞堂頌古五十二首  其六','釋懷深','宋','宋诗','song-poetry','','[]','咄哉異類身，輪轉無休息。',108,'全唐诗/poet.song.81000.json','["咄哉異類身，輪轉無休息。", "戴角復被毛，觳觫償人力。", "我觀佛與牛，其性本來一。", "良由昧此心，所以異形質。", "想汝爲人時，豈信有今日。", "侵欺常住錢，互用招提物。", "是非信口談，酒肉恣情食。", "五戒既不持，人身安可得。", "今日墮牛身，方知無利益。"]'),
('b22eac27-c973-43fc-a503-bcc2caf1cbec','陞堂頌古五十二首  其七','釋懷深','宋','宋诗','song-poetry','','[]','纔見仲冬初，不覺又月半。',76,'全唐诗/poet.song.81000.json','["纔見仲冬初，不覺又月半。", "光景急如梭，人情忙似鑽。", "白髮鬢邊添，朱顔暗裏換。", "名利競頭爭，好事無人看。", "臘月三十日，饒你是鐵漢。", "覺花有種無人種，心火無煙逐日燒。"]'),
('4808b659-1f4b-437f-8ed5-cef02fc9876c','陞堂頌古五十二首  其八','釋懷深','宋','宋诗','song-poetry','','[]','禪門泊將氣如雲，江北江南把要津。',32,'全唐诗/poet.song.81000.json','["禪門泊將氣如雲，江北江南把要津。", "莫怪林衆閑未待，掃除佛祖要當人。"]'),
('c0aeba7e-812e-4f23-bb42-b7a10793552a','陞堂頌古五十二首  其九','釋懷深','宋','宋诗','song-poetry','','[]','欲鑄紅爐百煉金，先煩廣結衆人心。',44,'全唐诗/poet.song.81000.json','["欲鑄紅爐百煉金，先煩廣結衆人心。", "刀山劍樹長年苦，好爲勞生發妙音。", "佛手遮不得，人心自等閑。"]'),
('bf6e9c4c-9ddd-4aea-ad73-ce30ba16aa33','陞堂頌古五十二首  其一○','釋懷深','宋','宋诗','song-poetry','','[]','昔時說有千般，今日看無一種。',28,'全唐诗/poet.song.81000.json','["昔時說有千般，今日看無一種。", "等閑拈轉虛空，始得平生受用。"]'),
('2651acce-17c7-49ce-b982-a00826203a18','陞堂頌古五十二首  其一一','釋懷深','宋','宋诗','song-poetry','','[]','焦山舊日時，堂安百餘衆。',288,'全唐诗/poet.song.81000.json','["焦山舊日時，堂安百餘衆。", "笊籬與木杓，如今不足用。", "多謝諸禪人，各出一隻手。", "南北與西東，面南看北斗。", "廚中一箇鍋，煮粥又不多。", "若非憲上座，誰人奈爾何。", "水陸會街坊，六人爲總領。", "但看正二月，夜夜香花請。", "二人同一心，打圍要種菜。", "意在钁頭邊，兩彩都一賽。", "臘月冷如冰，衆僧猶臥簟。", "二人去化蓆，姑蘇也不遠。", "漆桶要打破，深禪卻要光。", "但教無滲漏，得箇也無妨。", "鎮州蘿蔔頭，今年到處少。", "奇公去打錢，典座呵呵笑。", "法真小比丘，去覓溈山牛。", "繩頭須緊把，鼻孔要牢收。", "跡在牛還在，無心終易求。", "要得十分好，更造一層樓。", "更有一件事，不小亦不大。", "擘也擘不開，跣也跣下過。", "常在動用中，未有人擔荷。", "你若肯發心，我爲你說破。"]'),
('988a375b-13bc-4e33-a17c-d64aeb04f06b','陞堂頌古五十二首  其一二','釋懷深','宋','宋诗','song-poetry','','[]','臘月二十五，拄杖二十五。',130,'全唐诗/poet.song.81000.json','["臘月二十五，拄杖二十五。", "燈籠二十五，拂子二十五。", "普請栽菜上堂，焦別無見解，且學古人栽菜。", "若還摠不生根，也是諸人有彩。", "無端跂死禪和，只要硬守疆界。", "忽然築著磕著，便見草賊大敗。", "大凡履踐此事，須要自由自在。", "從教土面灰頭，不怕風吹日曬。", "老來意在钁頭漫，家風自有通人愛。"]'),
('0e896c49-c0bb-4426-abb1-1b4d9cf7d829','陞堂頌古五十二首  其一三','釋懷深','宋','宋诗','song-poetry','','[]','莫謂無心便是禪，箇中有路更幽玄。',32,'全唐诗/poet.song.81000.json','["莫謂無心便是禪，箇中有路更幽玄。", "繫驢橛子推翻後，打著南邊動北邊。"]'),
('039a2fc9-c3a3-4f9c-aa01-d2ccbefa2a8d','陞堂頌古五十二首  其一四','釋懷深','宋','宋诗','song-poetry','','[]','一切法不生，一切法不滅。',24,'全唐诗/poet.song.81000.json','["一切法不生，一切法不滅。", "若能如是解，諸佛常現前。"]'),
('18e2cd5b-4503-4bc2-932b-1fe32f4f3174','陞堂頌古五十二首  其一五','釋懷深','宋','宋诗','song-poetry','','[]','不風流處也風流，匹馬追風四百州。',32,'全唐诗/poet.song.81000.json','["不風流處也風流，匹馬追風四百州。", "金鏃離弦胸百戰，鐵鞭多力恨無讎。"]'),
('f5a59ada-b6ff-4256-aa12-e14418aaf527','陞堂頌古五十二首  其一六','釋懷深','宋','宋诗','song-poetry','','[]','本地風光何似生，誰明日午打三更。',32,'全唐诗/poet.song.81000.json','["本地風光何似生，誰明日午打三更。", "直饒金印大如斗，爭踏毗盧頂上行。"]'),
('a4c18fea-1b05-4c96-bd6f-095b1d1353e1','陞堂頌古五十二首  其一七','釋懷深','宋','宋诗','song-poetry','','[]','物物到心上，全心物自閑。',38,'全唐诗/poet.song.81000.json','["物物到心上，全心物自閑。", "古今城？得者？如山。", "但願清風生兩腋，不愁無路到人間。"]'),
('50cf0d0c-8ded-46e8-83aa-0b5869bca759','陞堂頌古五十二首  其一八','釋懷深','宋','宋诗','song-poetry','','[]','空王殿子幾經秋，日曬風吹古路頭。',32,'全唐诗/poet.song.81000.json','["空王殿子幾經秋，日曬風吹古路頭。", "莫怪今朝聊點破，恐人一向外邊修。"]'),
('cce99e7d-08ad-44fe-af35-bf6197e9687b','陞堂頌古五十二首  其一九','釋懷深','宋','宋诗','song-poetry','','[]','暖日曬開地面凍，春風吹拆嶺頭梅。',32,'全唐诗/poet.song.81000.json','["暖日曬開地面凍，春風吹拆嶺頭梅。", "他知物物無遮障，自是時人眼不開。"]'),
('f715f7b9-0203-4be5-8711-5237424088e7','陞堂頌古五十二首  其二○','釋懷深','宋','宋诗','song-poetry','','[]','奔馳光景幾翻春，何事臨風一慘神。',43,'全唐诗/poet.song.81000.json','["奔馳光景幾翻春，何事臨風一慘神。", "柳綠桃紅依舊在，今年不見去年？幸然明似鏡，向用曲如鈎。"]'),
('2d8fe98a-7748-41a3-a03c-8e4278724912','陞堂頌古五十二首  其二一','釋懷深','宋','宋诗','song-poetry','','[]','葉落歸根萬事休，來時無口句難酬。',32,'全唐诗/poet.song.81000.json','["葉落歸根萬事休，來時無口句難酬。", "虛空忽爾翻筋斗，嚇倒雲門六不收。"]'),
('5dde0478-d384-4f31-9b7f-7411f263a3c4','陞堂頌古五十二首  其二二','釋懷深','宋','宋诗','song-poetry','','[]','自慚無德繼高蹤，百事荒唐懶更慵。',32,'全唐诗/poet.song.81000.json','["自慚無德繼高蹤，百事荒唐懶更慵。", "要死山今死未得，且將香火奉諸公。"]'),
('d6dce40b-2d60-4be5-83cb-99f29824aa72','陞堂頌古五十二首  其二三','釋懷深','宋','宋诗','song-poetry','','[]','夢裏移廚夢裏來，夢中陞座夢中齋。',62,'全唐诗/poet.song.81000.json','["夢裏移廚夢裏來，夢中陞座夢中齋。", "夢中生也夢中喜，夢裏死事格裏埋。", "萬事不由人計較，一身休更巧安排。", "知夢裏惺惺者，達磨西來？鞋。"]'),
('33c79a6c-2fd1-438f-bd98-c8935b90b4a4','陞堂頌古五十二首  其二四','釋懷深','宋','宋诗','song-poetry','','[]','瑞氣氛氳鎖梵宮，嵯峨寶塔倚高空。',32,'全唐诗/poet.song.81000.json','["瑞氣氛氳鎖梵宮，嵯峨寶塔倚高空。", "簷楹金碧光相照，盡落山僧一頓中。"]'),
('f5d2c445-0e09-4ff9-a3a1-80b9c07dfdc9','陞堂頌古五十二首  其二五','釋懷深','宋','宋诗','song-poetry','','[]','休休休，放下著，無量劫來靈性惡。',64,'全唐诗/poet.song.81000.json','["休休休，放下著，無量劫來靈性惡。", "只知貪愛黑如雲，一段光明都昧卻。", "休休休，放下著，浮生不用多圖度。", "榮華富貴總成空，到頭唯有無生樂。"]'),
('0c03d7fc-a1a6-4fae-8484-ab8fb9038015','陞堂頌古五十二首  其二六','釋懷深','宋','宋诗','song-poetry','','[]','年年今夜月華多，一點雲生仗是魔。',32,'全唐诗/poet.song.81000.json','["年年今夜月華多，一點雲生仗是魔。", "爭似曹溪門下叟，一輪空月照婆婆。"]'),
('89784247-3528-423b-b853-9a2ae79e25d9','陞堂頌古五十二首  其二七','釋懷深','宋','宋诗','song-poetry','','[]','？宵燈燭鬬熒煌，車馬縱橫徹曉忙。',32,'全唐诗/poet.song.81000.json','["？宵燈燭鬬熒煌，車馬縱橫徹曉忙。", "倒底不知燈是火，區區幾箇解回光。"]'),
('98258d19-ecb9-4e24-a9c1-80d79d66b737','陞堂頌古五十二首  其二八','釋懷深','宋','宋诗','song-poetry','','[]','羚羊掛角時，箇事絕毫釐。',24,'全唐诗/poet.song.81000.json','["羚羊掛角時，箇事絕毫釐。", "既能通一線，方便有高低。"]'),
('b7bcc33d-ca08-452d-a0ee-7ab25a65dd71','陞堂頌古五十二首  其二九','釋懷深','宋','宋诗','song-poetry','','[]','二鼠侵藤真百苦，四蛇圍井過千憂。',32,'全唐诗/poet.song.81000.json','["二鼠侵藤真百苦，四蛇圍井過千憂。", "忽然我斷藤根子，道是千休與萬休。"]'),
