('7923ae87-799f-49f9-8fe8-7e283679f89c','頌古三十首  其一六','釋懷深','宋','宋诗','song-poetry','','[]','一條官路坦然平，無限遊人取次行。',32,'全唐诗/poet.song.81000.json','["一條官路坦然平，無限遊人取次行。", "莫謂地平無險處，須知平地有深坑。"]'),
('ba146c19-8179-4990-b5d0-77ae6663d9bb','頌古三十首  其一七','釋懷深','宋','宋诗','song-poetry','','[]','一人會上竿，一人會穿井。',40,'全唐诗/poet.song.81000.json','["一人會上竿，一人會穿井。", "伎倆雖不同，總是一般病。", "若人識得這般病，衲僧鼻孔都穿盡。"]'),
('72822755-9ab6-47bd-9a08-2940296517e9','頌古三十首  其一八','釋懷深','宋','宋诗','song-poetry','','[]','法身無相，法眼無瑕。',46,'全唐诗/poet.song.81000.json','["法身無相，法眼無瑕。", "因風吹火，借水獻花。", "絲毫不立，萬別千差。", "但看來年三二月，啣泥燕子入人家。"]'),
('a1fd639f-6fd7-4db8-8a4b-0e7acfcda9be','頌古三十首  其一九','釋懷深','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','簷頭雨滴，階前地濕。',30,'全唐诗/poet.song.81000.json','["簷頭雨滴，階前地濕。", "法法現成，人信不刃。", "更問如何，長江水急。"]'),
('35076d32-1ad8-4e76-a2bc-e08fbba1638b','頌古三十首  其二○','釋懷深','宋','宋诗','song-poetry','','[]','洞山麻三斤，斤兩不謾人。',24,'全唐诗/poet.song.81000.json','["洞山麻三斤，斤兩不謾人。", "語稀難問事，貌古易傳神。"]'),
('2635f263-1c2e-4778-8322-7d0de089ca90','頌古三十首  其二一','釋懷深','宋','宋诗','song-poetry','','[]','處處綠楊堪繫馬，家家門道透長安。',32,'全唐诗/poet.song.81000.json','["處處綠楊堪繫馬，家家門道透長安。", "一條大路平如掌，自是時人措足難。"]'),
('13865146-2075-4364-92ea-4aeced63d6f1','頌古三十首  其二二','釋懷深','宋','宋诗','song-poetry','','[]','驀直去，驀直去，草鞋跟斷人無數。',64,'全唐诗/poet.song.81000.json','["驀直去，驀直去，草鞋跟斷人無數。", "唱歌須是帝鄉人，一箇拍兮一箇舞。", "舞得徹，勿多般，趙州婆子特用瞞。", "今古五臺山下路，長松短檜聳雲端。"]'),
('c16a549c-0d5a-4ad8-a895-f885dea1a8ff','頌古三十首  其二三','釋懷深','宋','宋诗','song-poetry','','[]','馬祖捧出菱花鏡，王老親拈白玉槌。',56,'全唐诗/poet.song.81000.json','["馬祖捧出菱花鏡，王老親拈白玉槌。", "一擊當陽令瓦碎，此心能有幾人知，兩箇分明是赤眉。", "風前月下揚家醜，笑倒靈山老古錐。"]'),
('51056ca1-209c-47de-bca5-dc9f5c63b1a2','頌古三十首  其二四','釋懷深','宋','宋诗','song-poetry','','[]','上庵竪起拳頭，趙州左眼半斤。',56,'全唐诗/poet.song.81000.json','["上庵竪起拳頭，趙州左眼半斤。", "下庵竪起拳頭，趙州右眼八兩。", "君看陝府鐵牛，何似嘉州大像。", "若謂總沒諸訛，露柱燈籠合掌。"]'),
('4334ff72-100e-4be9-83dc-9902aba7dc31','頌古三十首  其二五','釋懷深','宋','宋诗','song-poetry','','[]','雲門一枚糊餅，天下衲僧咬嚼。',60,'全唐诗/poet.song.81000.json','["雲門一枚糊餅，天下衲僧咬嚼。", "若非鐵作牙關，往往完圝吞卻。", "吞時易，吐時難，莫道從來麯一般。", "踏看韶陽關捩子，方能平地起波瀾。"]'),
('3b13c702-08c6-4901-be30-62fc706a429d','頌古三十首  其二六','釋懷深','宋','宋诗','song-poetry','','[]','趙州門戶，都無關鎖。',44,'全唐诗/poet.song.81000.json','["趙州門戶，都無關鎖。", "侍者粗心，當頭蹉過。", "靈利沙彌，珍重便行。", "這裏下一轉語，夜深歸堂向火。"]'),
('f5dced13-6f64-4f44-9b76-30582b661c41','頌古三十首  其二七','釋懷深','宋','宋诗','song-poetry','','[]','趙州庭前柏，何似門外柳。',36,'全唐诗/poet.song.81000.json','["趙州庭前柏，何似門外柳。", "大盡三十日，小盡二十九。", "更問事如何，合卻？生口。"]'),
('f6051583-6a9c-4635-a6fd-ffc7456c88ab','頌古三十首  其二八','釋懷深','宋','宋诗','song-poetry','','[]','北斗裏藏身？擬議即差訛。',12,'全唐诗/poet.song.81000.json','["北斗裏藏身？擬議即差訛。"]'),
('5e766a72-5bfc-4d07-9c9b-a940b15cde99','頌古三十首  其二九','釋懷深','宋','宋诗','song-poetry','','[]','終朝噇飯費工夫，不識燈籠是鉢盂。',32,'全唐诗/poet.song.81000.json','["終朝噇飯費工夫，不識燈籠是鉢盂。", "多少三家村裏漢，忙忙樹上捉鮎魚。"]'),
('c539bd08-36cc-40f8-8c9c-7fc17aeded69','頌古三十首  其三○','釋懷深','宋','宋诗','song-poetry','','[]','髑髏裏眼見猶在，枯木中龍聲更狂。',32,'全唐诗/poet.song.81000.json','["髑髏裏眼見猶在，枯木中龍聲更狂。", "打破虛空光境盡，箇中別有好商量。"]'),
('4afb305f-c639-42f9-ab8a-1471fe7d248c','偈三首  其一','釋懷深','宋','宋诗','song-poetry','','[]','憶昔去年春，正當此時節。',72,'全唐诗/poet.song.81000.json','["憶昔去年春，正當此時節。", "雙拳打破太虛空，無限家風渾漏泄。", "人中獅子喪全成，月裏麒麟鬬角折。", "鬬角折，金剛正眼難磨滅。", "千古令人誦不休，吹散紅爐一點雲。"]'),
('4dd6fb5c-9a24-4c8a-8307-225e0245218c','偈三首  其二','釋懷深','宋','宋诗','song-poetry','','[]','一回飲水一回噎，本自無情似有情。',32,'全唐诗/poet.song.81000.json','["一回飲水一回噎，本自無情似有情。", "欲會箇中端的意，木雞啼作兩般聲。"]'),
('7eec7671-232f-49f0-b506-a73f3563651d','偈三首  其三','釋懷深','宋','宋诗','song-poetry','','[]','箇事相承八百年，實無一法與人傳。',32,'全唐诗/poet.song.81000.json','["箇事相承八百年，實無一法與人傳。", "今朝欲報無傳底，聊爇金鑪一炷煙。"]'),
('eea2df24-8fc4-4bdc-9037-2d3357e1ffa6','因勝澄禪師下火','釋懷深','宋','宋诗','song-poetry','','[]','這老子，斗時枯槁，不近人情。',85,'全唐诗/poet.song.81000.json','["這老子，斗時枯槁，不近人情。", "四海獨孤標，一身無伴侶。", "雖則兩提祖印，實無一法與人。", "閨門端坐冷啾啾，夜靜獨爲鬼神說。", "任你傍人惡發，我心終未和同？時開眼對青山，自笑滿頭生白髮。"]'),
('4db41a27-34b5-4a2f-b09c-54cce6ebf690','諸禪人下火  其一','釋懷深','宋','宋诗','song-poetry','','[]','初秋夏一時，衲僧多欲去。',116,'全唐诗/poet.song.81000.json','["初秋夏一時，衲僧多欲去。", "不搭陳梢船，便行泗州路。", "橫擔拄杖氣如雲，萬水千山都不顧。", "昨日通川方上入，隨例茫茫把不住。", "把不住，爲君說箇臨歧句。", "枯木巖前差路多，剔起眉毛著眼覷。", "一身恍若風中燭，百歲端如水上漚。", "未到衲僧平穩處，臨行那得不生愁。"]'),
('99b0d367-a93c-43be-aa28-13d934e7f2de','諸禪人下火  其二','釋懷深','宋','宋诗','song-poetry','','[]','浮生岸樹井藤，畢竟終歸敗壞。',69,'全唐诗/poet.song.81000.json','["浮生岸樹井藤，畢竟終歸敗壞。", "這僧撩起便行，也是平生慶快。", "著上沒底芒鞋，拋下這箇皮袋。", "茶？壇？火猶在，延壽堂中人又終。", "方言？身渾？同一夢中。"]'),
('d046129e-d3f6-4735-8f7f-e3fc9e5f60c4','行者下火','釋懷深','宋','宋诗','song-poetry','','[]','汝幼入空門，方年二十五。',36,'全唐诗/poet.song.81000.json','["汝幼入空門，方年二十五。", "鬚髪尚未除，幼身今日去。", "脫下布直裰，休問溫州路。"]'),
('097262e7-b22f-4c27-9a30-c94eb0ef01cc','田六娘子下火','釋懷深','宋','宋诗','song-poetry','','[]','浮生三十二春秋，方始修行肯轉頭。',64,'全唐诗/poet.song.81000.json','["浮生三十二春秋，方始修行肯轉頭。", "底事又隨雲雨去，煙波江上使人愁。", "休休休，不用愁，聚散還同水上漚。", "直饒壽得三十歲，不免輸他這一籌。"]'),
('9c5e616e-20d0-486c-b8f9-adf6dfe33c31','丁忠訓妻與女同下火','釋懷深','宋','宋诗','song-poetry','','[]','二十餘年寄此間，蓋蕪塵土翳朱顔。',32,'全唐诗/poet.song.81000.json','["二十餘年寄此間，蓋蕪塵土翳朱顔。", "今朝子母應相賀，且喜春來返故關。"]'),
('d871a5b0-9429-4bbf-89cc-e4aa3ff6c329','魏先生下火','釋懷深','宋','宋诗','song-poetry','','[]','嗚呼魏大和，爲人性純厚。',152,'全唐诗/poet.song.81000.json','["嗚呼魏大和，爲人性純厚。", "雖居陋巷中，簞瓢甘自守。", "聚學訓童蒙，束脩粗糊口。", "歲晚好吾宗，悟世非長久。", "臨行囑妻子，叮嚀誡諸後。", "不學老莊周，說葬成虛謬。", "不學襄陽翁，與女爭先後。", "先生之意不如斯，欲效禪家破諸有。", "四衆雲臻，柴薪已就。", "雖然父子至親，到此如何可救。", "不須救，生前已付山僧手。", "一枝紅燄贈君行，看取神龜火裏走。"]'),
('c14fd3be-2289-4580-bb2c-74ab38b3c617','登雲從禪師掩土','釋懷深','宋','宋诗','song-poetry','','[]','莫問青囊與紫囊，箇中風水十分強。',78,'全唐诗/poet.song.81000.json','["莫問青囊與紫囊，箇中風水十分強。", "青龍東去雲頭轉，白虎西來山脚長。", "江月松風皆舊物，綠苔芳草盡吾鄉。", "瑠璃殿上無知識，木馬泥牛暗斷腸。", "不問湘南潭北，休論坎短離長。"]'),
('2e0938eb-2120-4159-928a-ef9eafeb604f','諸禪人散灰  其一','釋懷深','宋','宋诗','song-poetry','','[]','言公心地最精專，曾學焦山一味禪。',32,'全唐诗/poet.song.81000.json','["言公心地最精專，曾學焦山一味禪。", "今日落盆盛白骨，翻身重上謝郎船。"]'),
('51273a89-cf77-4c74-85bd-44f99a5364a1','諸禪人散灰  其二','釋懷深','宋','宋诗','song-poetry','','[]','俗壽五十有三，出家一十八夏。',108,'全唐诗/poet.song.81000.json','["俗壽五十有三，出家一十八夏。", "平生行脚游方，多在鹽城興化。", "最好不曾參禪，免見鑽龜打瓦。", "今朝子細看來，也好一場詰霸。", "才公才公莫要怕，焦山布施你，一轉古人話。", "凈裸裸，赤灑灑，南北東西沒可把。", "忽然撞著閻羅王，拈起拂子驀口打。"]'),
('8beefa8e-5378-45cf-9bca-e9ec7c6fa08a','諸禪人散灰  其三','釋懷深','宋','宋诗','song-poetry','','[]','迢迢萬里別西川，要學諸方五味禪。',69,'全唐诗/poet.song.81000.json','["迢迢萬里別西川，要學諸方五味禪。", "昨日焦山山下死，劍門關上月重圓。", "既是焦山山下死，因什麽卻向劍門關上月重圓。", "究竟光明終一體，任他寒影落千江。"]'),
('f234551f-07cb-4945-81ae-603da31f4513','諸禪人散灰  其四','釋懷深','宋','宋诗','song-poetry','','[]','衲僧纔遇丙丁村，便作霜花骨一盆。',32,'全唐诗/poet.song.81000.json','["衲僧纔遇丙丁村，便作霜花骨一盆。", "火後始知梁不壞，翻身跳出是非門。"]'),
('1da33ade-50ed-46e4-97f7-dc2e4dbe50be','諸禪人散灰  其五','釋懷深','宋','宋诗','song-poetry','','[]','嚴兄嚴兄，善爲道路。',52,'全唐诗/poet.song.81000.json','["嚴兄嚴兄，善爲道路。", "從今換骨洗腸，更莫和泥合土。", "熟處放教生，生處不要住。", "揚子江頭浪拍天，莫教濕卻娘生褲。"]'),
('e29a155a-873f-49f2-adea-2f77af4c9328','諸禪人散灰  其六','釋懷深','宋','宋诗','song-poetry','','[]','宣州隆上人，叢林遊歷遍。',48,'全唐诗/poet.song.81000.json','["宣州隆上人，叢林遊歷遍。", "一入焦山門，便下延壽院。", "終朝何轆轆，喫藥都無驗。", "火後一莖茅，衆人皆總見。"]'),
('b1ccdd5e-11aa-468e-9662-6adbeb93e56c','偈二首  其一','釋懷深','宋','宋诗','song-poetry','','[]','只是舊時行李處，等閑舉著便郩訛。',32,'全唐诗/poet.song.81000.json','["只是舊時行李處，等閑舉著便郩訛。", "夜來一陣狂風起，吹落桃花知幾多。"]'),
('fa6f338e-f06d-4508-b379-46a8733476a5','偈二首  其二','釋懷深','宋','宋诗','song-poetry','','[]','雲自何山起，風從甚澗生。',24,'全唐诗/poet.song.81000.json','["雲自何山起，風從甚澗生。", "好箇入頭處，官路少人行。"]'),
('e89c27c0-345c-4654-943c-ca9c8109bf07','頌古','釋懷深','宋','宋诗','song-poetry','','[]','一火鑄成金彈子，團圝都不費鉗鎚。',32,'全唐诗/poet.song.81000.json','["一火鑄成金彈子，團圝都不費鉗鎚。", "拈來萬仞峰頭放，打落天邊白鳳兒。"]'),
('138aac62-bf5c-4952-afb8-8705b6f8951e','自贊','釋懷深','宋','宋诗','song-poetry','','[]','自顧個形骸，舉止凡而陋。',48,'全唐诗/poet.song.81000.json','["自顧個形骸，舉止凡而陋。", "只因放得下，觸事皆成就。", "醍醐與毒藥，萬味同一口。", "美惡盡銷融，是故名慈受。"]'),
('e8de7ed0-33a9-4c3e-b0c0-37bb3bd20bd2','上元陞座偈','釋懷深','宋','宋诗','song-poetry','','[]','靈巖上元節，且與諸方別。',48,'全唐诗/poet.song.81000.json','["靈巖上元節，且與諸方別。", "只點一碗燈，大千俱照徹。", "也不用添油，光明長皎潔。", "雨又打不濕，風又吹不滅。"]'),
('af051067-cedb-4559-80b7-2c3f0774c541','龍尾硯同程致道聯句','毛隨','宋','宋诗','song-poetry','','[]','無正文。',4,'全唐诗/poet.song.81000.json','["無正文。"]'),
('b6378f0f-0c13-4ace-9f11-cdb331dc94a7','句','方城高士','宋','宋诗','song-poetry','','[]','莫訝杖藜歸去早，家山閑卻一溪雲。',16,'全唐诗/poet.song.81000.json','["莫訝杖藜歸去早，家山閑卻一溪雲。"]'),
('6f51fb09-9f90-4500-b891-f8a811a65919','題佛剎','釋宗印','宋','宋诗','song-poetry','','[]','七十勞生西復東，鄉關在念感飄蓬。',64,'全唐诗/poet.song.81000.json','["七十勞生西復東，鄉關在念感飄蓬。", "大遼半歲九分盡，全晉一年千里空。", "周召已亡無善政，蔡童雖死有餘風。", "華陰乞食商山去，巖谷幽尋四老翁。"]'),
('67dbd71a-6936-4591-a604-1376d4ca0018','題玉華洞','劉嶠','宋','宋诗','song-poetry','','[]','洞南石燕接靈龜，獅子崢嶸氣與齊。',32,'全唐诗/poet.song.81000.json','["洞南石燕接靈龜，獅子崢嶸氣與齊。", "碧眼方瞳人不識，三山正在玉華西。"]'),
('37fb8b52-b515-4785-8286-596d45ec0032','李伯紀丞相挽詩三首  其一','陳公輔','宋','宋诗','song-poetry','','[]','豪傑不世出，爲時斯間生。',48,'全唐诗/poet.song.81000.json','["豪傑不世出，爲時斯間生。", "有心安社稷，無計避功名。", "憂國唯知重，謀身祇覺輕。", "徒令青史上，永？著英聲。"]'),
('1728fb58-7873-4b31-9dc7-d5620485c6b3','李伯紀丞相挽詩三首  其二','陳公輔','宋','宋诗','song-poetry','','[]','材大古難用，功多忌更多。',48,'全唐诗/poet.song.81000.json','["材大古難用，功多忌更多。", "忠懷衝日月，讒口肆風波。", "此老今亡矣，蒼生獨奈何。", "應遺一時恨，千載不能磨。"]'),
('aba27d17-0610-4465-bdb6-c448c1be0bf0','李伯紀丞相挽詩三首  其三','陳公輔','宋','宋诗','song-poetry','','[]','當時偶同罪，平昔豈相知。',48,'全唐诗/poet.song.81000.json','["當時偶同罪，平昔豈相知。", "天下指爲黨，我公終不疑。", "空懷荆渚樂，已失雁山期。", "此意憑誰訴，臨風有淚垂。"]'),
('c9a77098-8722-4096-becd-6f8383dec0eb','行諸山道中','陳公輔','宋','宋诗','song-poetry','','[]','我曾天台遊，于今四十載。',144,'全唐诗/poet.song.81000.json','["我曾天台遊，于今四十載。", "一朝忽復來，時節如有待。", "形骸覺老景，景色殊不改。", "雨中尋舊跡，觸目雲靉靆。", "巖瀑落千尋，澗花紛五彩。", "崖深蘚蒼蒼，溪淺石磊磊。", "昔時所未到，足力胡可殆。", "要當至絕頂，直下小滄海。", "茲山八萬丈，端的不吾給。", "偉哉造化功，疑若有真宰。", "黄精煮甚食，茯苓良可採。", "何當誅茆居，此志終有在。"]'),
('da190d35-0603-42a1-81a7-aaa3fa4e59a3','遊普慶院','陳公輔','宋','宋诗','song-poetry','','[]','滿目雲煙萬疊山，梵宮深鎖翠微間。',32,'全唐诗/poet.song.81000.json','["滿目雲煙萬疊山，梵宮深鎖翠微間。", "市朝多少紛紛客，輸卻僧家一味閑。"]'),
('43910aef-9014-4d11-a0d3-ac8683421cda','天封瑞雲閣','陳公輔','宋','宋诗','song-poetry','','[]','晴雲漠漠水潺潺，危閣春歸白日閑。',32,'全唐诗/poet.song.81000.json','["晴雲漠漠水潺潺，危閣春歸白日閑。", "若問祖師消息處，眼前環列是青山。"]'),
('3c4f20e7-eabc-4707-b862-e6ed777e5944','建炎丞相成國呂忠穆公退老堂  其一','陳公輔','宋','宋诗','song-poetry','','[]','經營堂宇近江濱，退穩功成名遂身。',64,'全唐诗/poet.song.81000.json','["經營堂宇近江濱，退穩功成名遂身。", "門外魚龍欣得地，圃中花木暖藏春。", "也知朝野思賢相，聊借湖山作主人。", "誰謂周公驕且吝，坐間無日不延賓。"]'),
('be76e3d0-7917-4ce7-bc0a-a371aabe041f','建炎丞相成國呂忠穆公退老堂  其二','陳公輔','宋','宋诗','song-poetry','','[]','平昔勳名絕輩流，正閑贏得去尋幽。',64,'全唐诗/poet.song.81000.json','["平昔勳名絕輩流，正閑贏得去尋幽。", "春風陌上飛千騎，曉日林間映九斿。", "閩嶺何妨傳雅詠，龍庭行即告嘉猷。", "願將屢秉鈞衡手，留作他年几杖遊。"]'),
('722dc12e-9c59-4f1d-be3f-c152e35afd1a','題張子正觀察溪風亭','陳公輔','宋','宋诗','song-poetry','','[]','我家近東城，南湖屢嘗游。',240,'全唐诗/poet.song.81000.json','["我家近東城，南湖屢嘗游。", "往時古堤岸，路暗行人愁。", "棘籬蔽荒圃，貍鼠呼啾啾。", "好景豈終廢，發見端有由。", "張公山西將，帷幄久運籌。", "晚歲倦征討，雅懷在林邱。", "人方棄不取，公乃得所求。", "除治見佳趣，經營出奇謀。", "竹窗清景亂，梅軒暗香浮。", "中間溪風亭，崢嶸跨碧流。", "虛簷極宏敞，坐見羣山幽。", "終夜自泠泠，六月長颼颼。", "蕩漾月波起，飄急雲靄收。", "曠然天宇間，清思何悠悠。", "高朋幾還往，玉斝時勸酬。", "相從同一醉，庶以消百憂。", "羨公強健身，萬事心不留。", "獨愛池館閑，永日嘗休休。", "公才自無雙，何用嘆不侯。", "試訪舊識中，此樂寧有不。"]'),
('bbbd6236-6244-4c49-b72d-f1a0b1261c8a','題蒼嶺','陳公輔','宋','宋诗','song-poetry','','[]','行到山危僕已痡，此身強健不須扶。',32,'全唐诗/poet.song.81000.json','["行到山危僕已痡，此身強健不須扶。", "回頭指顧重岡險，得似人心險也無。"]'),
('cfec058b-d2c9-4edc-99ac-0765d3b88a92','肄業廣慈院臨別留一絕','陳公輔','宋','宋诗','song-poetry','','[]','來時膏雨迷新野，去日薰風吹舊林。',32,'全唐诗/poet.song.81000.json','["來時膏雨迷新野，去日薰風吹舊林。", "寄語主人休惜別，白雲南北本無心。"]'),
('99827419-bfec-41c0-8b45-b8210c7f5152','次韻叔厚內翰喜雪詩','陳公輔','宋','宋诗','song-poetry','','[]','動天須假至誠祈，誠若專時定弗違。',64,'全唐诗/poet.song.81000.json','["動天須假至誠祈，誠若專時定弗違。", "冬後縱無三白應，春前俄有六花飛。", "著人但覺寒威重，擁火猶嫌酒力微。", "聊爲使君歌上瑞，麥苗千頃已菲菲。"]'),
('3c1965d0-26aa-483c-b08b-022aeafbe686','雪晴可喜戲作四韻奉呈','陳公輔','宋','宋诗','song-poetry','','[]','盈尺階前瑞已多，曉來天色漸晴和。',64,'全唐诗/poet.song.81000.json','["盈尺階前瑞已多，曉來天色漸晴和。", "青陽一氣應回暖，黄竹三章且罷歌。", "小雨洗時嵐滴翠，細風吹處沼生波。", "東郊便好尋芳去，桃李爭妍映綺羅。"]'),
('051f37f2-7e90-4a5b-99f8-603bd84c26ca','予與德升尚書招已懋端明叔厚內翰會飲因有倡和佳篇謾次前韻呈三兄','陳公輔','宋','宋诗','song-poetry','','[]','盛朝多少舊公卿，誰似三人負大名。',64,'全唐诗/poet.song.81000.json','["盛朝多少舊公卿，誰似三人負大名。", "金带並趨清禁路，玉杯同醉白雲城。", "吾儕出處真成戲，俗眼觀瞻祇自驚。", "便恐名隨封詔去，且頻開宴慰交情。"]'),
('bc41d687-b6e4-431b-a98e-519dd9f7a6f1','戲和德升賞梅因記十三日梅園之游發諸兄一笑','陳公輔','宋','宋诗','song-poetry','','[]','我聞永慶梅，孤標寄巖陰。',96,'全唐诗/poet.song.81000.json','["我聞永慶梅，孤標寄巖陰。", "衰年苦多病，咫尺未暇尋。", "公心亦似鐵，惜花情卻深。", "愛此獨株好，何必須滿林。", "茲游恨莫陪，有酒誰與斟。", "因思東郊上，瓊蕊滿髻簪。", "黄昏月下歸，翠袖寒易侵。", "想公見戲語，一笑開胸襟。"]'),
('d46932ba-2575-4cab-86e3-497a07b2e8ed','石鼓山','陳公輔','宋','宋诗','song-poetry','','[]','有山名石鼓，千古鎮南溟。',24,'全唐诗/poet.song.81000.json','["有山名石鼓，千古鎮南溟。", "大手不勞力，動時天下驚。"]'),
('51f91386-2796-49e7-8881-d5c72804a017','凈明寺閱藏經','陳公輔','宋','宋诗','song-poetry','','[]','三載功夫一藏經，非禪非道亦非僧。',32,'全唐诗/poet.song.81000.json','["三載功夫一藏經，非禪非道亦非僧。", "但憑方寸行諸善，也是如來最上乘。"]'),
('75ed8117-4dd9-4b30-a792-e1e282315f46','詩一首','陳公輔','宋','宋诗','song-poetry','','[]','白髮鬅鬙未得閑，有時覽鏡笑衰顔。',64,'全唐诗/poet.song.81000.json','["白髮鬅鬙未得閑，有時覽鏡笑衰顔。", "逢人載酒寧辭醉，寓意題詩不用刪。", "幸有鑑湖堪寄傲，直慚書殿尚通班。", "豁除簿領塵矣了，卻上蓬萊看好山。"]'),
('1c892128-0903-4ef7-bf8c-7388a86ac793','州宅','陳公輔','宋','宋诗','song-poetry','','[]','萬疊湖山煙水濱，朱門畫戟間松筠。',64,'全唐诗/poet.song.81000.json','["萬疊湖山煙水濱，朱門畫戟間松筠。", "登臨不踏紅塵路，燕寢長居紫府春。", "晝靜欲驂風外駕，夜寒疑是月中身。", "我慚白首方懷紱，猶得蓬萊作主人。"]'),
('e2f92d97-1b5b-4bfd-8dc4-c44369ab4828','蓬萊閣歸醉','陳公輔','宋','宋诗','song-poetry','','[]','蓬萊閣上醉歸時，猶索芳樽步步隨。',64,'全唐诗/poet.song.81000.json','["蓬萊閣上醉歸時，猶索芳樽步步隨。", "啼鳥似來留翠佩，旁人笑爲整花枝。", "腰間半嚲黄金印，頭上斜欹白接䍦。", "拍手向他賓從道，使君未老莫扶持。"]'),
('484aa4f7-fce2-4ce1-a179-2ed3bb0bf536','述懷謝陳去非見訪','陳公輔','宋','宋诗','song-poetry','','[]','愧無直節報朝廷，富貴端能一羽輕。',64,'全唐诗/poet.song.81000.json','["愧無直節報朝廷，富貴端能一羽輕。", "若比公孫終作相，寧堪汲黯止爲卿。", "吾曹學古當然事，俗眼看人只自驚。", "賴有同年曲江客，每回相過語平生。"]'),
('e159153b-e81a-42b1-ab8d-9133e45640f0','絕句三首  其一','陳公輔','宋','宋诗','song-poetry','','[]','雨過疏窗分外涼，隔簾風引芰荷香。',32,'全唐诗/poet.song.81000.json','["雨過疏窗分外涼，隔簾風引芰荷香。", "江湖六月生秋思，清夢回時月滿床。"]'),
('32cedc9d-c8ee-4db8-909d-5d044dc7a743','絕句三首  其二','陳公輔','宋','宋诗','song-poetry','','[]','夾岸古榆清蔭密，傍簷斜月冷光疏。',32,'全唐诗/poet.song.81000.json','["夾岸古榆清蔭密，傍簷斜月冷光疏。", "晚涼一枕邯鄲夢，半夜西風已滿裙。"]'),
('43b1c6b4-ae76-4b1d-a067-92f7030f31f9','絕句三首  其三','陳公輔','宋','宋诗','song-poetry','','[]','京國重來一夢間，不堪回首赤城山。',32,'全唐诗/poet.song.81000.json','["京國重來一夢間，不堪回首赤城山。", "隋堤古柳年年在，應笑行人鬢已班。"]'),
('2ec401b0-0e26-46be-b0c1-cce80a529a33','句','陳公輔','宋','宋诗','song-poetry','','[]','有德傳鄉里，無金遺子孫。',12,'全唐诗/poet.song.81000.json','["有德傳鄉里，無金遺子孫。"]'),
('fdf5e76e-f392-46c9-957f-6e1ee8225dfc','章序臣得銅雀硯屬余作詩','何薳','宋','宋诗','song-poetry','','[]','阿瞞恃姦雄，挾漢令天下。',168,'全唐诗/poet.song.81000.json','["阿瞞恃姦雄，挾漢令天下。", "惜時無英豪，磔裂異肩踝。", "終令盜坏土，埏作三臺瓦。", "雖云當塗高，會有食槽馬。", "人愚瓦何罪，淪蟄翳梧檟。", "錫花封雨苔，鴛彩晦雲罅。", "當時丹油去，實非謀諸野。", "因之好奇士，探琢助揮寫。", "歸參端歙材，堅澤未渠亞。", "章侯捐百金，訪獲從吾詫。", "興亡何復論，徒足增忿罵。", "但嗟瓦礫微，亦以材用捨。", "徒令瓴甓餘，當擅瓊瑰價。", "士患德不修，不憂老田舍。"]'),
('22dfa46b-9afa-4864-842c-2d31722c6c7e','華蓋仙山院','何薳','宋','宋诗','song-poetry','','[]','舊聞山隱彌天釋，幾欲從談不二門。',32,'全唐诗/poet.song.81000.json','["舊聞山隱彌天釋，幾欲從談不二門。", "尋到經窗收足座，卻應賓主兩忘言。"]'),
('18430977-404c-45da-9560-604a12a2b07a','句','何藗','宋','宋诗','song-poetry','','[]','不使翠分旁牖去，卻緣清甚畏人知。',16,'全唐诗/poet.song.81000.json','["不使翠分旁牖去，卻緣清甚畏人知。"]'),
('ff2c315c-5a5f-4ca5-ad1f-2dfadf907117','句','張圖南','宋','宋诗','song-poetry','','[]','坐中競病分明久，驢上推敲兀未裁。',16,'全唐诗/poet.song.81000.json','["坐中競病分明久，驢上推敲兀未裁。"]'),
('49524ce6-7598-4d93-b007-4fae42552dbe','偈二十七首  其一','釋紹隆','宋','宋诗','song-poetry','','[]','窮諸玄辯，竭世樞機。',30,'全唐诗/poet.song.81000.json','["窮諸玄辯，竭世樞機。", "百千法門，無量妙義。", "總在箇裏，不隔一絲。"]'),
('0408c160-b7ad-4051-b288-9c10c5b4b1e5','偈二十七首  其二','釋紹隆','宋','宋诗','song-poetry','','[]','掩室摩竭，杜口毗耶。',62,'全唐诗/poet.song.81000.json','["掩室摩竭，杜口毗耶。", "面壁九年，黄梅夜渡。", "點簡將來，翻成計較。", "殊不知日不待火而熱，月不待風而涼。", "雲龍，風從虎。", "作無作，爲無爲。"]'),
('471cc718-347e-401a-8082-679c649a396d','偈二十七首  其三','釋紹隆','宋','宋诗','song-poetry','','[]','悠悠世事空浮沉，自愛白雲歲月深。',32,'全唐诗/poet.song.81000.json','["悠悠世事空浮沉，自愛白雲歲月深。", "舉眼盡非凡草木，剛然斷臂覓安心。"]'),
('83303958-86a6-4bc5-8977-17546ce6e07f','偈二十七首  其四','釋紹隆','宋','宋诗','song-poetry','','[]','寰中天子勑，塞外將軍令。',24,'全唐诗/poet.song.81000.json','["寰中天子勑，塞外將軍令。", "一句定乾坤，一劍平天下。"]'),
('5bb0932f-6d77-4557-bfba-71239568ce5f','偈二十七首  其五','釋紹隆','宋','宋诗','song-poetry','','[]','牛頭沒，馬頭迴，渠無國土。',38,'全唐诗/poet.song.81000.json','["牛頭沒，馬頭迴，渠無國土。", "無位真人，突出難辯甚處。", "逢渠擊石火，閃電光得不得。"]'),
('35067808-a27f-4f96-bac1-e98fd516ceab','偈二十七首  其六','釋紹隆','宋','宋诗','song-poetry','','[]','萬里浮雲捲碧天，年年此夜十分圓。',32,'全唐诗/poet.song.81000.json','["萬里浮雲捲碧天，年年此夜十分圓。", "令人轉憶寒山子，說似吾心恰宛然。"]'),
('83e69ab1-3a2f-4c85-a017-7201078dcc55','偈二十七首  其七','釋紹隆','宋','宋诗','song-poetry','','[]','眼裏不著沙，耳裏不著水。',24,'全唐诗/poet.song.81000.json','["眼裏不著沙，耳裏不著水。", "堪笑老俱胝，無端竪一指。"]'),
('084f15c2-354e-480f-8298-7318ef68d7b8','偈二十七首  其八','釋紹隆','宋','宋诗','song-poetry','','[]','大智圓明，體無向背。',40,'全唐诗/poet.song.81000.json','["大智圓明，體無向背。", "凝然湛寂，彌滿太虛。", "覆蓋乾坤，常光獨露。", "削蹤滅跡，離相絕名。"]'),
('0ae9a3ba-bd68-4ebf-b419-a1741494ec6a','偈二十七首  其九','釋紹隆','宋','宋诗','song-poetry','','[]','炎暑蒸人汗似湯，鹽官用底豈尋常。',32,'全唐诗/poet.song.81000.json','["炎暑蒸人汗似湯，鹽官用底豈尋常。", "輕搖休問犀牛在，拈出清風宇宙涼。"]'),
('08f8668d-786a-4cde-85ee-41ddc8724a1f','偈二十七首  其一○','釋紹隆','宋','宋诗','song-poetry','','[]','一滴水，一滴凍，喝下風雷彰大用。',64,'全唐诗/poet.song.81000.json','["一滴水，一滴凍，喝下風雷彰大用。", "棒頭點出眼睛來，照了諸相悉空洞。", "出門撞著須菩提，拶破虛空全體露。", "一片虛凝絕謂情，萬里清光飛玉兔。"]'),
('975ace9f-d7a5-488f-97e5-6f3862899dc8','偈二十七首  其一一','釋紹隆','宋','宋诗','song-poetry','','[]','目前無法，萬象森然。',20,'全唐诗/poet.song.81000.json','["目前無法，萬象森然。", "意在目前，突出難辨。"]'),
('bdabac31-be0f-438c-9b68-026115a7ff89','偈二十七首  其一二','釋紹隆','宋','宋诗','song-poetry','','[]','離四句，絕百非，閫外風光誰得知。',120,'全唐诗/poet.song.81000.json','["離四句，絕百非，閫外風光誰得知。", "牛頭沒，馬頭回，空生巖畔碧崔嵬。", "一口吸西江，一句該萬象。", "一月普現一切水，一切水月一月攝。", "重重主伴，歷歷交參。", "品彙茲彰，人天正眼。", "如斯告報，只要知歸。", "苟或未然，便見生死。", "交謝寒暑，迭遷北里。", "豪家昨日歌兮今日哭。"]'),
('a6c3da7b-24e6-4517-a387-380fc7e70dce','偈二十七首  其一三','釋紹隆','宋','宋诗','song-poetry','','[]','光非照境，境亦非存。',30,'全唐诗/poet.song.81000.json','["光非照境，境亦非存。", "光境俱忘，復是何物。", "百草頭上，罷卻干戈。"]'),
('b870311e-c112-496b-b202-6cccd2b329c5','偈二十七首  其一四','釋紹隆','宋','宋诗','song-poetry','','[]','日日日東出，日日日西沒。',48,'全唐诗/poet.song.81000.json','["日日日東出，日日日西沒。", "人命在呼吸，百年輕倏忽。", "驀地得逢渠，掀翻生死窟。", "放出遼天鶻，萬重雲一突。"]'),
('139b31f6-4b22-4262-bf07-1e5af990a496','偈二十七首  其一五','釋紹隆','宋','宋诗','song-poetry','','[]','示現天宮補處身，堯風舜日耀乾坤。',32,'全唐诗/poet.song.81000.json','["示現天宮補處身，堯風舜日耀乾坤。", "今朝共祝南山壽，萬國來朝萬乘尊。"]'),
('666a02ab-1740-426d-8169-63b337cf6efe','偈二十七首  其一六','釋紹隆','宋','宋诗','song-poetry','','[]','大地撮來粟米粒，一毛頭上現乾坤。',36,'全唐诗/poet.song.81000.json','["大地撮來粟米粒，一毛頭上現乾坤。", "居家不離途中事，常在途中不出門。", "喝一喝。"]'),
('f6a1686f-4fb8-464d-b90d-44e7f8607c40','偈二十七首  其一七','釋紹隆','宋','宋诗','song-poetry','','[]','田地隱密，鬼家活計。',54,'全唐诗/poet.song.81000.json','["田地隱密，鬼家活計。", "從空放下，坐井窺天。", "虎丘門下，不說老婆禪。", "只要諸人眼橫鼻直，三十年後免得敲{忄窘}打瓦。"]'),
('d608db0c-f81c-45b1-86ea-397467da56e8','偈二十七首  其一八','釋紹隆','宋','宋诗','song-poetry','','[]','物宜求新，人宜求舊。',20,'全唐诗/poet.song.81000.json','["物宜求新，人宜求舊。", "不起于座，現諸威儀。"]'),
('dbf43d0d-7d1e-49f0-b3f4-92686ceb8dd4','偈二十七首  其一九','釋紹隆','宋','宋诗','song-poetry','','[]','當陽正體露堂堂，休謂當年付飲光。',32,'全唐诗/poet.song.81000.json','["當陽正體露堂堂，休謂當年付飲光。", "彼既丈夫我亦爾，潁將好肉更剜瘡。"]'),
('ef62e8ae-05bd-43c0-a365-c6505a66fe1f','偈二十七首  其二○','釋紹隆','宋','宋诗','song-poetry','','[]','百鳥不來春又暄，憑欄溢目水如天。',32,'全唐诗/poet.song.81000.json','["百鳥不來春又暄，憑欄溢目水如天。", "無心還似今宵月，照見三千及大千。"]'),
('e70b7125-b5bb-42f7-b86e-8ae7a63f4806','偈二十七首  其二一','釋紹隆','宋','宋诗','song-poetry','','[]','放一線道，曲爲今時。',20,'全唐诗/poet.song.81000.json','["放一線道，曲爲今時。", "性地未明，須憑指注。"]'),
('2c284f5f-fcea-4870-b95f-9d318a654402','偈二十七首  其二二','釋紹隆','宋','宋诗','song-poetry','','[]','一二三四五，梅雨炎蒸暑。',40,'全唐诗/poet.song.81000.json','["一二三四五，梅雨炎蒸暑。", "碓觜也生花，道芽知幾許。", "古佛與露柱交參，貓兒咬殺犯罪虎。"]'),
('86de49cf-9d3b-4510-a79b-fa7a873e53e1','偈二十七首  其二三','釋紹隆','宋','宋诗','song-poetry','','[]','病起雲山草木秋，浮華世事謾悠悠。',32,'全唐诗/poet.song.81000.json','["病起雲山草木秋，浮華世事謾悠悠。", "從來萬法不爲侶，何以韶陽六不收。"]'),
('492ec3bb-c994-4a9e-ae38-9114f0dbb0eb','偈二十七首  其二四','釋紹隆','宋','宋诗','song-poetry','','[]','如來三轉於大千，趙州半藏亦如然。',32,'全唐诗/poet.song.81000.json','["如來三轉於大千，趙州半藏亦如然。", "其輪本來常清凈，一念承當誰後先。"]'),
('0c4bb660-5854-4f09-aef3-16af3274d9ac','偈二十七首  其二五','釋紹隆','宋','宋诗','song-poetry','','[]','葉落歸根，來時無口。',56,'全唐诗/poet.song.81000.json','["葉落歸根，來時無口。", "不留朕跡，騰身北斗。", "火裏蝍蟟，吞卻嘉州大象。", "益州馬腹，不覺膨脹。", "燈籠露柱大笑，拾得寒山撫掌。"]'),
('476afe1a-9659-49c6-9279-0944c188db8c','偈二十七首  其二六','釋紹隆','宋','宋诗','song-poetry','','[]','靈機密運，日月旋流。',40,'全唐诗/poet.song.81000.json','["靈機密運，日月旋流。", "四象推遷，一陽來復。", "化育之本，匝地普天。", "草木昆蟲，悉承恩力。"]'),
('98c36413-c0c6-497c-b4b7-e89325fa1c3d','偈二十七首  其二七','釋紹隆','宋','宋诗','song-poetry','','[]','脫身已曉南柯夢，始覺人間萬事空。',32,'全唐诗/poet.song.81000.json','["脫身已曉南柯夢，始覺人間萬事空。", "吹起還鄉無孔笛，夕陽斜照碧雲紅。"]'),
('2d3b33a1-9b23-4326-ae96-d14be0c11978','初祖贊','釋紹隆','宋','宋诗','song-poetry','','[]','闔國人難挽，西攜隻履歸。',24,'全唐诗/poet.song.81000.json','["闔國人難挽，西攜隻履歸。", "只應熊耳月，千古冷光輝。"]'),
('236da04b-43c2-40d6-88d4-91bd629c7b23','頌古','釋紹隆','宋','宋诗','song-poetry','','[]','迅雷吼破澄潭月，當下曾經三月聾。',32,'全唐诗/poet.song.81000.json','["迅雷吼破澄潭月，當下曾經三月聾。", "去卻膏盲必死疾，叢林從此有家風。"]'),
('de5e5fc8-ae99-49b8-9cff-6d557ed09021','送化士分衛','釋紹隆','宋','宋诗','song-poetry','','[]','大地撮來粟米粒，一毫頭上現乾坤。',32,'全唐诗/poet.song.81000.json','["大地撮來粟米粒，一毫頭上現乾坤。", "居家不離途中事，常在途中不出門。"]'),
('f5b6f7e3-457f-4087-b0e3-995284c023cf','開山明教大師贊','釋紹隆','宋','宋诗','song-poetry','','[]','春至百花觸處開，幽香旖旎襲人來。',32,'全唐诗/poet.song.81000.json','["春至百花觸處開，幽香旖旎襲人來。", "臨風無限深深意，聲色堆中絕點埃。"]'),
('e83ff814-b2d4-4db1-8a01-78eaf47477ba','朱槿花','釋紹隆','宋','宋诗','song-poetry','','[]','朱槿移栽釋梵中，老僧非是愛花紅。',31,'全唐诗/poet.song.81000.json','["朱槿移栽釋梵中，老僧非是愛花紅。", "朝開暮落關何，祇要人知色是空。"]'),
('d521f159-e4bc-42b5-b5eb-0389d1e607db','臨終偈','崔婆','宋','宋诗','song-poetry','','[]','西方一路好修行，上無條嶺下無坑。',32,'全唐诗/poet.song.81000.json','["西方一路好修行，上無條嶺下無坑。", "去時不用著鞋襪，脚踏蓮花步步行。"]'),
('a6d7122d-8640-4dae-bd27-717bf1d2b546','過郭傳師太尉山居','鄭諶','宋','宋诗','song-poetry','','[]','大固擅雄強，一峰連紫邏。',97,'全唐诗/poet.song.81000.json','["大固擅雄強，一峰連紫邏。", "戶牖開上頭，可愛不可唾。", "前山奔馬來，一一窗間過。", "無人識故侯，得趣貪高臥。", "不受富貴吞，但供香火課。", "槍甲久沈埋，立場書真頓挫。", "兩國正交兵，萬民心膽破。", "莫惜功業成，更遣聲名大。"]'),
('82310992-eb94-457c-9738-3b6fab650910','悟法呈守卓禪師偈','釋居慧','宋','宋诗','song-poetry','','[]','打破多年赤肉團，大千俱現一毫端。',32,'全唐诗/poet.song.81000.json','["打破多年赤肉團，大千俱現一毫端。", "縱橫妙用無多子，妙用縱橫總一般。"]'),
('c9fac7e7-3df2-4eae-94f3-24aa6d74be6b','偈二首  其一','釋居慧','宋','宋诗','song-poetry','','[]','鍾馗醉裏唱涼州，小妹門前祇點頭。',32,'全唐诗/poet.song.81000.json','["鍾馗醉裏唱涼州，小妹門前祇點頭。", "巡海夜叉相見後，大家拍手上高樓。"]'),
('ed4e7583-1f13-4e37-8a7e-0f418eadf5aa','偈二首  其二','釋居慧','宋','宋诗','song-poetry','','[]','百尺竿頭弄影戲，不唯瞞你又瞞天。',32,'全唐诗/poet.song.81000.json','["百尺竿頭弄影戲，不唯瞞你又瞞天。", "自笑平生歧路上，投老歸來沒一錢。"]'),
('21bfc998-82e4-40a2-b27a-77d73f94b4fd','和潘良貴題明州三江亭韻','汪思溫','宋','宋诗','song-poetry','','[]','危亭聳觀與雲侵，勝概何勞杖屨尋。',64,'全唐诗/poet.song.81000.json','["危亭聳觀與雲侵，勝概何勞杖屨尋。", "回合江山真有意，去來鷗鷺本無心。", "歡聲洋溢均千里，好句清新抵萬金。", "四海倚需經濟手，豈容長對白頭吟。"]'),
('b16f38ff-34d0-4aeb-b35c-cdc4a6afda66','次唐彥猷顧亭林韻','汪思溫','宋','宋诗','song-poetry','','[]','雲間更深處，獨見古人居。',48,'全唐诗/poet.song.81000.json','["雲間更深處，獨見古人居。", "想像風猷遠，荒寒景物疏。", "書成千卷帙，往事一邱墟。", "唯有清名在，流行百歲餘。"]'),
('bf6cb579-f729-4fe7-8f85-a8e80f5ac373','句','鄭如幾','宋','宋诗','song-poetry','','[]','看朱成碧醉中眼，施粉太白尊前人。',16,'全唐诗/poet.song.81000.json','["看朱成碧醉中眼，施粉太白尊前人。"]'),
('53233357-3f64-4b90-8759-2580fc27d2a8','游二老峰','章清','宋','宋诗','song-poetry','','[]','最愛東山碧玉叢，洗開塵土見穹隆。',31,'全唐诗/poet.song.81000.json','["最愛東山碧玉叢，洗開塵土見穹隆。", "官閑莫道？遁，看取巖前二老峰。"]'),
('68224d93-fd2a-47a3-8345-22bef701ce3a','句','章清','宋','宋诗','song-poetry','','[]','妙曲撓周郎。',6,'全唐诗/poet.song.81000.json','["妙曲撓周郎。"]'),
('9cdb8375-0b90-4e39-bb00-ca5761545c43','萬松嶺','趙遹','宋','宋诗','song-poetry','','[]','清溪狹徑小橋東，風入桃花處處同。',32,'全唐诗/poet.song.81000.json','["清溪狹徑小橋東，風入桃花處處同。", "我爲日長無一事，偶然來此聽松風。"]'),
('44bbdcd4-7362-4a89-ba28-66fb8f2bf220','句','趙遹','宋','宋诗','song-poetry','','[]','不是學僧初念佛，從來念佛指人迷。',16,'全唐诗/poet.song.81000.json','["不是學僧初念佛，從來念佛指人迷。"]'),
('395a5c79-3d86-4d66-8c5e-74e90adcbd4d','重游西湖','劉氏','宋','宋诗','song-poetry','','["\u897f\u6e56"]','西湖湖上山如畫，二十年前曾客來。',32,'全唐诗/poet.song.81000.json','["西湖湖上山如畫，二十年前曾客來。", "飛絮蒲城歸未得，江南老卻賀方回。"]'),
('0c5b563b-e3ed-4e12-a452-8aa5e460588b','詩二首  其一','劉氏','宋','宋诗','song-poetry','','[]','拔地高厓如鐵色，拂天老樹作寒聲。',32,'全唐诗/poet.song.81000.json','["拔地高厓如鐵色，拂天老樹作寒聲。", "他年記宿楁臺夜，便是南歸第一程。"]'),
('34beb4b4-70a2-42bb-9d1e-b1f7acd9cdc7','詩二首  其二','劉氏','宋','宋诗','song-poetry','','[]','囊無金絫貧如故，鏡有絲生老奈何。',32,'全唐诗/poet.song.81000.json','["囊無金絫貧如故，鏡有絲生老奈何。", "一事尚堪誇北客，來時詩少去時多。"]'),
('d238bfe0-d1a7-4b72-881d-27eb57606fb6','五月二十七日游諸洞','劉氏','宋','宋诗','song-poetry','','[]','來南百慮拙，所得惟幽尋。',144,'全唐诗/poet.song.81000.json','["來南百慮拙，所得惟幽尋。", "矧余玉雪友，共此丘壑心。", "江亭俯虛曠，穴室窮邃深。", "是時薄雨收，白靄籠青岑。", "棄筇追野步，卻扇開風襟。", "炎方豈必好，差遠鞞鼓音。", "且願海道清，莫問神州沉。", "徘徊惜景短，留滯畏老侵。", "昨遊感鶯哢，今至聞蟬吟。", "常恐官事縶，佳日妨登臨。", "避如逃學兒，汲汲貪寸陰。", "何因釋膠擾，把臂借入林。"]'),
('03758f6e-6eb6-4e57-bb7a-5dd0fa382e9b','題莒口鋪詩','劉氏','宋','宋诗','song-poetry','','[]','終朝行半驛，時有數家居。',48,'全唐诗/poet.song.81000.json','["終朝行半驛，時有數家居。", "店少聞灘壯，程遙見堠疏。", "山歌農設醴，野飯僕烹蔬。", "禽鳥先栖宿，勞生恨不如。"]'),
('e5136146-fd16-427e-9b83-e9a5a58795fa','福應山  其一','楊崈','宋','宋诗','song-poetry','','[]','清風送月上欄干，雲雨溪流破玉寒。',32,'全唐诗/poet.song.81000.json','["清風送月上欄干，雲雨溪流破玉寒。", "我有三峰高興在，漫堂聊作畫屏看。"]'),
('63dca40a-d980-4b5c-8892-645cc53deda5','福應山  其二','楊崈','宋','宋诗','song-poetry','','[]','醉後愁生任數奇，僧窗借夢入新詩。',32,'全唐诗/poet.song.81000.json','["醉後愁生任數奇，僧窗借夢入新詩。", "覺來著意尋桃李，除了春風總不知。"]'),
('5b838992-baaa-4643-8578-f28e8f12eb7b','南峰桃花洞','楊崈','宋','宋诗','song-poetry','','[]','水縛山腰點萬松，雲扶翠岫插寒空。',32,'全唐诗/poet.song.81000.json','["水縛山腰點萬松，雲扶翠岫插寒空。", "此溪定入桃源去，時見波間有落紅。"]'),
('6591b880-aeec-4532-bf1a-7f5c7f9a4c64','絕句','王寘','宋','宋诗','song-poetry','','[]','耕田博飯未爲辱，爲米折腰真可憐。',32,'全唐诗/poet.song.81000.json','["耕田博飯未爲辱，爲米折腰真可憐。", "高臥北窗風颯至，更于何處覓神仙。"]'),
('eae4a82d-e346-48c8-80d9-ab82ca6814ed','康判官寄螃蟹','毛友','宋','宋诗','song-poetry','','[]','沙頭郭索衆橫行，豈料身歸五鼎烹。',32,'全唐诗/poet.song.81000.json','["沙頭郭索衆橫行，豈料身歸五鼎烹。", "支解樽前供大嚼，胸中戈甲也虛名。"]'),
('7b941d3c-416b-43ea-8791-43eda463aff3','寄顯之太尉使燕山','毛友','宋','宋诗','song-poetry','','[]','三年淮海靜妖氛，老上龍庭又勒勳。',64,'全唐诗/poet.song.81000.json','["三年淮海靜妖氛，老上龍庭又勒勳。", "塞外爭看真太尉，行間猶識舊將軍。", "塵清漠北烽煙斷，風落山前號令聞。", "預想歸時如定遠，爭持白玉上青雲。"]'),
('d7e87faf-677a-4ac8-970e-6d2e5fcec082','冷泉亭','毛友','宋','宋诗','song-poetry','','[]','面山取勢俯山中，亭外安亭自蔽蒙。',64,'全唐诗/poet.song.81000.json','["面山取勢俯山中，亭外安亭自蔽蒙。", "眼界己通無礙物，胸中陡覺有真空。", "試尋櫓響驚時變，卻聽猿啼與舊同。", "萬事須臾成壞裏，我來閱世一初終。"]'),
('e0f92120-da63-488f-9279-d22770624d1e','桑','毛友','宋','宋诗','song-poetry','','[]','地僻柴桑古，人亡松菊存。',24,'全唐诗/poet.song.81000.json','["地僻柴桑古，人亡松菊存。", "不如彭澤吏，歸去有田園。"]'),
('ac4d4bb4-8c96-406f-a551-1cbdab91f5cd','玉晨鑒義芮公見訪','毛友','宋','宋诗','song-poetry','','[]','曾看扁舟下國門，風吹玉袖欲蜚仙。',64,'全唐诗/poet.song.81000.json','["曾看扁舟下國門，風吹玉袖欲蜚仙。", "經過弱水三萬里，邂逅長安五百年。", "投老漸諳隨處樂，此生只有未償眠。", "茅山朮老堪鑱斸，服食相依倘宿緣。"]'),
('42c2ca24-ce0f-4578-b82f-6ec69d684c41','寄陳子高','毛友','宋','宋诗','song-poetry','','[]','秋來目送雁南飛，不似春風雁卻歸。',32,'全唐诗/poet.song.81000.json','["秋來目送雁南飛，不似春風雁卻歸。", "慚愧宜興老居士，一生只在釣魚磯。"]'),
('aa02e633-71ae-4ac5-94fb-f811d0386dc3','句  其一','毛友','宋','宋诗','song-poetry','','[]','長安酒苦貴，蟹初臂著霜。',12,'全唐诗/poet.song.81000.json','["長安酒苦貴，蟹初臂著霜。"]'),
('47b359be-215b-4da4-99ca-80bba0a96437','句  其二','毛友','宋','宋诗','song-poetry','','[]','身綴鵷鸞集鳳池，夢尋麋鹿遊蟹堁。',16,'全唐诗/poet.song.81000.json','["身綴鵷鸞集鳳池，夢尋麋鹿遊蟹堁。"]'),
('265875e8-740d-4e09-a177-c1ebbd164fa2','句  其三','毛友','宋','宋诗','song-poetry','','[]','竹裏橫斜一兩枝。',8,'全唐诗/poet.song.81000.json','["竹裏橫斜一兩枝。"]'),
('c011a25f-a946-4324-b0a9-66dadcdcd782','句  其四','毛友','宋','宋诗','song-poetry','','[]','因風蛺蝶低仍起。',8,'全唐诗/poet.song.81000.json','["因風蛺蝶低仍起。"]'),
('8b685e3e-11be-4535-8a51-56294a78a9e0','寄外','毛友妻','宋','宋诗','song-poetry','','[]','剔燭親封錦字書，擬憑歸雁寄天隅。',32,'全唐诗/poet.song.81000.json','["剔燭親封錦字書，擬憑歸雁寄天隅。", "經年未報干秦策，不識如今舌在無。"]'),
('da9e897c-e220-4248-893d-a7de35426b01','宣和七年十二月二十一日就睿謨殿張燈預賞元宵曲燕應制','馮熙載','宋','宋诗','song-poetry','','[]','化工欲放陽春到，先教玄冥戮衰草。',384,'全唐诗/poet.song.81000.json','["化工欲放陽春到，先教玄冥戮衰草。", "層冰封地萬木僵，誰向雪中探天巧。", "璿璣星回斗指寅，羣芳未知時已春。", "人心蕩漾趁佳節，燈夕獨冠年華新。", "昇平萬里同文軌，井邑相連通四裔。", "蘭膏競吐夜烘春，和叔回車避義轡。", "巍巍九禁倚天開，溫風更覺先春來。", "試燈不用雨花落，迎陽爲卻寒崔嵬。", "宣和初載元冬尾，瑞白纔消塵不起。", "穆清光賞屬欽鄰，錦繡雲龍頒宴喜。", "初聞傳詔開睿謨，步障幾里承金鋪。", "調音度曲三千女，正似廣樂陳清都。", "遏雲妙唱韓娥侶，回雪飛花稱獨步。", "千春蟠木效地英，獻壽當筵豈金母。", "上林晚色煙靄輕，景龍遊人歡笑聲。", "霞裾月佩擁仙仗，翠鳳挾輦趨平成。", "銅華金掌散晶彩，翠碧重重簇珠琲。", "先從前殿望脩廊，日出綺霞紅茜海。", "神光通透雲母屏，驪龍出舞波濤驚。", "煌煌黼座承天命，座下錯落如明星。", "榻前玉案真核旅，獸炭銀爐夜初鼓。", "憲天重屋訝雲屯，崇道簫臺疑蜃吐。", "前楹火柱回萬牛，蘭卿璧碎色光浮。", "周圍照耀眼界徹，冰壺漾月生珠流。"]'),
('41f89c22-cff6-4380-9d87-877fc05c96b3','題朱陵洞水簾','李先輔','宋','宋诗','song-poetry','','[]','一片掛蒼崖，分明不惹埃。',48,'全唐诗/poet.song.81000.json','["一片掛蒼崖，分明不惹埃。", "蹙成珠顆白，垂下玉繩來。", "野燕飛難入，山風卷不開。", "聲聲去朝海，無意戀巖隈。"]'),
('614e2783-7b1e-4b25-8d08-3b4eaaa19ce7','赴建康過京口呈劉季高','葉夢得','宋','宋诗','song-poetry','','[]','客路重經黄鵠前，故人仍得暫留連。',64,'全唐诗/poet.song.81000.json','["客路重經黄鵠前，故人仍得暫留連。", "長槍大劍笑安用，白髮蒼顔空自憐。", "照野已驚横雉堞，蔽江行見下樓船。", "灞陵醉尉無人識，漫對雲峰說舊年。"]'),
('ef253195-c187-47af-874a-da903f8506cf','將至建康將佐出迓','葉夢得','宋','宋诗','song-poetry','','[]','遥憐部曲遠相迎，猶記當年驃騎營。',32,'全唐诗/poet.song.81000.json','["遥憐部曲遠相迎，猶記當年驃騎營。", "莫作揚州貴人看，箭聲聊聽餓鴟鳴。"]'),
('a63cf50f-1e10-4e1b-8124-5d609a947c7e','再至建康  其一','葉夢得','宋','宋诗','song-poetry','','[]','老罷那知力已疲，君恩誤遣出車詩。',64,'全唐诗/poet.song.81000.json','["老罷那知力已疲，君恩誤遣出車詩。", "金湯自鞏中原地，熊虎空高大將旗。", "江海百神朝魏闕，風雲千里護彤墀。", "白頭再啟征西將，深愧甘棠咏去思。"]'),
('c9f0785d-b8a6-4214-8bba-aa94765710bb','再至建康  其二','葉夢得','宋','宋诗','song-poetry','','[]','推轂何堪付老儒，腰間仍佩玉麟符。',64,'全唐诗/poet.song.81000.json','["推轂何堪付老儒，腰間仍佩玉麟符。", "千門萬户照天闕，二水三山非故廬。", "談笑定誰能却敵，衰慵真自笑非夫。", "淮南金鼓連滄海，爲趣嫖姚速破胡。"]'),
('9f56e148-2cc9-4d4f-8fc4-fcafeeda1bc8','府中即事  其一','葉夢得','宋','宋诗','song-poetry','','[]','稍喜胡塵欲漸清，離宫雙闕照層城。',64,'全唐诗/poet.song.81000.json','["稍喜胡塵欲漸清，離宫雙闕照層城。", "不驚巷陌銅駝没，自愧兒童竹馬迎。", "衰謝詎堪仍簿領，病慵久已廢杯行。", "三山不動潮頭過，洶洶江流自不平。"]'),
('eac82edd-801b-4d20-8907-4ed755951a8f','府中即事  其二','葉夢得','宋','宋诗','song-poetry','','[]','？坐笑往來頻，俯仰之間迹已陳。',63,'全唐诗/poet.song.81000.json','["？坐笑往來頻，俯仰之間迹已陳。", "可是猶思建鄴水，却應喜近洛陽塵。", "十年遍閱三行闕，四海奔馳一老臣。", "未有夷吾在江左，柴車空換兩朱輪。"]'),
('a56c59e0-5e2e-4f0e-96e4-8469a906070c','送模歸卞山并示僧宗義爲余守西巖者三首  其一','葉夢得','宋','宋诗','song-poetry','','[]','自我離山間，忽已兩改月。',96,'全唐诗/poet.song.81000.json','["自我離山間，忽已兩改月。", "饑人不忘食，未坐先已說。", "家僮挾書至，驚起慰愁絕。", "推尋到雞犬，問訊窮曲折。", "此生豈多爲，一壑萬慮滅。", "可能復大錯，更鑄八州鐵。", "汝歸馬蹄輕，初不恨觸熱。", "殷勤報松竹，吾豈成久别。"]'),
('f982be0d-a5ad-4899-97ac-3eba6a4ec5ff','送模歸卞山并示僧宗義爲余守西巖者三首  其二','葉夢得','宋','宋诗','song-poetry','','[]','端居探幽奇，自謂略已遍。',96,'全唐诗/poet.song.81000.json','["端居探幽奇，自謂略已遍。", "昨登西山巔，雄絕昔未見。", "溪湖莽吞吐，雲物紛百變。", "乃知十年間，尚或遺勝踐。", "巢成輙棄去，我豈秋社燕。", "爲吾課童僕，開闢盡二面。", "莫言羊腸險，徑小煩屢轉。", "杖藜不用扶，吾脚猶爾健。"]'),
('e58bc60c-b535-42ec-8c23-ef88bd6a8155','送模歸卞山并示僧宗義爲余守西巖者三首  其三','葉夢得','宋','宋诗','song-poetry','','[]','生長在山間，從翁守蓬户。',96,'全唐诗/poet.song.81000.json','["生長在山間，從翁守蓬户。", "人言膏粱子，粗免污紈袴。", "官居無多戀，暫止復遽去。", "家法恐未傳，此心良已素。", "義禪晚從我，似識此間趣。", "西巖鬱嶔岑，久斷俗子路。", "聊持山中節，爲我主留務。", "封陲際湖海，雲月皆所部。"]'),
('fc3bf8a4-3b00-4582-9c6c-b5b3ce2b27a7','建康舊俗貴重九上已諸曹皆休務祀神登北山參議馬君獨不出攜詩相過因言石林之勝次其韻','葉夢得','宋','宋诗','song-poetry','','[]','倦飛歸鳥正思還，叩户聊分半日閒。',64,'全唐诗/poet.song.81000.json','["倦飛歸鳥正思還，叩户聊分半日閒。", "勝事漫同談栗里，佳時休笑負龍山。", "簿書已老無餘力，香火朝真有舊班。", "他日尚期能過我，試窮千嶂共追攀。"]'),
('a70fc9fe-f15e-496c-902c-a5a2c81f0406','去歲以九日期賀子忱徐惇濟祝子權爲松竹臺之會作寒字韻詩唱酬數次今歲郡齋獨坐慨然有懷復用前韻寄惇濟子權時皆在湖州','葉夢得','宋','宋诗','song-poetry','','[]','地近中原怯早寒，一杯何處復追歡。',64,'全唐诗/poet.song.81000.json','["地近中原怯早寒，一杯何處復追歡。", "同尋澗壑閒誰共，强逐風塵老自難。", "歸夢孰知元有約，故情應得舊相看。", "閉關且示維摩病，圖畫他年付瓦官。"]'),
('073fbe4b-b329-4343-bbb6-52459193d528','郡齋望蒋山','葉夢得','宋','宋诗','song-poetry','','[]','十年在空山，未覺與世殊。',143,'全唐诗/poet.song.81000.json','["十年在空山，未覺與世殊。", "再來撫城郭，始悟非吾廬。", "豈不有華屋，旌旗拱王都。", "峨冠坐清旦，百吏前走趨。", "而我麋鹿姿，甎然若囚拘。", "忽看北山岑，突兀當坐隅。", "歡言顧之笑，便欲凌崎嶇。", "似我槿籬間，層巒儼相扶。", "瞻不得往，起步空長吁。", "少年四方志，顧盼略九區。", "衰慵一如此，畢願終田閭。", "拙艱固應爾，豈但悲老夫。"]'),
('d2b00747-187c-4141-9d0f-e1b016f33e72','自和','葉夢得','宋','宋诗','song-poetry','','[]','生涯一茅屋，物役忘萬殊。',144,'全唐诗/poet.song.81000.json','["生涯一茅屋，物役忘萬殊。", "再爲東諸侯，作軍蒐被廬。", "追尋念往迹，六鷁慚宋都。", "浩歌記土風，誰能和且趨。", "自笑良巳隘，真成撅株拘。", "聊云效知止，未敢傷廉隅。", "兹山閱人多，龍蟠委崎嶇。", "寄我千里目，笻枝尚堪扶。", "但愁見中原，驚心愴嗟吁。", "何由返我室，小徑遵芋區。", "未用懷遠遊，蒼茫賦三閭。", "明當秣吾馬，解組戒僕夫。"]'),
('1a73e185-b1e2-42c5-b890-23528c755cbe','西齋初成廨中舊有太湖石數十枚因壘之庭下','葉夢得','宋','宋诗','song-poetry','','["\u592a\u6e56"]','萬壑千巖不易求，壺中聊寄小瀛洲。',64,'全唐诗/poet.song.81000.json','["萬壑千巖不易求，壺中聊寄小瀛洲。", "稍看硉兀雲峰出，便有檀欒桂嶼幽。", "絕境自知難遽忘，奇蹤争怪獨能留。", "山翁已老猶兒戲，漫擬伸眉一散愁。"]'),
('bfd6f5bc-d615-44ed-b66b-0f4ed08cd734','與晁激仲夜話','葉夢得','宋','宋诗','song-poetry','','[]','外家文采到諸郎，凜凜詞鋒未可當。',64,'全唐诗/poet.song.81000.json','["外家文采到諸郎，凜凜詞鋒未可當。", "伴我何辭共戎馬，憐君聊欲濯糟漿。", "殘年落寞風塵際，永夜從容銀燭光。", "祇恐扁舟吾欲去，病慵無意薄淮陽。"]'),
('ccf9caa2-4272-4fc1-887a-6f27ca66e749','次韻答激仲','葉夢得','宋','宋诗','song-poetry','','[]','牛渚誰逢臨汝郎，參軍暫肯佐戎行。',64,'全唐诗/poet.song.81000.json','["牛渚誰逢臨汝郎，參軍暫肯佐戎行。", "世緣不擬營三窟，人事那求饋五漿。", "春近嶺梅横暗蕊，夜寒霜月落飛光。", "十年情話何由盡，我亦傷心嘆渭陽。"]'),
('705bb8a6-0b54-4f06-a6f1-8e6e6ca71bf2','再答','葉夢得','宋','宋诗','song-poetry','','[]','生涯久許捕魚郎，鳬鴈相追不亂行。',64,'全唐诗/poet.song.81000.json','["生涯久許捕魚郎，鳬鴈相追不亂行。", "但遣陶廬有松徑，不辭楚酒醉椒漿。", "交情老柏寒方見，妙語靈珠夜有光。", "回首漸知歸路好，已看梅柳動初陽。"]'),
('e82eed69-6402-4755-b962-169081d387d5','又答','葉夢得','宋','宋诗','song-poetry','','[]','家聲合繼紫微郎，不獨詩同沈鮑行。',64,'全唐诗/poet.song.81000.json','["家聲合繼紫微郎，不獨詩同沈鮑行。", "晚歲清談淹幕府，中原喜氣望壺漿。", "頗聞時論憐衰朽，空愧君恩負寵光。", "肯許輞川期後約，彈冠知不借王陽。"]'),
('f42ae473-e521-4511-b560-8e9e1f4b3dd3','閱武士回邊報與山中信併至','葉夢得','宋','宋诗','song-poetry','','[]','椎牛饗士隘轅門，投老兵間强自論。',64,'全唐诗/poet.song.81000.json','["椎牛饗士隘轅門，投老兵間强自論。", "稍喜並邊無牧馬，却慚空帳有驚猿。", "乞盟似欲回天意，排難誰能報主恩。", "壮志蹉跎真便爾，獨懷搔首望丘園。"]'),
('84001054-9492-4581-8b8c-411b1275acf8','雨夜西堂獨宿','葉夢得','宋','宋诗','song-poetry','','[]','華屋非所安，憶我三間茅。',120,'全唐诗/poet.song.81000.json','["華屋非所安，憶我三間茅。", "閉關傲初寒，坐聽風雨交。", "燈火微黯淡，松篁雜蕭梢。", "一枝寄宿鳥，自許無傾巢。", "我非乘桴翁，詎敢辭繫匏。", "朅來亦何事，大似從僧包。", "忽聞報嚴更，鼓鐘亂鉦鐃。", "慨然念故棲，此地寧久抛。", "君知芥舟微，但可浮杯坳。", "去矣無更疑，作詩聊自嘲。"]'),
('4307b387-0729-445b-8d29-b57c24709101','雨夜與模論中原旦起模與徐惇濟游清凉觀形勢嘉其有志因以勉之','葉夢得','宋','宋诗','song-poetry','','[]','千年石頭城，突兀真虎踞。',120,'全唐诗/poet.song.81000.json','["千年石頭城，突兀真虎踞。", "蒼茫劫火餘，尚復留故處。", "大江轉洪濤，騰踏不可御。", "空城寂寞潮，日暮獨東去。", "登臨欲弔古，俯視極千慮。", "吾兒勇過我，蓐食穿沮洳。", "謂言撫中原，未暇論割據。", "功名亦何人，我老聊自恕。", "他年報國心，或可借前箸。", "無爲笑頹然，已飽安用飫。"]'),
('49cb6fc8-3cc7-4f6d-ae26-1ec1354cb13a','連日邊報稍稀西齋默坐','葉夢得','宋','宋诗','song-poetry','','[]','鼓角遥聞出塞聲，邊風吹鴈過高城。',64,'全唐诗/poet.song.81000.json','["鼓角遥聞出塞聲，邊風吹鴈過高城。", "疆陲無復戊己尉，盗賊猶憐壬午兵。", "歲晚胡牀閉深閣，夜長刁斗聽連營。", "便須從此傳烽息，要及春農論勸耕。"]'),
('7839f8a4-d117-4569-a9ee-c9c5c69b46be','獨坐不得眠讀舊書','葉夢得','宋','宋诗','song-poetry','','[]','青燈相對久無眠，擁毳無人伴夜禪。',64,'全唐诗/poet.song.81000.json','["青燈相對久無眠，擁毳無人伴夜禪。", "閉户便能忘屨迹，炷香時自續爐煙。", "辭家屈指驚三月，撫事關心愴十年。", "漫展殘書亦安用，可能猶欲絕韋編。"]'),
('94c2720d-c94e-4d67-8838-174e3b5d7057','懷西山','葉夢得','宋','宋诗','song-poetry','','[]','西山十畝强，高下略不齊。',168,'全唐诗/poet.song.81000.json','["西山十畝强，高下略不齊。", "嵌空抱奇秀，上有凌雲梯。", "小屋八九間，茅簷敢辭低。", "所欣面勢好，老稚通扶攜。", "密竹轉脩徑，老松故成蹊。", "仲冬景氣肅，碧草猶萋萋。", "仰視天宇大，四觀渺回溪。", "徐行信足力，未畏成顛躋。", "用意各有適，孰云無町畦。", "平生幾濡首，末路多噬臍。", "不作巢幕燕，肯從觸藩羝。", "胡爲濫麾鉞，坐聽鳴鼓鼙。", "外物委蟲臂，全生思馬蹄。", "可能三徑草，歸路老更迷。"]'),
('25eb91b3-32b5-42c1-bfaa-46c89b587c42','杜堅大夫作南窗求詩爲賦','葉夢得','宋','宋诗','song-poetry','','[]','意得不願多，心閒本長虚。',120,'全唐诗/poet.song.81000.json','["意得不願多，心閒本長虚。", "超然適有契，天地良有餘。", "頗念彭澤老，所懷常晏如。", "南窗僅幾何，盤薄萬古初。", "束带悟已往，世紛便能疏。", "懸知千載情，共有三間廬。", "杜子老不遇，買田賦歸歟。", "西山鬱攢空，江水繞故墟。", "衡門閉松菊，亦有琴與書。", "邂逅一杯酒，安知我非渠。"]'),
('1fcedf22-d7fc-4268-bfd1-670a8c7aff4b','送光上人還湖南光丞相吴元忠之母弟舊名惇字元常以進士入官已而棄家祝髮云','葉夢得','宋','宋诗','song-poetry','','[]','棄家忽若遺，四海吴元常。',120,'全唐诗/poet.song.81000.json','["棄家忽若遺，四海吴元常。", "軒冕安足輕，妻孥等毫芒。", "古來惟仁者，有勇故莫當。", "棖也自多慾，此心焉得剛。", "相君抱壮烈，慷慨志亦償。", "徒悲蕭長倩，屢折終堂堂。", "子居真俗間，袖手毎在傍。", "十載復相見，掛帆上瀟湘。", "我居卞峰顛，萬仞凌穹蒼。", "何時一茅屋，共結兩道場。"]'),
('075ab194-4d14-4adb-aa2f-799d8709f279','山間每歲正月望夜梅花正開多與客飲花下今年郡廨獨坐十四夜張暘叔晁激仲相過共話宣和間事慨然歸不能寐因以寫懷','葉夢得','宋','宋诗','song-poetry','','[]','山頭野梅白玉花，月明弄影紛横斜。',160,'全唐诗/poet.song.81000.json','["山頭野梅白玉花，月明弄影紛横斜。", "青天無雲萬峰立，下有十畝幽人家。", "年年春歸不暇省，但掃雪徑尋寒葩。", "老夫已忘少年事，燈火豈念更繁華。", "一杯起步遍空谷，破屋歸卧暾朝霞。", "陪都復来亦何有，凛凛殺氣浮高牙。", "重關深鎻夜漏永，忽記昨夢翻長嗟。", "景龍門前一月會，金碗賜酒餘雄誇。", "神州陸沉近歸我，漢節方議通胡沙。", "天翻地覆那得料，忍復更聽漁陽撾。"]'),
('c031762a-bdb7-49b1-8d05-1291ca70d63d','次韻馬參議同游蒋山','葉夢得','宋','宋诗','song-poetry','','[]','華屋驚随劫火飛，江山空自繞邦圻。',64,'全唐诗/poet.song.81000.json','["華屋驚随劫火飛，江山空自繞邦圻。", "靈蹤可便超千載，妙解誰從寄一微。", "著屐尚堪窮碧落，據牀聊伴俯清輝。", "追尋會識關心處，未怪衰翁苦憶歸。"]'),
('ab1d12ac-bca5-486a-943e-2e5b6e9ada3a','再次韻','葉夢得','宋','宋诗','song-poetry','','[]','頽垣敗屋落花飛，草草春光亦故圻。',64,'全唐诗/poet.song.81000.json','["頽垣敗屋落花飛，草草春光亦故圻。", "但愛野塘輸渌净，不知風景轉清微。", "帳空尚憶猿驚曉，基廢猶傳鳳覽輝。", "女几自無平賊意，坐來休笑久忘歸。"]'),
('49a0d08b-fbd5-48f8-b1e5-2d9d90ef5116','三次韻','葉夢得','宋','宋诗','song-poetry','','[]','荒林寂寂鳥飛飛，舊事那容數一圻。',64,'全唐诗/poet.song.81000.json','["荒林寂寂鳥飛飛，舊事那容數一圻。", "山色自憐雲泱莽，暮寒猶作雨霏微。", "談餘故喜珠仍在，境勝端知玉有輝。", "問取塔中黄面老，此生何處是真歸。"]'),
('68195265-5499-459a-9c1b-52ad6fda901f','四次韻','葉夢得','宋','宋诗','song-poetry','','[]','雨厭殘雲暝不飛，亂紅猶欲點春圻。',64,'全唐诗/poet.song.81000.json','["雨厭殘雲暝不飛，亂紅猶欲點春圻。", "蒋陵路絕人誰到，蕭寺庭荒迹已微。", "偃蹇松篁空自老，參差觀閣舊相輝。", "令威等是千年客，想有遼東獨鶴歸。"]'),
('2fe001c7-c11a-4dba-9dba-5a7e275ac033','偶至劉少師園二首  其一','葉夢得','宋','宋诗','song-poetry','','[]','葉底黄鸝一再鳴，故知久住識人情。',32,'全唐诗/poet.song.81000.json','["葉底黄鸝一再鳴，故知久住識人情。", "習家池館元無禁，應笑山公自懶行。"]'),
('a40417fe-8c61-4f75-8c39-164d71d07217','偶至劉少師園二首  其二','葉夢得','宋','宋诗','song-poetry','','[]','老木參天拱十圍，何妨桃李間相依。',32,'全唐诗/poet.song.81000.json','["老木參天拱十圍，何妨桃李間相依。", "却憐韓令功如許，不爲山丹少霽威。"]'),
('3d0088fc-67d2-4161-8a62-859302b1c01e','蔡子因相過留踰月','葉夢得','宋','宋诗','song-poetry','','[]','解作江山一月留，仲文儒雅更風流。',64,'全唐诗/poet.song.81000.json','["解作江山一月留，仲文儒雅更風流。", "欲知爵躍心能喜，正愛蟬連語不休。", "築室君方論並舍，歸山我已辦扁舟。", "交親四海今餘幾，萬事傷心付白頭。"]'),
('6228ae38-c219-43f5-a55a-bf8b5efb2cf7','次韻再答子因','葉夢得','宋','宋诗','song-poetry','','[]','人事紛紛去不留，客心空感大江流。',64,'全唐诗/poet.song.81000.json','["人事紛紛去不留，客心空感大江流。", "已拚瓠落真何用，那得鐘鳴尚不休。", "鄰里朱陳無别社，江山李郭有同舟。", "若爲便覓苕溪路，六月明珠剥芡頭。"]'),
('2822d6d7-7fb2-4793-8fee-90824188c58a','蔡子因前韻留别再答二首  其一','葉夢得','宋','宋诗','song-poetry','','[]','早時物望冠陳留，晚悟禪心更不流。',64,'全唐诗/poet.song.81000.json','["早時物望冠陳留，晚悟禪心更不流。", "安用前身真阮籍，久知此道得孫休。", "千年會有歸来鶴，萬事元同不繫舟。", "邂逅一菴随地有，不妨衲被對蒙頭。"]'),
('632cd911-6d79-4546-b690-684358cc2717','蔡子因前韻留别再答二首  其二','葉夢得','宋','宋诗','song-poetry','','[]','已議營屯列上留，稍欣羣盗障横流。',64,'全唐诗/poet.song.81000.json','["已議營屯列上留，稍欣羣盗障横流。", "三時舊業終應在，萬里長征亦少休。", "和策但令均挾纊，壮圖何用輒焚舟。", "東都自是興王地，虎踞寧須問石頭。"]'),
('4702915f-6c73-44b8-b7a6-8a902eff097b','劉太保招撫淮北劉馬軍屢奏捷','葉夢得','宋','宋诗','song-poetry','','[]','先聲已起故將軍，卧治何勞病使君。',64,'全唐诗/poet.song.81000.json','["先聲已起故將軍，卧治何勞病使君。", "冠带豈能忘舊俗，山河自亦惡妖氛。", "羽書奏捷無留敵，輿地論封有策勲。", "横槊賦詩非我事，車書會復見斯文。"]'),
('f49cba28-56f3-420a-a419-31a401a66429','題子因雙鳩百葉桃畫','葉夢得','宋','宋诗','song-poetry','','[]','百葉緗桃照眼明，繁枝似見雨新晴。',32,'全唐诗/poet.song.81000.json','["百葉緗桃照眼明，繁枝似見雨新晴。", "故知睡足聊相並，不作林間逐婦聲。"]'),
('ed47f78c-7f74-47df-a8ac-31d801f5839d','徐惇立罷吏部郎官出守天台待次卞山舊居因寄','葉夢得','宋','宋诗','song-poetry','','[]','嵇康不作絕交書，出處蕭然兩裕如。',64,'全唐诗/poet.song.81000.json','["嵇康不作絕交書，出處蕭然兩裕如。", "錦帳不妨游省户，草堂還得賦郊居。", "傾崖濺水青雲上，夾道輕陰落絮餘。", "亦記舊游聊待我，未須催駕赤城車。"]'),
('d2b8e84d-fb9a-4f28-83c3-11b06ef048e0','陳子高移官浙東戱寄','葉夢得','宋','宋诗','song-poetry','','[]','幕府陳琳老，官身戀故溪。',48,'全唐诗/poet.song.81000.json','["幕府陳琳老，官身戀故溪。", "解談孫破虜，那厭庾征西。", "未擬煩刀筆，聊應謝鼓鼙。", "登臨如得句，小字與親題。"]'),
('7819a0ff-b6c7-41f4-be1f-6389ee3e83d3','戲示幕客','葉夢得','宋','宋诗','song-poetry','','[]','不用黄金更築臺，一時傾蓋盡奇材。',32,'全唐诗/poet.song.81000.json','["不用黄金更築臺，一時傾蓋盡奇材。", "關中豈是穰侯物，浪怕諸侯客子来。"]'),
('eda6a1de-75c7-4095-8f26-3365c814bfdb','章幾道將歸小飲懷謝城父','葉夢得','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','中年甚畏别交親，况復雲山舊結鄰。',64,'全唐诗/poet.song.81000.json','["中年甚畏别交親，况復雲山舊結鄰。", "澗谷何時同笑語，干戈已老更風塵。", "少留對榻聊分坐，多病持杯漫幾巡。", "賈傅長沙知健否，洞庭波浪渺無津。"]'),
('8f62de33-3a43-44b5-85e4-32f67dce7552','聞邊報示諸將','葉夢得','宋','宋诗','song-poetry','','[]','插羽驚傳赤白囊，胡行如鬼尚跳梁。',64,'全唐诗/poet.song.81000.json','["插羽驚傳赤白囊，胡行如鬼尚跳梁。", "頗聞廟算無遺策，但遣封人謹豫防。", "送死定知天悔禍，追奔寧使汝争彊。", "将軍剩有封侯印，盡掃無令一鏃亡。"]'),
('7800aead-f76a-4526-a870-e4a68ceed41e','虜酋復過河王師出討','葉夢得','宋','宋诗','song-poetry','','[]','羽檄初徴天下兵，誤慚一陣守王城。',64,'全唐诗/poet.song.81000.json','["羽檄初徴天下兵，誤慚一陣守王城。", "秦兵出項終何得，漢將征遼會掃平。", "便遣幽燕驅號令，久憐河洛污羶腥。", "書生豈解論幾事，詎信平涼有劫盟。"]'),
('00f4b63b-fb9d-43bd-a598-b41ef3353e54','遣晁公昂按行瀕江營壘','葉夢得','宋','宋诗','song-poetry','','[]','他日傳烽望夕煙，重来老更負戎旃。',64,'全唐诗/poet.song.81000.json','["他日傳烽望夕煙，重来老更負戎旃。", "我言固自平平耳，王事那辭數數然。", "轉餉未應勞木馬，摧鋒猶或要戈船。", "天威本自無多殺，萬一征和属此年。"]'),
('2e6eb7dc-9ce9-4432-9630-e695da440848','聞兀朮將過淮再遣晁公昂覘師','葉夢得','宋','宋诗','song-poetry','','[]','狂酋屢慣騁長驅，未省新軍有被廬。',67,'全唐诗/poet.song.81000.json','["狂酋屢慣騁長驅，未省新軍有被廬。", "快飲勿辭金鑿落，先聲須破鐵浮圖。", "{走勾}官爾自疲千里，飛将吾寧較一夫。", "試向八公山上望，當關何用守濡須。"]'),
('6e690d48-6742-448e-8c9d-f5b21d4e9316','登南城','葉夢得','宋','宋诗','song-poetry','','[]','大江南渡是長干，北望清淮歲已寒。',64,'全唐诗/poet.song.81000.json','["大江南渡是長干，北望清淮歲已寒。", "廢壘至今聞鶴唳，蒼山從古自龍蟠。", "鬢毛白盡空看鏡，髀肉銷来尚據鞍。", "折箠不能笞黠虜，遺民猶有漢衣冠。"]'),
('5750f877-7da1-4d99-992f-ab520e48f7bc','與陳子高夜話','葉夢得','宋','宋诗','song-poetry','','[]','鼓角開東道，山川壮别京。',48,'全唐诗/poet.song.81000.json','["鼓角開東道，山川壮别京。", "病慵憐竊食，幽憤敢論兵。", "廢簡鉛黄暗，馳囊赤白驚。", "褒衣聊自喜，時見魯諸生。"]'),
('0c6a6e4b-5a70-4837-9691-f5b6eed33cbe','送馬參議觀國從辟劉太保','葉夢得','宋','宋诗','song-poetry','','[]','伏波老自厭壺頭，壮志諸孫凛未休。',64,'全唐诗/poet.song.81000.json','["伏波老自厭壺頭，壮志諸孫凛未休。", "稍喜烽烟從絕塞，即聞貔虎静中州。", "先聲早已傳推轂，婉畫聊煩佐運籌。", "好去劉公書一紙，無忘老子上南樓。"]'),
('89f8f4ad-83f7-4f10-9353-bf1a939e29fb','次韻馬參議留别','葉夢得','宋','宋诗','song-poetry','','[]','戎車百兩去難攀，秣馬前驅矢石間。',128,'全唐诗/poet.song.81000.json','["戎車百兩去難攀，秣馬前驅矢石間。", "析木舊津吞朔易，神都新令愯寘顔。", "傳聲已報連三捷，觸熱那辭冒百艱。", "束縛會看擒頡利，灰釘何待執戎蠻。", "清談一笑時能共，妙語千篇未可刪。", "緩带且從黄閣老，峨冠行奉紫宸班。", "分攜坐歎虚懸榻，老病懷歸祇故山。", "他日小舟能過我，萬峰深處有柴關。"]'),
('1c0805a5-0f5a-497e-b02a-214e188103e7','寄潭州謝城父','葉夢得','宋','宋诗','song-poetry','','[]','南國波濤已過春，稍清羣盗剪荆榛。',64,'全唐诗/poet.song.81000.json','["南國波濤已過春，稍清羣盗剪荆榛。", "孰知賈傅傾多士，但說番君得遠民。", "痛飲千鐘應可强，傳書一紙未能頻。", "臺評袖裏猶多在，莫枉汀洲詠白蘋。"]'),
('cff7e186-1447-4397-926d-242e043bbc23','久不飲酒厨人獻白醪却之','葉夢得','宋','宋诗','song-poetry','','[]','老大無堪百不能，年来但可飲三升。',32,'全唐诗/poet.song.81000.json','["老大無堪百不能，年来但可飲三升。", "齋厨何用須佳釀，莫遣征南誤見稱。"]'),
('e78c4a07-ae14-4fc7-ab29-87f423fafb9a','立秋二首  其一','葉夢得','宋','宋诗','song-poetry','','[]','江上西風萬里秋，際空高浪洶回流。',64,'全唐诗/poet.song.81000.json','["江上西風萬里秋，際空高浪洶回流。", "他時譽賊真非策，此日摧鋒盍有謀。", "天險漫能憑故國，陸沉端復恨神州。", "將軍競綰封侯印，誰爲吾君更解憂。"]'),
('e1af195b-d28a-4025-a961-f931776c31ce','立秋二首  其二','葉夢得','宋','宋诗','song-poetry','','[]','蕭關隴水隔天區，壮士何人是破奴。',64,'全唐诗/poet.song.81000.json','["蕭關隴水隔天區，壮士何人是破奴。", "一日頓傳三節度，十年空鬭五單于。", "坐談激烈心猶在，疲俗彫殘喘未蘇。", "安得倉箱盈百萬，少令天下足軍儲。"]'),
('f260f510-14ac-4211-aec5-51f87e04f72c','秋高申戒諸屯示幕府','葉夢得','宋','宋诗','song-poetry','','[]','草枯馬健已高秋，堂上應須早伐謀。',64,'全唐诗/poet.song.81000.json','["草枯馬健已高秋，堂上應須早伐謀。", "傳箭猶聞聚蜂蟻，控弦那得犯貔貅。", "書生會擊單于頸，壮士誰舂長狄喉。", "快使營平歸印綬，貂蟬敢望出兜鍪。"]'),
('f1b18570-de09-45ea-9615-ddda1ad88113','寄順昌劉節使','葉夢得','宋','宋诗','song-poetry','','[]','四海胡塵久未清，遥聞苦戰有奇兵。',64,'全唐诗/poet.song.81000.json','["四海胡塵久未清，遥聞苦戰有奇兵。", "妖氛盡掃人誰敵，捷奏初傳我亦驚。", "授鉞已欣傳帝澤，揮戈終見静王城。", "軒臺固有英靈在，更遣将軍得令名。"]'),
('55afafbf-cafb-44db-b32a-42a714a64417','二月六日虜兵犯歷陽方出師客自吴江来有寄聲道湖山之適趣其歸者慨然寫懷','葉夢得','宋','宋诗','song-poetry','','[]','松江浪静如鏡平，菰蒲長春秋水生。',160,'全唐诗/poet.song.81000.json','["松江浪静如鏡平，菰蒲長春秋水生。", "晴沙回鴈久未到，坐想白鷗增眼明。", "五年辜負釣船約，故人疑我真逃盟。", "豈知塵纓不易濯，正想滄浪之水清。", "朝来鐵馬暗江北，中流疊鼓雲濤傾。", "樓船十萬下采石，旗纛滅没天戈横。", "書生事業今乃爾，授鉞孰敢辭專征。", "豈無傳檄走飛騎，漫復長嘯登高城。", "文思天子民父母，大度未忍鏖奇兵。", "澶淵一矢安五世，明日儻或傳諸營。"]'),
('fd66b13c-5487-4571-9ef7-dd1345e8e953','淮西軍大破賊兵連六告捷喜成口號二首  其一','葉夢得','宋','宋诗','song-poetry','','[]','一戰聊麾十萬師，西来捷報走黄旗。',64,'全唐诗/poet.song.81000.json','["一戰聊麾十萬師，西来捷報走黄旗。", "六驘壮騎終？去，九虎将軍亦謾爲。", "面內疲民元不改，從中勝算自無遺。", "臨軒想見天顔喜，百辟歡聲動玉墀。"]'),
('6f1f62a7-fd16-4577-9773-cd90e5898688','淮西軍大破賊兵連六告捷喜成口號二首  其二','葉夢得','宋','宋诗','song-poetry','','[]','蛇豕何知闞近坰，且欣鏖戰掃羶腥。',64,'全唐诗/poet.song.81000.json','["蛇豕何知闞近坰，且欣鏖戰掃羶腥。", "寄聲急走破羌帖，歸路還經征虜亭。", "多難兵間頭更白，放懷物外眼終青。", "花殘不負巖邊約，更看前焚老上庭。"]'),
('efe715d4-746f-4412-b642-fa510bbd634d','爲山亭後有小池叢石間得石螭因以斛汲水導注之','葉夢得','宋','宋诗','song-poetry','','[]','微流自作小潺湲，底處奔崖落迸泉。',64,'全唐诗/poet.song.81000.json','["微流自作小潺湲，底處奔崖落迸泉。", "驟喜忽聞飛雨過，却疑驚起老龍眠。", "憑軒但遣時醒耳，裂岸何須去拍天。", "索寞歸心誰與寄，家山不到已三年。"]'),
('983ae42d-5461-4c6d-bc7e-a6ba9bc625f5','爲山亭移植冬青等近遂成陰','葉夢得','宋','宋诗','song-poetry','','[]','一寸蒼根手自鉏，年来繞屋亦扶疏。',32,'全唐诗/poet.song.81000.json','["一寸蒼根手自鉏，年来繞屋亦扶疏。", "客来但愛清陰好，不見幽人澗下居。"]'),
('56bc9c5c-0f45-4d28-ba53-33753ad84e57','小飲示幕府','葉夢得','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','邊書日夜急，王旅方徂征。',108,'全唐诗/poet.song.81000.json','["邊書日夜急，王旅方徂征。", "我非劉越石，長嘯徒登城。", "緬想豺與虎，行當築鯢鯨。", "傳車日邊来，風雷走天聲。", "黄旗三面至，捷奏紛紛横。", "天險限南北，長江正東傾。", "諸君亦良苦，唾口争請纓。", "誰云凌煙閣，自昔無書生。", "巵酒安足辭，勉當建雄名。"]'),
('fd468107-77ed-4a62-814d-85be4fb3dce9','徐惇濟書報甞過余石林','葉夢得','宋','宋诗','song-poetry','','[]','繞澗新添數百竿，故人書爲報平安。',64,'全唐诗/poet.song.81000.json','["繞澗新添數百竿，故人書爲報平安。", "似聞謖謖山風響，正想陰陰夏簟寒。", "老大不能窮蠹簡，歸来便擬掛塵冠。", "一杯且覓林間約，莫枉山王廢舊歡。"]'),
('38ffa8cd-a5cf-489d-b58b-72e8d8e4531d','夜聽莫撫幹彈琴流水操','葉夢得','宋','宋诗','song-poetry','','[]','故山不在眼，遠想流水聲。',120,'全唐诗/poet.song.81000.json','["故山不在眼，遠想流水聲。", "佳人南風手，起我澗谷情。", "十載厭鼙鼓，囂塵亂鳴鉦。", "蕭然洗病耳，爲鼓一再行。", "度險微斷續，奔前忽琮琤。", "凄風拉遠響，薄月當微明。", "亂石拱高下，回環亦峥嶸。", "吾歸正自爾，猛士方西征。", "年少勇過我，犬羊羶王城。", "請更平戎操，盡掃洛河清。"]'),
('4ef8628b-abdf-481c-8258-176f7c8b6f9d','送沈傳曜','葉夢得','宋','宋诗','song-poetry','','[]','卞峰摩青空，東望烏氐墩。',120,'全唐诗/poet.song.81000.json','["卞峰摩青空，東望烏氐墩。", "豈忘宿舂糧，終愧一欵門。", "邂逅此相過，傾懷得徐論。", "人言解牛刀，要使？劇煩。", "未悟清廟器，朱絃列罍尊。", "我衰百慮息，但念三畝園。", "王師肅西征，萬馬先雲屯。", "何力償賜履，緬慚羡歸軒。", "寄聲舴艋舟，想見浮鴈村。", "清冷尚可釣，無使霅水渾。"]'),
('aa13d438-e386-411c-b6b8-0850989349b1','八月二十日','葉夢得','宋','宋诗','song-poetry','','[]','？覺凉風入，軒窗自亦幽。',35,'全唐诗/poet.song.81000.json','["？覺凉風入，軒窗自亦幽。", "漫能持麈尾，終憶釣槎頭。", "我從添老，愁予不爲秋。"]'),
('b943ac28-c5ef-4928-bf26-c50181714afd','偶書爲山亭五首  其一','葉夢得','宋','宋诗','song-poetry','','[]','爲山亭下小巑岏，只欠蕭蕭竹數竿。',32,'全唐诗/poet.song.81000.json','["爲山亭下小巑岏，只欠蕭蕭竹數竿。", "但遣飛流時潄玉，且將歸思爲翁寬。"]'),
('ddbe71e7-6079-4643-ac84-6ee2b1fcff84','偶書爲山亭五首  其二','葉夢得','宋','宋诗','song-poetry','','[]','微風似與洗庭除，石枕蠻藤不負予。',32,'全唐诗/poet.song.81000.json','["微風似與洗庭除，石枕蠻藤不負予。", "八尺方牀聊已足，可須仍要讀殘書。"]'),
('f23bfe74-7fb6-4309-a2bc-2b76b7c948bb','偶書爲山亭五首  其三','葉夢得','宋','宋诗','song-poetry','','[]','僚吏相哀白事稀，抱琴時自弄清徽。',32,'全唐诗/poet.song.81000.json','["僚吏相哀白事稀，抱琴時自弄清徽。", "何妨共倒樽中渌，不怕鳴騶問道歸。"]'),
('6ed6fcdb-5d93-4796-874a-dacbfc615b76','偶書爲山亭五首  其四','葉夢得','宋','宋诗','song-poetry','','[]','羶穢初聞潁水清，東君更復過蒙城。',32,'全唐诗/poet.song.81000.json','["羶穢初聞潁水清，東君更復過蒙城。", "應須鄂渚兵同入，賊壘聊煩盡剗平。"]'),
('72b66339-b0ea-4864-97c0-ccee56d6b714','偶書爲山亭五首  其五','葉夢得','宋','宋诗','song-poetry','','[]','使節交馳數路分，頗知旰食念前軍。',32,'全唐诗/poet.song.81000.json','["使節交馳數路分，頗知旰食念前軍。", "疾須圖上金城策，一見真？勝百聞。"]'),
('4940ded5-5826-4980-a468-362a9b6f2766','次韻程伯禹贈宗室趙朝請','葉夢得','宋','宋诗','song-poetry','','[]','人物相望不並時，使君水鑑有真知。',64,'全唐诗/poet.song.81000.json','["人物相望不並時，使君水鑑有真知。", "未論理窟傾三語，只鬭詩壇自一奇。", "擾擾干戈猶戰伐，紛紛簿領更喧卑。", "應須便作高軒過，好德何人佐我儀。"]'),
('34e012fc-bf9a-41ba-ae06-67e662e91d56','次韻程伯禹用時字韻見寄二首  其一','葉夢得','宋','宋诗','song-poetry','','[]','衰病侵尋豈故時，暮年懷抱祇公知。',64,'全唐诗/poet.song.81000.json','["衰病侵尋豈故時，暮年懷抱祇公知。", "彊論出處初無意，底有文章更好奇。", "王氣山川元自壮，歸心茅竹敢嫌卑。", "中原趣下王正曆，盡使遺民復漢儀。"]'),
('749e0980-0f0c-4f7a-a1a0-a9fb624b4963','次韻程伯禹用時字韻見寄二首  其二','葉夢得','宋','宋诗','song-poetry','','[]','漢道中興此一時，虞亡不臘爾何知。',64,'全唐诗/poet.song.81000.json','["漢道中興此一時，虞亡不臘爾何知。", "地中鳴角無多怪，堂上論兵固有奇。", "夢櫟那求梁棟遠，搶榆正羡羽翰卑。", "淮陽汲直猶高卧，願看簫韶集鳳儀。"]'),
('cb50ecec-35ba-4cde-b375-435bf274b287','送表弟晁公耄沿海師幕','葉夢得','宋','宋诗','song-poetry','','[]','巖邑相望數寄聲，十年湖海最關情。',64,'全唐诗/poet.song.81000.json','["巖邑相望數寄聲，十年湖海最關情。", "談鋒尚憶傾甥舅，鬢雪何堪數弟兄。", "飽讀父書聊自足，深知民事却須評。", "揚旗且逐樓船下，萬里波濤本不驚。"]'),
('dd57f7cf-5daa-4b80-99de-57158ff81eb8','題晁公耄惠崇溪山','葉夢得','宋','宋诗','song-poetry','','[]','荒林翳宿莽，脫木寒無煙。',48,'全唐诗/poet.song.81000.json','["荒林翳宿莽，脫木寒無煙。", "不知三間茅，中有幾醉眠。", "山遠尚見雪，江空欲吞天。", "歸舟定何許，滄波方渺然。"]'),
('4ba250b2-31af-44fb-8a4d-bfca1a5d9672','再賦','葉夢得','宋','宋诗','song-poetry','','[]','惠崇殘筆老尤奇，袖裏溪山每自随。',32,'全唐诗/poet.song.81000.json','["惠崇殘筆老尤奇，袖裏溪山每自随。", "欲識滄波無限意，此間惟許當家知。"]'),
('5068c63d-ed36-4e1a-a478-13c5bfde0f95','觀化堂編校舊書  其一','葉夢得','宋','宋诗','song-poetry','','[]','赫日真能永，微風亦自凉。',48,'全唐诗/poet.song.81000.json','["赫日真能永，微風亦自凉。", "故應便北户，何敢厭東牆。", "汲水聊爲戲，繙書却未忙。", "平生閒與懶，併覺味兼長。"]'),
('74e52868-5087-469a-9313-167a780cd35f','觀化堂編校舊書  其二','葉夢得','宋','宋诗','song-poetry','','[]','翰墨他生業，山林晚歲心。',48,'全唐诗/poet.song.81000.json','["翰墨他生業，山林晚歲心。", "那知身已老，但覺意增深。", "捉麈誰能話，扶笻可細尋。", "晚来庭鵲喜，似恐有歸音。"]'),
('7a0e79af-68f0-4195-8fec-3c437c2018ba','憶朱氏西澗  其一','葉夢得','宋','宋诗','song-poetry','','[]','澗下流泉澗上松，清陰盡處有層峰。',32,'全唐诗/poet.song.81000.json','["澗下流泉澗上松，清陰盡處有層峰。", "應知六月冰壺外，未許人間得暫逢。"]'),
('f00b30c5-d6da-4b59-a3c4-4142b2e2faf8','憶朱氏西澗  其二','葉夢得','宋','宋诗','song-poetry','','[]','憶向中流置竹牀，萬錢無處買清凉。',32,'全唐诗/poet.song.81000.json','["憶向中流置竹牀，萬錢無處買清凉。", "只今路斷無来客，自撥新篘醉幾場。"]'),
('1a459546-ca5f-44ef-af40-0bcc3297e42c','雨後爲山亭獨卧','葉夢得','宋','宋诗','song-poetry','','[]','過雨虚簷氣稍清，卧聞刁斗起連營。',64,'全唐诗/poet.song.81000.json','["過雨虚簷氣稍清，卧聞刁斗起連營。", "幾看薄月當軒過，驚見陰蟲繞砌鳴。", "洶洶南江浮静夜，寥寥北斗掛高城。", "白頭心事今如許，慚愧兒童話請纓。"]'),
('3831b33a-335a-456d-9cca-7e3957b96989','七夕','葉夢得','宋','宋诗','song-poetry','','[]','七夕仍殘暑，三年記此宵。',48,'全唐诗/poet.song.81000.json','["七夕仍殘暑，三年記此宵。", "傍簷依嶺月，欹枕聽江潮。", "瓠大何妨拙，槎迴未覺遥。", "何須論乞巧，河漢望星橋。"]'),
('d2c7c026-c1fd-4bb7-b37e-0c41b4223093','送王陞歸知果州','葉夢得','宋','宋诗','song-poetry','','[]','何處西南是果州，黄柑殊勝木奴洲。',64,'全唐诗/poet.song.81000.json','["何處西南是果州，黄柑殊勝木奴洲。", "使君自喜鄉閭近，騷客仍憐井邑幽。", "盗賊燕秦猶未息，山川楚越已先秋。", "原頭兵馬今多少，更與將軍論木牛。"]'),
('ce25851e-1d9b-4c38-b8c0-ead2f161314d','祈雨  其一','葉夢得','宋','宋诗','song-poetry','','[]','老農酣歌望捫腹，旱魃何爲敢予毒。',64,'全唐诗/poet.song.81000.json','["老農酣歌望捫腹，旱魃何爲敢予毒。", "九淵再拜欵神龍，仰空但見屯雲簇。", "天公愛民亦自惜，我愧無功神弗福。", "願看一洗注天瓢，未須震暴如車軸。"]'),
('a7ad799c-10de-46ff-987a-36c54fee968d','祈雨  其二','葉夢得','宋','宋诗','song-poetry','','[]','今年淮西蹙胡騎，王師盡掃無餘類。',64,'全唐诗/poet.song.81000.json','["今年淮西蹙胡騎，王師盡掃無餘類。", "武王伐紂報豐年，今者驕陽豈天意。", "東求三茅西采石，塔中至人肯徒視。", "明朝掣電駭翻盆，婦子猶能飽遺滯。"]'),
('012cc4ed-063d-443f-96c7-1ebc6c09a3a1','再任後遣模歸按視石林四首  其一','葉夢得','宋','宋诗','song-poetry','','[]','巖石三年别，君恩未許歸。',48,'全唐诗/poet.song.81000.json','["巖石三年别，君恩未許歸。", "從誰尋草徑，爲我欵荆扉。", "舊繞山千疊，新添竹一圍。", "故人如見問，端欲掛朝衣。"]'),
('aca4ae2e-3a63-4856-83c3-d879a7e475ec','再任後遣模歸按視石林四首  其二','葉夢得','宋','宋诗','song-poetry','','[]','白髮萱堂上，孩兒更共懷。',48,'全唐诗/poet.song.81000.json','["白髮萱堂上，孩兒更共懷。", "弄孫那得見，將母竟難諧。", "已絕功名望，猶疑出處乖。", "此心終未穩，何處復安排。"]'),
('535425fd-8da1-45f7-86d5-6c98f5ae8b42','再任後遣模歸按視石林四首  其三','葉夢得','宋','宋诗','song-poetry','','[]','插架環千軸，傳家有舊書。',48,'全唐诗/poet.song.81000.json','["插架環千軸，傳家有舊書。", "展舒慚几案，凉曝闕庭除。", "破屋防懸溜，殘編足蠹魚。", "好須重檢校，扃鎻莫令疏。"]'),
('ea0fd8e4-f305-4c66-b00d-e7da7ca38a6b','再任後遣模歸按視石林四首  其四','葉夢得','宋','宋诗','song-poetry','','[]','細路穿南嶺，新松幾許長。',48,'全唐诗/poet.song.81000.json','["細路穿南嶺，新松幾許長。", "毋庸馳馬足，祇擬轉羊膓。", "便作高亭好，初非亂石妨。", "兩溪渾在眼，似欲見帆檣。"]'),
('d26e0141-3a2d-4fe1-bc11-487f7ca82b05','祈雨未應復請於茅山采石庶幾遂得之  其一','葉夢得','宋','宋诗','song-poetry','','[]','苗當七八月之間，甘膏不濡何太慳。',64,'全唐诗/poet.song.81000.json','["苗當七八月之間，甘膏不濡何太慳。", "飛塵蓬勃晝欲暝，坐視雲物占羣山。", "五日一風十日雨，天方勤民輔明主。", "作書未敢頌風伯，寄謝羣龍少勞苦。"]'),
('375a96a8-fe66-4f4f-b66f-a5bc2ea6cee2','祈雨未應復請於茅山采石庶幾遂得之  其二','葉夢得','宋','宋诗','song-poetry','','[]','羣龍分馳不難興，噴薄雲霧隨飛騰。',64,'全唐诗/poet.song.81000.json','["羣龍分馳不難興，噴薄雲霧隨飛騰。", "中田勿憂龜兆坼，倐忽便看盈溝塍。", "老農何功報神力，但趣官租飽軍食。", "中原卷盡胡無人，爾土明年更開闢。"]'),
('fefdfa9e-312d-4aa6-8d87-d09094738b21','余每歲病肺往往坐達旦去冬以来偶不作遂得安眠','葉夢得','宋','宋诗','song-poetry','','[]','衰殘每苦病相纒，粗喜今年勝去年。',64,'全唐诗/poet.song.81000.json','["衰殘每苦病相纒，粗喜今年勝去年。", "未說清樽酬？醉，且欣高枕得安眠。", "風塵不報邊烽入，聖澤頻聞好語傳。", "可是淮陽真卧治，滿囊空費大農錢。"]'),
('22ece7e3-e8e6-41c2-b8b2-088c1be06e9d','聞莫尚書周侍郎已自鄂州過江入漢上','葉夢得','宋','宋诗','song-poetry','','[]','再見狂胡力請平，將軍無事罷屯營。',64,'全唐诗/poet.song.81000.json','["再見狂胡力請平，將軍無事罷屯營。", "傳軍已割淮壖地，牙帳仍收鄂渚兵。", "勝日身猶堪杖策，衰年耳自厭鳴鉦。", "角巾初了東歸約，安用區區峴首名。"]'),
('c18865ef-520a-499c-a5c8-9155312ff442','東園草堂新成二首  其一','葉夢得','宋','宋诗','song-poetry','','[]','官舍如何有草堂，野人熟處是難忘。',64,'全唐诗/poet.song.81000.json','["官舍如何有草堂，野人熟處是難忘。", "池開月映千山迥，檻静風生六月凉。", "幽徑也從穿别圃，小舟還似過横塘。", "深知幕府文書省，盡付甘眠亦未妨。"]'),
('8555ef1e-327d-411a-a7a8-14b7b30f2324','東園草堂新成二首  其二','葉夢得','宋','宋诗','song-poetry','','[]','密覆荒茅已數重，中開别户更相容。',64,'全唐诗/poet.song.81000.json','["密覆荒茅已數重，中開别户更相容。", "苦無公事妨人樂，多有清閑借客慵。", "南浦潮平分賸水，北山路近得青松。", "怪翁歸意何能緩，新築高臺見臥龍。"]'),
('b8bae96c-9f51-4f62-9014-a8c712d338c8','三月八日草堂獨坐','葉夢得','宋','宋诗','song-poetry','','[]','四年身不到吾廬，底處仍堪話左符。',64,'全唐诗/poet.song.81000.json','["四年身不到吾廬，底處仍堪話左符。", "閉閣漫憐公事少，投簪敢說宦情無。", "軍聲早已吞窮寨，使指何時返舊都。", "故作茅堂開水檻，要知心自在江湖。"]'),
('81458e77-d277-4274-92f6-f88fad00763c','徐惇立相過','葉夢得','宋','宋诗','song-poetry','','[]','茅齋一曲傍寒灣，邂逅終年伴我閒。',64,'全唐诗/poet.song.81000.json','["茅齋一曲傍寒灣，邂逅終年伴我閒。", "契闊易驚成歲月，追尋空復望江山。", "暫留客枕聽疏雨，遥想吾廬掩舊關。", "落莫歸心誰與話，坐談聊爲起衰顔。"]'),
('ef52d851-5c4f-48b6-a3fa-7580b1119bdc','同惇立游蒋山謁寶公塔王荆公墓晚過草堂寺周顒故宅也','葉夢得','宋','宋诗','song-poetry','','[]','我居在城府，再至俄二年。',168,'全唐诗/poet.song.81000.json','["我居在城府，再至俄二年。", "豈無山水心，可奈簿領纒。", "今晨偶乘興，適此賓從賢。", "零雨洗驕陽，谷中聽流泉。", "憑高快遠覽，正見江浮天。", "至人本無心，與我常周旋。", "誰云喚不譍，汝意自不虔。", "麥隴稍已滋，横水漲微漣。", "佳城倚華表，拱木埋貂蟬。", "暮過草堂寺，借榻聊暫眠。", "不復聞怨鶴，茅簷但連延。", "歸路踐落日，羣峰鬱相先。", "回風送遠響，墟里生晚煙。", "吾廬悵何許，東望良慨然。"]'),
('7d816f7d-ca8f-4f39-b4dc-f9e7f2c7267f','明日復游石頭城清凉寺再用前韻','葉夢得','宋','宋诗','song-poetry','','[]','大江洶西来，故國今幾年。',168,'全唐诗/poet.song.81000.json','["大江洶西来，故國今幾年。", "我衰倦登臨，坐愧雙行纒。", "忽驚山陰集，邂逅来羣賢。", "俛仰弔前古，高談注淵泉。", "千巖過宿雨，餘潤滋麥天。", "頽簷翳崖壁，過午不得旋。", "像佛再經始，此邦心亦虔。", "稍欣臺殿新，廢沼依淪漣。", "坐懷馬化龍，僅作蜋捕蟬。", "相傾走掣電，詎暇安枕眠。", "六飛暫東巡，恨爾不少延。", "單于久凋殘，屈已今我先。", "衰憊乘一障，無功記凌煙。", "乞身自兹始，此計君儻然。"]'),
('a7b1e14f-de98-4419-8e2c-650a682ef7d4','又明日復同惇立總領吴德素運使章思台過天禧寺登雨花臺再用前韻','葉夢得','宋','宋诗','song-poetry','','[]','言經朱雀桁，復度白雞年。',168,'全唐诗/poet.song.81000.json','["言經朱雀桁，復度白雞年。", "謝公不可見，廢壘蔓草纒。", "三日瞰坰牧，所懷多昔賢。", "陂陀北城墩，誰可作九泉。", "石頭控峥嶸，目盡西南天。", "定都記孔明，赤壁方凱旋。", "惟初鼎足計，用意良已虔。", "更作長干行，秦淮亂清漣。", "殘春掃餘花，密葉未有蟬。", "高臺略四遠，綠野浮芊眠。", "午陰久未移，幽景爲我延。", "使君固不凡，况有嘉客先。", "老大百念息，爨餘豈遺烟。", "了知塵外心，本自無間然。"]'),
('465b1fa7-9c45-40e0-b861-1a4e9d3a1a59','與惇立夜話有懷石林復用前韻','葉夢得','宋','宋诗','song-poetry','','[]','有山不能歸，坐愧三十年。',168,'全唐诗/poet.song.81000.json','["有山不能歸，坐愧三十年。", "冠服豈不榮，狙猿强包纒。", "惟餘緇衣心，未敢忘賢賢。", "他日得吾子，匣藏駭龍泉。", "衰頽爲興起，此腸寧非天。", "羯胡玩兵久，亦悟終好旋。", "叩關復請吏，企頸志頗虔。", "休兵固有期，撫事猶涕漣。", "投懷幸傾瀉，知子非寒蟬。", "十日對榻語，夜窗了無眠。", "賈生侍宣室，趣席方招延。", "願上治安策，何者今當先。", "我行返故廬，趺坐看爐烟。", "功名會及時，佇子論燕然。"]'),
('82bd7617-db95-4497-8420-8c023773367b','用前韻送惇立','葉夢得','宋','宋诗','song-poetry','','[]','畏作親友别，况復非中年。',168,'全唐诗/poet.song.81000.json','["畏作親友别，况復非中年。", "身如三眠蠶，已老翻自纒。", "朅来守江關，從事寧獨賢。", "經年兩大入，爟火通甘泉。", "石林豈壺中，亦自有一天。", "采薇敢言勤，誰與歌勞旋。", "上書苦哀祈，傾寫志已虔。", "坐懷北山巖，未見西溪漣。", "人言摶風鵬，不及翳葉蟬。", "共挽攜手客，可忘曲肱眠。", "首鼠信秃翁，胡爲尚遷延。", "子来幸暖熱，愧我一飯先。", "清詩似鳴玉，想見藍田煙。", "索去何乃遽，臨分重依然。"]'),
('bf5e4b82-ed60-4169-bec2-a9b9a3b8b6f6','爲山亭晚卧','葉夢得','宋','宋诗','song-poetry','','[]','痩石聊我伴，遥山更爾瞻。',48,'全唐诗/poet.song.81000.json','["痩石聊我伴，遥山更爾瞻。", "泉聲分寂歷，草色借廉纖。", "玉粒時能飽，霜毛日更添。", "平生疏懶意，况與病同兼。"]'),
('c9d3ac2f-c6cc-4936-9bbf-3c4ecaee01ee','次韻方仁聲惠文編','葉夢得','宋','宋诗','song-poetry','','[]','他年落筆坐生風，下舍諸郎敢長雄。',64,'全唐诗/poet.song.81000.json','["他年落筆坐生風，下舍諸郎敢長雄。", "操縵不能陪衆手，斵輪終自付良工。", "鏡湖漫憶歸狂客，漢上誰從過德公。", "會向南溪尋舊約，别開小徑共相通。"]'),
('069f013b-e555-40d1-9cb0-fb2f7cd47a81','戲方仁聲四絕句  其一','葉夢得','宋','宋诗','song-poetry','','[]','戲弄扁舟泊宅村，却尋三徑築茅墩。',32,'全唐诗/poet.song.81000.json','["戲弄扁舟泊宅村，却尋三徑築茅墩。", "雲邊此意真誰解，剩作新詩與細論。"]'),
('49910803-8f9e-4a05-9044-c6ca94103090','戲方仁聲四絕句  其二','葉夢得','宋','宋诗','song-poetry','','[]','水檻新開似浣花，傍溪須更作浮槎。',32,'全唐诗/poet.song.81000.json','["水檻新開似浣花，傍溪須更作浮槎。", "祗應屢費王弘酒，時要清樽對落霞。"]'),
('f6963382-ff04-490c-a88a-6c5d8ebc5c87','戲方仁聲四絕句  其三','葉夢得','宋','宋诗','song-poetry','','[]','不惜囊錢信手空，荒田却擬望年豐。',32,'全唐诗/poet.song.81000.json','["不惜囊錢信手空，荒田却擬望年豐。", "天公可是憐風月，判遣詩人一例窮。"]'),
('e363af6e-8bc4-48ed-baf5-8604b80f649e','戲方仁聲四絕句  其四','葉夢得','宋','宋诗','song-poetry','','[]','盧橘楊梅已及時，我歸先自在前期。',32,'全唐诗/poet.song.81000.json','["盧橘楊梅已及時，我歸先自在前期。", "平生不作宣明面，浪愧將軍建鼓旗。"]'),
('f1feee43-f3f4-4cc7-b590-555fe640bbab','次韻馬參謀蔣山開堂飯素','葉夢得','宋','宋诗','song-poetry','','[]','邂逅聊憑法供真，兹山誰謂我非鄰。',64,'全唐诗/poet.song.81000.json','["邂逅聊憑法供真，兹山誰謂我非鄰。", "相追更喜同枝策，得意遥知了斵輪。", "幽事要須塵外侣，好詩仍借鏡中人。", "歸来袖裏傳新句，驚放巖花作小春。"]'),
('b605d6d6-8408-4030-a6ff-8e0613bf3e58','諸幕府見和復答二首  其一','葉夢得','宋','宋诗','song-poetry','','[]','一勺清甘寄悟真，覺城東路更相鄰。',64,'全唐诗/poet.song.81000.json','["一勺清甘寄悟真，覺城東路更相鄰。", "臺傾劫火無遺燼，地轉奔風有伏輪。", "但遣籃輿從太守，深知幕府盡詩人。", "登臨莫忘千秋意，不必山陰記暮春。"]'),
('37abaec5-ab33-4642-8c4f-c15bb6c1ec4e','諸幕府見和復答二首  其二','葉夢得','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','欲眠遣客笑吾真，愛酒空牀羡汝鄰。',64,'全唐诗/poet.song.81000.json','["欲眠遣客笑吾真，愛酒空牀羡汝鄰。", "歸計？甘從短帽，倦塗何止畏奔輪。", "高車不用三千客，净社須期十八人。", "尚許一樽仍破戒，黄柑催釀洞庭春。"]'),
('7b9edbdd-a585-49a2-9e7a-3435ec950bbe','次韻馬參謀新作山亭','葉夢得','宋','宋诗','song-poetry','','[]','家山千仞聳亭亭，夢繞苕溪十里青。',128,'全唐诗/poet.song.81000.json','["家山千仞聳亭亭，夢繞苕溪十里青。", "苦厭簿書迷老景，坐懷丘壑寄頹齡。", "稚川可復尋勾漏，靈運能忘過始寧。", "疊石且從開小徑，苦寒仍喜報餘馨。", "天工未擬藏遺巧，物態何曾有遁形。", "散策便思穿窈窕，沉鉤真欲釣清泠。", "已看袖裏攜東海，端向籬中得畫屏。", "半世生涯皆福地，不妨歸更侍祠庭。"]'),
('711906fa-78e7-47b3-9b7c-21c3889d8a2b','方參議用前韻記嘗過余石林次韻答之','葉夢得','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','不復襄陽寫孟亭，草齋人道是丹青。',128,'全唐诗/poet.song.81000.json','["不復襄陽寫孟亭，草齋人道是丹青。", "那知客自從文舉，但怪山能養伯齡。", "世味無多真潦倒，歸心欲寄毎丁寧。", "遥聞徑竹添新影，更想巖花作遠馨。", "夜鶴未應真怨别，江鷗須信久忘形。", "地偏故逐淵明遠，風好常隨禦寇泠。", "癡坐正憐塵滿案，醉眠終倚石爲屏。", "瀛洲學士煩追賦，尚記滄波接洞庭。"]'),
('e282731f-0dd1-407c-8771-9fdcac4c1a80','徽宗皇帝挽歌詞五首  其一','葉夢得','宋','宋诗','song-poetry','','[]','制作三王舊，憂勤一紀餘。',48,'全唐诗/poet.song.81000.json','["制作三王舊，憂勤一紀餘。", "豈惟成禮樂，真欲混車書。", "黼扆猶丹陛，颷輪忽紫虚。", "帝鄉歸路穩，無復顧樓居。"]'),
('845cf605-419f-45c9-98b2-4b759a74a3de','徽宗皇帝挽歌詞五首  其二','葉夢得','宋','宋诗','song-poetry','','[]','帝業承瓜瓞，天倫映棣華。',48,'全唐诗/poet.song.81000.json','["帝業承瓜瓞，天倫映棣華。", "千年垂接統，四海自爲家。", "畢郢終何恨，蒼梧邈已賖。", "廟壖驚指顧，行路泣悲笳。"]'),
('3eb8c5e3-7b5a-4e1d-b8e6-62b0cbeaaf07','徽宗皇帝挽歌詞五首  其三','葉夢得','宋','宋诗','song-poetry','','[]','脱屣初無戀，遺弓故不忘。',48,'全唐诗/poet.song.81000.json','["脱屣初無戀，遺弓故不忘。", "金盤徒自聳，玉椀且深藏。", "付託歸真主，經營有舊章。", "柏城森渭水，空愧寢中郎。"]'),
('32d35774-7987-4dd5-aced-951bd1681620','徽宗皇帝挽歌詞五首  其四','葉夢得','宋','宋诗','song-poetry','','[]','卜宅軒臺近，因山禹穴深。',48,'全唐诗/poet.song.81000.json','["卜宅軒臺近，因山禹穴深。", "綴衣驚在匣，黄屋本非心。", "海闊青雲隔，天高白日沉。", "秋風無馬跡，惆悵属車音。"]'),
('cbbeb485-d324-4e34-b690-c815ea784f7c','徽宗皇帝挽歌詞五首  其五','葉夢得','宋','宋诗','song-poetry','','[]','浴殿陪書詔，甘泉忝侍臣。',48,'全唐诗/poet.song.81000.json','["浴殿陪書詔，甘泉忝侍臣。", "虚傳遊帝所，不復從時巡。", "效死終何日，餘生漫此身。", "攀髯如已矣，揮涕灑江濵。"]'),
('3ec6190a-4d7a-42a5-94fa-e41c5d776318','哭趙叔問','葉夢得','宋','宋诗','song-poetry','','[]','劉氏磐石宗，略分天下半。',239,'全唐诗/poet.song.81000.json','["劉氏磐石宗，略分天下半。", "斯文獨更生，落落分族冠。", "探書到千古，極意在理亂。", "故宜蕭長倩，憂國共長算。", "我懷崇蘭君，多學真一貫。", "束髮踵癯儒，長檠媚空案。", "胸中行秘書，領略能默斷。", "埋光久不暴，玉石終自判。", "中年立周行，杞梓見脩幹。", "雍容視出處，未可亟招喚。", "坐令護都水，不特美先漢。", "荷囊侍丹扆，正訝歸稍緩。", "爲棄天閑，一往謝覊絆。", "黄壚閉白玉，萬事風雨散。", "訃来爲失聲，涕落傷老伴。", "孰知錦囊心，無復銀鈎腕。", "柯山渺何許，日月忽已換。", "平生渾金質，反覆要熟看。", "至寶琢寒泓，誰？撫遺玩。", "尚有千字碑，臨風寄長歎。"]'),
('a16abe09-96ee-4d65-94d2-6c110bfdf196','東山圖贊 許玄度','葉夢得','宋','宋诗','song-poetry','','[]','揚眉軒然，意軼萬里。',40,'全唐诗/poet.song.81000.json','["揚眉軒然，意軼萬里。", "亦將焉往，而竟斯止。", "曰遠游者，以是爲游。", "疾走息陰，彼將安休。"]'),
('c46ae407-6301-4a79-9248-4beabaf01fb4','東山圖贊 王逸少','葉夢得','宋','宋诗','song-poetry','','[]','翰墨之娛，以寫萬變。',40,'全唐诗/poet.song.81000.json','["翰墨之娛，以寫萬變。", "不償一姥，笑蕺山扇。", "袖手縱觀，我行故遲。", "豈以懷祖，樂此逶迤。"]'),
('2dc74c58-0a53-4c75-b41c-ade15ff1ad52','東山圖贊 謝安石','葉夢得','宋','宋诗','song-poetry','','[]','韞玉于山，燁然不枯。',40,'全唐诗/poet.song.81000.json','["韞玉于山，燁然不枯。", "我觀此容，非山澤儒。", "卻顧何爲，東山之陟。", "如何淮淝，乃折此屐。"]'),
('19c193e1-31cd-478c-ae1c-ad331d665360','東山圖贊 支道林','葉夢得','宋','宋诗','song-poetry','','[]','一世所驅，顛倒軒裳。',40,'全唐诗/poet.song.81000.json','["一世所驅，顛倒軒裳。", "是身何依，獨委支郎。", "從容三人，亦躡其後。", "人誰無言，聯一舉手。"]'),
('7f44f4d6-6d80-4cf3-a079-23677d126771','法眼禪師真贊','葉夢得','宋','宋诗','song-poetry','','[]','八萬四千，大悲寶目。',100,'全唐诗/poet.song.81000.json','["八萬四千，大悲寶目。", "問此多目，孰爲正觀。", "惟阿那律，無目而視。", "問此真目，畢竟安在。", "是法眼者，猶爲金屑。", "有法無眼，有眼無法。", "稽首導師，五藴皆寂。", "悲觀慈觀，等大圓鏡。", "頹然方牀，如夢中事。", "山河大地，一切消隕。"]'),
('a780f902-1403-4bfa-9395-75fefb515e51','詩二首  其一','葉夢得','宋','宋诗','song-poetry','','[]','霜風獵獵將寒威，林下山僧見亦稀。',32,'全唐诗/poet.song.81000.json','["霜風獵獵將寒威，林下山僧見亦稀。", "怪得吟詩無俗語，十年肝鬲湛寒輝。"]'),
('b3c31161-6858-438e-a9fc-bdd35c7ff6f6','詩二首  其二','葉夢得','宋','宋诗','song-poetry','','[]','城頭晚漏鳴丁丁，窗間月落卻未明。',64,'全唐诗/poet.song.81000.json','["城頭晚漏鳴丁丁，窗間月落卻未明。", "衡陽歸雁過欲盡，汝陽荒雞初一鳴。", "悠悠斷夢子不記，草草微吟還獨生。", "成人得意須幾許，一睡稍足無與情。"]'),
('17223a55-8748-4adf-9bb5-080ad6cc8b7c','慈感蚌珠','葉夢得','宋','宋诗','song-poetry','','[]','九淵幽怪舞垂涎，游戲那知我獨尊。',64,'全唐诗/poet.song.81000.json','["九淵幽怪舞垂涎，游戲那知我獨尊。", "應迹不辭從異類，藏身何意戀窮源。", "歸來自說龍宮化，久住方驚鷲嶺存。", "此話須逢老摩詰，圓通無礙本無門。"]'),
('a3a84f32-ccce-47fa-9aaa-d12455eeb330','題懷隱庵','葉夢得','宋','宋诗','song-poetry','','[]','春風的的爲誰來，遶舍閑花亦謾栽。',32,'全唐诗/poet.song.81000.json','["春風的的爲誰來，遶舍閑花亦謾栽。", "菴內不知菴外事，夜來微雨小桃開。"]'),
('539105e3-00d4-4b83-8655-d283c60bf2fe','酴醾','葉夢得','宋','宋诗','song-poetry','','[]','東風吹麝入鉛華，未肯隨春到謝家。',32,'全唐诗/poet.song.81000.json','["東風吹麝入鉛華，未肯隨春到謝家。", "夜半粉香垂露泣，定應和月怨梨花。"]'),
('f370adc7-3791-42bd-bb90-5cbfc41465c3','遊南峰寺','葉夢得','宋','宋诗','song-poetry','','[]','澤國鍾下流，有山獨西南。',240,'全唐诗/poet.song.81000.json','["澤國鍾下流，有山獨西南。", "標奇借明眼，夙昔多窮探。", "腹背眩金碧，鍾魚半精藍。", "支郎放鶴地，妙解無餘談。", "高木氣未炎，綠陰正青酣。", "我懶倦登陟，茲行咤猶堪。", "幽尋雖云初，佳處默已諳。", "久欲謝塵滓，往同彌勒龕。", "平生行九九，晚識前三三。", "才也實可人，窮年玩煙嵐。", "胸中有定水，萬境潛包含。", "嚴霜掃赬紫，老榦餘楩柟。", "噉蔗要自佳，食茶亦云甘。", "坐斷方丈室，天花雨毶毶。", "笑我窘世網，何殊老眠蠶。", "我今已解縛，真理密自耽。", "但恐愛山意，多求尚成貪。", "願借待月嶺，重開石頭庵。", "偃松久傲兀，碧琳故澄涵。", "言尋覺城路，更欲從遍參。"]'),
('3f637fb5-f3af-4fa1-9d58-1b810502764f','褒忠廟歌','葉夢得','宋','宋诗','song-poetry','','[]','天生裔夷，以限四極。',240,'全唐诗/poet.song.81000.json','["天生裔夷，以限四極。", "有不能然，乃嘯上國。", "既殄我民，爾則逆天。", "惡稔而誅，天胡舍㫋。", "在昔肅氏，厥貢砮矢。", "不我來庭，敢干我紀。", "揭揭楊侯，梗其喉牙。", "萬夫一軀，莫我敢加。", "誰謂爾狂，我馮我抑。", "誰謂備殘，我唑我斥。", "天子曰嘻，惟我有臣。", "曷不贖之，人百其身。", "屹屹崇岡，侯安于域。", "桷梴旅楹，侯有廟食。", "惟皇上帝，命侯來歸。", "顧瞻山川，申我王威。", "侯食百世，旗纛旖旖。", "百靈齊趨，從侯北指。", "侯車轟轟，于彼故疆。", "覆其穴巢，何有虎狼。", "告功帝閽，帝笑爲喜。", "四方既平，侯祀百世。", "曷慕匪忠，歇畏匪死。", "簡于帝衷，惟忠弗畏。"]'),
('bf04a310-f161-4325-b7a0-fef5f976f745','送嚴婿侍郎北使','葉夢得','宋','宋诗','song-poetry','','[]','朔風吹雪暗龍荒，荷櫜驚看玉節郎。',64,'全唐诗/poet.song.81000.json','["朔風吹雪暗龍荒，荷櫜驚看玉節郎。", "楛矢石砮傳地產，醫閭析木照天光。", "傳車玉帛風塵息，盟府山河歲月長。", "寄語遺民知帝力，勉拋鋒鏑事耕桑。"]'),
('a0f9ca6a-0d3d-4502-8486-4faaab68518c','皂鏡冊','葉夢得','宋','宋诗','song-poetry','','[]','依然一冊巧裝成，故紙爲胎越樣輕。',32,'全唐诗/poet.song.81000.json','["依然一冊巧裝成，故紙爲胎越樣輕。", "四畔黑雲都罩盡，中間只有月長明。"]'),
('4d0289e4-8538-42fe-8565-efa4f8c55115','虎丘','葉夢得','宋','宋诗','song-poetry','','[]','虎丘之名歲二千，虎丘之丘何渺然。',128,'全唐诗/poet.song.81000.json','["虎丘之名歲二千，虎丘之丘何渺然。", "衆山爭高隱日月，笑此拳石埋平田。", "雖然培塿疑異物，劃開陰崖十丈懸。", "冢中有恨索遺指，亭上無語傳枯禪。", "偏是吳人愛山急，逐面分方誇憑立。", "屋承隋唐良穩稱，墨題熙豐尚新濕。", "松梢莫遣風雨橫，石盤自添苔蘚澀。", "春來春去吳人游，足繭層巓踣應泣。"]'),
('53ce3312-f8d2-4027-8052-345c51aa2de2','長橋','葉夢得','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','長橋跨空水彌漫，北望吞天去無岸。',65,'全唐诗/poet.song.81000.json','["長橋跨空水彌漫，北望吞天去無岸。", "洞庭自湧東西山，驚濤忽起起行人斷。", "禹功千年在坤輿，東南大浸惟五湖。", "如何寇來不少限，鐵馬萬騎翻長驅。"]'),
('b95dc008-292e-4522-88ba-70def2acb612','句','葉夢得','宋','宋诗','song-poetry','','[]','逸人舊住子午谷，詩客獨尋丁卯橋。',16,'全唐诗/poet.song.81000.json','["逸人舊住子午谷，詩客獨尋丁卯橋。"]'),
('9449961c-365d-4ac7-98c3-457daae85517','桐君祠作招仙歌','盧襄','宋','宋诗','song-poetry','','[]','桐君歸來兮，仙馭遠遊將何之，寧不欲朝玉京兮升紫微。',117,'全唐诗/poet.song.81000.json','["桐君歸來兮，仙馭遠遊將何之，寧不欲朝玉京兮升紫微。", "戴日月之冠兮披紫霞之衣，佩蒼精之龍兮餐玉田之芝。", "友王喬與蕭史兮，儼蜺旌玉佩而葳蕤，何如歸來。", "猿鶴慘兮怨空山，川壑寂兮松桂閑，胡不拂袖煙幌兮開雲關。", "藉芳草兮歌幽蘭，庶乎遊山之人可以往還。"]'),
('b333d36a-8661-4dcb-97d7-dd3f12aa4570','嚴子陵釣臺','盧襄','宋','宋诗','song-poetry','','[]','無欲戴蟬冠，蟬冠械我首。',108,'全唐诗/poet.song.81000.json','["無欲戴蟬冠，蟬冠械我首。", "無欲披衮衣，衮衣囚我身。", "貧賤自閑暇，功名多苦辛。", "君不見大將軍功蓋天地，一朝餓死垣牆裏。", "又不見穰侯貴壓咸陽都，朝爲卿相暮匹夫。", "爭如春風秋月一竿竹，萬古溪山看不足。", "勝他宮殿鎖千門，細草新蒲爲誰綠。"]'),
('3eff671a-be0a-47f4-b484-9210b7fae8f0','姑蘇臺歌','盧襄','宋','宋诗','song-poetry','','[]','姑蘇臺上麋鹿遊，斷煙荒草令人愁。',96,'全唐诗/poet.song.81000.json','["姑蘇臺上麋鹿遊，斷煙荒草令人愁。", "姑蘇臺邊少行迹，宮殿無人土花碧。", "當年霸業幾英雄，至首都歸血刃中。", "利劍一朝尸壯士，白楊千古蟗悲風。", "吳王羞歸九泉裏，西施空似桃花美。", "子胥雖死過生榮，越人卻是奇男子。"]'),
('5f95846e-d07d-4246-a765-186c49291ae7','登三賢堂  其一','盧襄','宋','宋诗','song-poetry','','[]','舟繫小橋楊柳月，帆移平浦芰荷風。',32,'全唐诗/poet.song.81000.json','["舟繫小橋楊柳月，帆移平浦芰荷風。", "當時不向煙波老，霸業功名一掃空。"]'),
('a8e1f175-7422-4454-a6f8-391ad9cfc46d','登三賢堂  其二','盧襄','宋','宋诗','song-poetry','','[]','鱸膾色鮮盤玉縷，蒓羹香滑煮龍髯。',32,'全唐诗/poet.song.81000.json','["鱸膾色鮮盤玉縷，蒓羹香滑煮龍髯。", "可憐水月交光夜，一笛西風自捲簾。"]'),
('988f393d-2591-4104-8931-f644be890401','登三賢堂  其三','盧襄','宋','宋诗','song-poetry','','[]','醉夢幾經芳草渡，吟魂飛上月明樓。',32,'全唐诗/poet.song.81000.json','["醉夢幾經芳草渡，吟魂飛上月明樓。", "散人已出形骸外，肯作鄉聲效楚囚。"]'),
('a3f439a5-3d8f-4338-a555-de5b094148fb','姑蘇臺通遺址','盧襄','宋','宋诗','song-poetry','','[]','秋風起兮鴻雁歸，秋月明兮白雲飛，弔往古兮一霑衣。',24,'全唐诗/poet.song.81000.json','["秋風起兮鴻雁歸，秋月明兮白雲飛，弔往古兮一霑衣。"]'),
('65236e27-3062-4ebb-a1f0-b3b826253992','韓信廟','盧襄','宋','宋诗','song-poetry','','[]','登壇當日拜元戎，楚漢都歸指掌中。',64,'全唐诗/poet.song.81000.json','["登壇當日拜元戎，楚漢都歸指掌中。", "王氣未消垓下敵，將星已落陣前功。", "高名紫宇千鈞重，冤血青蛇一縷紅。", "尚有鸞刀薦牲酒，斜陽煙樹泣秋風。"]'),
('86b1dede-e483-4313-99cf-80b0d9830d02','黄金堤','盧襄','宋','宋诗','song-poetry','','[]','崑崙一線蒼崖，霹靂飛聲趁地來。',63,'全唐诗/poet.song.81000.json','["崑崙一線蒼崖，霹靂飛聲趁地來。", "煬帝截教淮水斷，巨靈羞劈華山開。", "桃花漲滿通西洛，竹箭奔流逐吹臺。", "午夜月明楊柳岸，空餘風咽笛聲哀。"]'),
('cbc88250-bdbf-4ab8-8c1c-a2c14bce981a','雍丘歌','盧襄','宋','宋诗','song-poetry','','[]','胡兒倚劍摩崆峒，范陽兵火燒天紅。',160,'全唐诗/poet.song.81000.json','["胡兒倚劍摩崆峒，范陽兵火燒天紅。", "潼關失守大將死，鑾輿播遷岷峨中。", "貔貅兵甲照冰雪，戈頭盡是生民血。", "鯨海揚波魚鼈腥，中原盡作天山月。", "二公擐甲怒攙槍，極鬬軍前皆眥裂。", "食窮愛妾膏斤斧，愁蹙蛾眉氣如縷。", "花鈿寶髻誰復收，壯士相看泣如雨。", "霜刀抉齒肉未寒，再造皇家有英主。", "雄心義骨填溝壑，不得生榮肩李郭。", "論功初入鸛鵲樓，圖形已入麒麟閣。"]'),
('5edd4cb1-fb66-41c4-9cfa-7b1f111cdedc','招隱二首  其一','盧襄','宋','宋诗','song-poetry','','[]','有玉人兮山之隅，騎蒼龍兮歌步虛。',59,'全唐诗/poet.song.81000.json','["有玉人兮山之隅，騎蒼龍兮歌步虛。", "薜荔衣兮女蘿裾，餐瓊蕊兮被玉書。", "朝玉皇兮遊上都，擘麟脯兮邀麻姑。", "胡不捨此而來兮吾與俱。"]'),
('5aafd4e1-8a0b-4355-aa7c-d5ee3d6200b2','招隱二首  其二','盧襄','宋','宋诗','song-poetry','','[]','日旋月轉兮能幾時，人間不可以久留兮，緇塵染予素衣。',90,'全唐诗/poet.song.81000.json','["日旋月轉兮能幾時，人間不可以久留兮，緇塵染予素衣。", "何不讀青苔之篇兮，歌白雲之詩。", "玉書金簡號仙籍兮，留芳名其庶幾。", "然後左蒼龍而右青螭，飛羽蓋兮張雲旂。", "黄鵠引兮歸瑤池，汝將捨此兮安之。"]'),
('0d44c035-3a3b-4dd4-b4c8-16f0be19eb8b','予同彥老自四明之永嘉中道留宿岳林會法照海印二禪伯夜話投曉登車乃行留題於寺三首  其一','盧襄','宋','宋诗','song-poetry','','[]','病骨倦鞍馬，禪居忻少留。',48,'全唐诗/poet.song.81000.json','["病骨倦鞍馬，禪居忻少留。", "暮雲山盡路，孤磬月明樓。", "林靜鉤輈曉，風香罷亞秋。", "重來坐磐石，相對話歸休。"]'),
('38c7ff5d-9aae-4c5f-bece-1665f010e148','予同彥老自四明之永嘉中道留宿岳林會法照海印二禪伯夜話投曉登車乃行留題於寺三首  其二','盧襄','宋','宋诗','song-poetry','','[]','嘆息老禪伯，蕭閑心自如。',48,'全唐诗/poet.song.81000.json','["嘆息老禪伯，蕭閑心自如。", "買松栽別塢，引水過新渠。", "草色經行外，禽聲宴坐餘。", "自慚雙客鬢，垂老尚征車。"]'),
('6850b312-9d54-4a77-ac23-e2efe7e31dfc','予同彥老自四明之永嘉中道留宿岳林會法照海印二禪伯夜話投曉登車乃行留題於寺三首  其三','盧襄','宋','宋诗','song-poetry','','[]','報國竟無補，敢辭山路遙。',48,'全唐诗/poet.song.81000.json','["報國竟無補，敢辭山路遙。", "晚寒生竹徑，新漲斷溪橋。", "奔走真逋客，安閑愧老樵。", "令人欲心折，風雨夜瀟瀟。"]'),
('ce0f24cd-6de3-4c23-824f-a76e5202606d','途中書懷寄奉化知縣二首  其一','盧襄','宋','宋诗','song-poetry','','[]','自戴淵明漉酒巾，食鮭甘作庾郎貧。',64,'全唐诗/poet.song.81000.json','["自戴淵明漉酒巾，食鮭甘作庾郎貧。", "雖無殘菊簪華髪，賴有青山似故人。", "幾處鴉鳴牛背雨，經年衣犯馬蹄塵。", "待攜神武朝衫去，還我煙溪漱石身。"]'),
('23e95833-fa07-4e7d-8972-acc0d68957ef','途中書懷寄奉化知縣二首  其二','盧襄','宋','宋诗','song-poetry','','[]','奔馳漸覺崢嶸，負郭蕪田未退耕。',63,'全唐诗/poet.song.81000.json','["奔馳漸覺崢嶸，負郭蕪田未退耕。", "正恐山溪吹岸去，任從煙草喚愁生。", "別來竹院門長掩，好去漁舟手自撐。", "漸晚歸心在何許，夕陽低處伴雲橫。"]'),
('43028c71-3dec-4ca2-bedd-dcba6a87059f','太上皇帝御製題扇面所畫紅木犀賜從臣榮薿','盧襄','宋','宋诗','song-poetry','','[]','月宮移向日宮栽，染得嬌紅入面來。',32,'全唐诗/poet.song.81000.json','["月宮移向日宮栽，染得嬌紅入面來。", "多謝秋風揚雨露，丹心一一爲君開。"]'),
('dd930226-3f09-46fb-afb3-43122799b5ae','秋','盧襄','宋','宋诗','song-poetry','','[]','岸紅初破木芙蓉，送別遙聞野寺鐘。',32,'全唐诗/poet.song.81000.json','["岸紅初破木芙蓉，送別遙聞野寺鐘。", "江抱月流青炯炯，山隨天去碧重重。"]'),
('036a39ff-46a7-43f4-8429-f7292e9abfeb','窗外梅花','盧襄','宋','宋诗','song-poetry','','[]','已消殘雪豆稭灰，斜壓疏籬一半開。',64,'全唐诗/poet.song.81000.json','["已消殘雪豆稭灰，斜壓疏籬一半開。", "雖我故園無分看，問渠春色幾時來。", "冷香漸欲薰時夢，落蕊朊能砌韻臺。", "定復水邊多屐齒，試令長鬣視蒼苔。"]'),
('7c53e6bd-cb29-4121-b4cc-e1dd0584987e','貧賤二首  其一','盧襄','宋','宋诗','song-poetry','','[]','身在秋湖天一角，嶺猿洲雁亦相哀。',32,'全唐诗/poet.song.81000.json','["身在秋湖天一角，嶺猿洲雁亦相哀。", "他時相見柯山下，土銼芳薪煮芋魁。"]'),
('43b8460e-22a9-419e-b884-89b39964af2c','貧賤二首  其二','盧襄','宋','宋诗','song-poetry','','[]','多病吳中一腐儒，新來鉛水照髭鬍。',32,'全唐诗/poet.song.81000.json','["多病吳中一腐儒，新來鉛水照髭鬍。", "掃地靜憐黄吻婢，縛雞賣遣白頭奴。"]'),
('e34644b9-d06b-4367-9595-1af8444d367f','村落','盧襄','宋','宋诗','song-poetry','','[]','釣船歸落昏鴉後，江雨來從白鳥邊。',32,'全唐诗/poet.song.81000.json','["釣船歸落昏鴉後，江雨來從白鳥邊。", "舊屋但餘燒葉竈，破囊猶欠買山錢。"]'),
('1728aea7-0f42-4d89-8009-f08914fc02ad','石橋道中三首  其一','盧襄','宋','宋诗','song-poetry','','[]','牛羊日晚下煙坡，病眼看花手自摩。',64,'全唐诗/poet.song.81000.json','["牛羊日晚下煙坡，病眼看花手自摩。", "千里家鄉曾夢到，一年風景最春多。", "樽前有酒須相覓，眼底無愁可奈何。", "王事雖勞吾敢憚，猶勝乘雪下蓬婆。"]'),
('4f54e9c6-0bfa-4ddd-8458-79e865e0de8f','石橋道中三首  其二','盧襄','宋','宋诗','song-poetry','','[]','枕底雞聲月影殘，搖鞭驅馬上巑岏。',64,'全唐诗/poet.song.81000.json','["枕底雞聲月影殘，搖鞭驅馬上巑岏。", "路高蜀道九折坂，水急香山八節灘。", "茶異雪花生筯底，眼明金雀舞林端。", "凌晨只怪貂裘薄，山近天門分外寒。"]'),
('d6180d8e-ca73-47ed-a733-aaabe0b2cd09','石橋道中三首  其三','盧襄','宋','宋诗','song-poetry','','[]','足根重繭寸心灰，故里田園好在哉。',65,'全唐诗/poet.song.81000.json','["足根重繭寸心灰，故里田園好在哉。", "晚浦橫舟芳草遠，廢牆經雨小桃開。", "須知鞭馬駸駸去，不是尋春得得得來。", "多謝殘年足公事，因將香火訪天台。"]'),
('f00fb13c-26d6-457a-8f32-dc2dd85d90dd','剡溪書懷三絕  其一','盧襄','宋','宋诗','song-poetry','','[]','山鳥逢春恰恰啼，桃花流水路猶迷。',32,'全唐诗/poet.song.81000.json','["山鳥逢春恰恰啼，桃花流水路猶迷。", "何時鼠子膏齊斧，笑領白雲歸剡溪。"]'),
('c79ef5f8-766c-4d8b-8533-478d030dfb6d','剡溪書懷三絕  其二','盧襄','宋','宋诗','song-poetry','','[]','故園生事只衡茅，不管方兄久絕交。',32,'全唐诗/poet.song.81000.json','["故園生事只衡茅，不管方兄久絕交。", "糲食枯椽吾易足，鷦鷯只占一枝巢。"]'),
('c2a6ef10-a923-46f7-b412-d19381acd7ab','剡溪書懷三絕  其三','盧襄','宋','宋诗','song-poetry','','[]','山杏枝頭鵯鵊兒，來傳春意語多時。',32,'全唐诗/poet.song.81000.json','["山杏枝頭鵯鵊兒，來傳春意語多時。", "脆紅可是渾無力，不奈東風盡日吹。"]'),
('9de26251-c2a6-4565-b58d-5293475f12d5','泛剡溪','盧襄','宋','宋诗','song-poetry','','[]','愁呵龜手冷搖鞭，乘興來登訪戴船。',32,'全唐诗/poet.song.81000.json','["愁呵龜手冷搖鞭，乘興來登訪戴船。", "解事篙師小鳴櫓，恐驚寒雁入晴天。"]'),
('9577a3cc-9296-4ba9-93d8-bd5f0c93a70b','題圓超寺挾溪亭','盧襄','宋','宋诗','song-poetry','','[]','孤亭瞰平野，雙溪分兩腋。',120,'全唐诗/poet.song.81000.json','["孤亭瞰平野，雙溪分兩腋。", "野闊春風香，溪晴照人碧。", "我來亭上天欲春，溪聲野色爭赴人。", "胸中丘壑相映發，翛然便欲乘飆輪。", "惜無妙手王摩詰，半破鵝溪重畫出。", "溪山應喜得賞音，盡遣煙霞供落筆。", "我嗟吟鬢犯車塵，一憑危欄眼界新。", "寄謝溪聲與山色，他時來作箇中人。"]'),
('8688010a-4962-45fb-be04-b824505d4c0c','題石鼓','盧襄','宋','宋诗','song-poetry','','[]','山在江城欲盡頭，招提無處著清幽。',64,'全唐诗/poet.song.81000.json','["山在江城欲盡頭，招提無處著清幽。", "寒枕水底長留月，冷入天圍不剩秋。", "村靜尚遺看鶴戶，溪寒只受釣漁舟。", "眼前佳思能如許，悔不長爲隱地遊。"]'),
('e8cd1d69-02a5-44fc-b6b3-8d26e613cd56','過定林寺','盧襄','宋','宋诗','song-poetry','','[]','寒旌隱隱入花村，小雨初晴水带昏。',64,'全唐诗/poet.song.81000.json','["寒旌隱隱入花村，小雨初晴水带昏。", "不憚山程尋寺去，只將詩思與僧論。", "菱侵水步深藏艇，柳暗人家半掩門。", "莫厭禪居蕭冷甚，此來一爲訪溪藤。"]'),
('a0e857cc-1099-40a6-a98b-28564f21047e','登鹿苑隱天閣  其一','盧襄','宋','宋诗','song-poetry','','[]','欲結愛山人，共了尋山債。',24,'全唐诗/poet.song.81000.json','["欲結愛山人，共了尋山債。", "未有買山錢，愁聞有山賣。"]'),
('78a0d9e7-8c1e-4f7d-ad4c-d90ba0c7db43','登鹿苑隱天閣  其二','盧襄','宋','宋诗','song-poetry','','[]','小雨濕春風，倦雲遮落日。',24,'全唐诗/poet.song.81000.json','["小雨濕春風，倦雲遮落日。", "不若叫風來，吹雲放山出。"]'),
('845dd50c-5def-470b-b57c-8fcc78aa61e3','登鹿苑隱天閣  其三','盧襄','宋','宋诗','song-poetry','','[]','一眼吞萬山，寸心貯千里。',24,'全唐诗/poet.song.81000.json','["一眼吞萬山，寸心貯千里。", "何日上歸舟，教人問春水。"]'),
('90ed2f1e-9687-4d57-99f2-f3e17526a89b','登鹿苑隱天閣  其四','盧襄','宋','宋诗','song-poetry','','[]','殘雪領春來，疏鐘驚夢去。',24,'全唐诗/poet.song.81000.json','["殘雪領春來，疏鐘驚夢去。", "尚憶去年愁，孤舟繫江樹。"]'),
('8c31ee29-862f-4df2-b6ca-11d8e63edcfd','再登隱天閣','盧襄','宋','宋诗','song-poetry','','[]','好在滄州趣，青蘋入眼多。',48,'全唐诗/poet.song.81000.json','["好在滄州趣，青蘋入眼多。", "落紅隨水盡，啼鳥奈春何。", "生事詩千首，功名印幾窼。", "如何喚禪伯，軟語坐盤陀。"]'),
('26130334-8c2f-433b-b8e1-d41ac15aaec5','登鹿苑寺玉虹亭','盧襄','宋','宋诗','song-poetry','','[]','饑鼯愁玃號窮冬，層巒秀壁撐晴空。',144,'全唐诗/poet.song.81000.json','["饑鼯愁玃號窮冬，層巒秀壁撐晴空。", "閑拖小藤借餘力，來看霜巖飛怒虹。", "小奚催呼老欵段，瀹鼎篝火烹團龍。", "餘甘入口齒頰爽，兩腋便欲生清風。", "悠然千里墮眼界，金篦刮膜開雙瞳。", "乃知足力不到處，別有天地生壺中。", "國恩欲報已華髪，征車未去先晨鐘。", "玉川乘雲紫皇家，謫仙騎鯨河伯宮。", "聊追二子歸禹穴，碧空轉首山重重。"]'),
('3448b5cc-5135-4a32-bc96-8ac69e09a4e7','遊鹿苑寺山','盧襄','宋','宋诗','song-poetry','','[]','喜策尋春杖，登高不待扶。',48,'全唐诗/poet.song.81000.json','["喜策尋春杖，登高不待扶。", "蟻寒穿柳影，蜂暖飽花鬚。", "把酒憐櫻筍，臨流憶鱖魚。", "他時公事了，方有醉工夫。"]'),
('df031cc7-d12e-4841-8699-ea1ea6ab34e2','接山堂','盧襄','宋','宋诗','song-poetry','','[]','故臘老欲盡，新春慳未來。',120,'全唐诗/poet.song.81000.json','["故臘老欲盡，新春慳未來。", "無令隴梅覺，且遣山禽催。", "雲間古招提，鐵鳳翔斗魁。", "單車夜剝啄，境凈無纖埃。", "修篁舞瘦蛟，怒瀑生晴雷。", "坐久欲頰風，吹我心霧開。", "迺知白蓮社，未下黄金臺。", "緬思王騎曹，逸韻挽不回。", "且同謝康樂，屐齒破蒼苔。", "重遊定不惡，林壑富詩材。"]'),
('c7dbe767-6131-476f-afbb-d0e5cfa0abfa','再登接山堂  其一','盧襄','宋','宋诗','song-poetry','','[]','鷲峰游屐少，我獨住多時。',48,'全唐诗/poet.song.81000.json','["鷲峰游屐少，我獨住多時。", "僧護翻經石，猿攀嘯月枝。", "地寒春到晚，山遠夢歸遲。", "尚被浮雲誤，吾心信自癡。"]'),
('cfe5d6db-0868-49c0-9eaf-e898c5f3f05e','再登接山堂  其二','盧襄','宋','宋诗','song-poetry','','[]','着地嵐陰撥不開，傍閑同到妙高臺。',32,'全唐诗/poet.song.81000.json','["着地嵐陰撥不開，傍閑同到妙高臺。", "老僧只恐泉聲少，坐遣飛雲喚雨來。"]'),
('58554528-5703-4521-94d5-86fd33890282','再登接山堂  其三','盧襄','宋','宋诗','song-poetry','','[]','修蛇細路困車牛，公事催人不自由。',32,'全唐诗/poet.song.81000.json','["修蛇細路困車牛，公事催人不自由。", "欲到遙岑冷侵骨，寄聲歸雁莫來休。"]'),
('69cdd8a5-b9b3-4400-b8f1-c8f4dae9ff37','剡山瑞香花','盧襄','宋','宋诗','song-poetry','','[]','入夢生香酒力微，不須金鴨裊孤馡。',32,'全唐诗/poet.song.81000.json','["入夢生香酒力微，不須金鴨裊孤馡。", "爲嫌淡白非真色，故著仙家紫道衣。"]'),
('a3e7ab5c-f0b6-4a18-bfa3-5d7b8632d2fe','初薰堂紅梅  其一','盧襄','宋','宋诗','song-poetry','','[]','河陽滿縣栽桃李，風過落花吹不起。',32,'全唐诗/poet.song.81000.json','["河陽滿縣栽桃李，風過落花吹不起。", "潘郎遠韻故不凡，爲米折腰聊爾爾。"]'),
('4cadaf5e-b28c-4a4b-abbf-5c04edcbd886','初薰堂紅梅  其二','盧襄','宋','宋诗','song-poetry','','[]','剡溪詩尹亦可人，作堂餉客名迎薰。',32,'全唐诗/poet.song.81000.json','["剡溪詩尹亦可人，作堂餉客名迎薰。", "雖無桃李繼潘令，紅梅一窼香入雲。"]'),
('ac3f4c1c-daaf-447c-97d0-2739324ab336','初薰堂紅梅  其三','盧襄','宋','宋诗','song-poetry','','[]','自憐多病繡衣客，百年未半鬢先白。',80,'全唐诗/poet.song.81000.json','["自憐多病繡衣客，百年未半鬢先白。", "長鞭短帽飽霜露，田園將蕪身未索。", "何日背琴攜瘦筇，鳴弦堂上迎薰風。", "梅香已斷葉初暗，滿枝著子雙頰紅。", "寄聲釢子可留意，爲我沿溪撐短篷。"]'),
('fcc5848c-9500-43d0-b930-7ec367f9f06e','定林寺沿溪采石蒲','盧襄','宋','宋诗','song-poetry','','[]','曉行隱隱入花村，小雨初晴水氣昏。',32,'全唐诗/poet.song.81000.json','["曉行隱隱入花村，小雨初晴水氣昏。", "莫厭僧家能冷淡，且穿芸屩采溪蓀。"]'),
('2e9e843b-0e3f-4580-9e2a-53877c2d6736','玉虹亭試茶  其一','盧襄','宋','宋诗','song-poetry','','[]','乍見飛泉眼即明，玉虹垂地半天聲。',32,'全唐诗/poet.song.81000.json','["乍見飛泉眼即明，玉虹垂地半天聲。", "何時閑散無公事，洗鉢重來汲淺清。"]'),
('76f2b18d-1557-45da-8d20-0a5a383a8aa0','玉虹亭試茶  其二','盧襄','宋','宋诗','song-poetry','','[]','航湖未逐鴟夷子，得水今同桑苧翁。',32,'全唐诗/poet.song.81000.json','["航湖未逐鴟夷子，得水今同桑苧翁。", "試遣茶甌作花乳，從教兩腋起清風。"]'),
('c759e4d5-23ac-42ea-bddb-0bff4ccdce4d','春興','盧襄','宋','宋诗','song-poetry','','[]','雪花初著鴛鴦瓦，疊嶂疏林入圖畫。',112,'全唐诗/poet.song.81000.json','["雪花初著鴛鴦瓦，疊嶂疏林入圖畫。", "春工不作兩樣心，盡遣根荄赴陶冶。", "我昔年少曾買春，著盡榆錢不多價。", "春應索價來覓人，客氣今猶不相下。", "待領春風歸去家，家山卻有療愁花。", "鄰公大段作春計，小囿栽花今數世。", "但憎赤脚婢惱人，要逐丫鬟同拾翠。"]'),
('4dc06c1d-11df-4c59-bbf3-fa59d575a6a5','寧海道中','盧襄','宋','宋诗','song-poetry','','[]','又騎弱馬聳吟肩，數點旗尖破暝煙。',64,'全唐诗/poet.song.81000.json','["又騎弱馬聳吟肩，數點旗尖破暝煙。", "曉逕寒生梧葉露，晚風愁入雁行天。", "新年事業唯行路，故國生涯只釣船。", "早晚徑歸耕莽蒼，任從人笑客無氈。"]'),
('8e7b2da4-4126-4afe-89ac-2144d5dc5d4a','登摘星嶺','盧襄','宋','宋诗','song-poetry','','[]','自知牛鬬耳，不奈晚猿何。',48,'全唐诗/poet.song.81000.json','["自知牛鬬耳，不奈晚猿何。", "客鬢愁中老，秋山別後多。", "扁舟桃葉渡，夜雨竹枝歌。", "賴有皋盧碗，時堪戰睡魔。"]'),
('b05d1acf-2597-4aa7-87e3-eecc2d745370','和田南仲梅','盧襄','宋','宋诗','song-poetry','','[]','壽陽粧額太矜持，不待宮貂賜口脂。',64,'全唐诗/poet.song.81000.json','["壽陽粧額太矜持，不待宮貂賜口脂。", "惜妙風姿令雪妬，定真消息有春知。", "試看呵手攀條處，何似成陰着子時。", "莫遣王孫三弄絕，早尋疏影對江湄。"]'),
('20e4a6df-04fe-4ab2-809d-55e454d27341','酴醾花','盧襄','宋','宋诗','song-poetry','','[]','天將花王國艷殿春色，酴醾洗妝素頰相追陪。',80,'全唐诗/poet.song.81000.json','["天將花王國艷殿春色，酴醾洗妝素頰相追陪。", "絕勝濃英綴枝不韻李，堪友橫斜照水攙先梅。", "瑤池董雙成浴香肌露，竹林嵇叔夜醉玉山頹。", "風流何事不入錦囊句，清和天氣直挽青陽回。"]'),
('df48c0ed-fe76-4ec1-8d3c-fcfe8bca7071','遊南巖山','盧襄','宋','宋诗','song-poetry','','[]','不著烏紗只岸巾，尋山還得愛山人。',64,'全唐诗/poet.song.81000.json','["不著烏紗只岸巾，尋山還得愛山人。", "半空飛雨侵衣潤，入座晴嵐照眼新。", "風過松杉猶藴藉，雪消巖壑更精神。", "何時亦把任公釣，坐釣日東橫海鱗。"]'),
('4fe7b8bb-aa5a-4114-884c-6b7ffcf769bb','句  其一','盧襄','宋','宋诗','song-poetry','','[]','試將鍾子山水意，一洗退之冰炭腸。',16,'全唐诗/poet.song.81000.json','["試將鍾子山水意，一洗退之冰炭腸。"]'),
('67eb07a8-2b56-4dc4-b4e3-e7ea60211b3a','句  其二','盧襄','宋','宋诗','song-poetry','','[]','江鷗斜日浪清淺，巖桂小窗香有無。',16,'全唐诗/poet.song.81000.json','["江鷗斜日浪清淺，巖桂小窗香有無。"]'),
('491d2eb2-fad2-48cb-8f72-8d6268113301','句  其三','盧襄','宋','宋诗','song-poetry','','[]','井花汲水銀瓶冷，雁字吹高玉露寒。',16,'全唐诗/poet.song.81000.json','["井花汲水銀瓶冷，雁字吹高玉露寒。"]'),
('5a1d8e3e-00b8-4735-8d22-618829d11b0c','句  其四','盧襄','宋','宋诗','song-poetry','','[]','恍疑水底長流月，冷覺天圍不剩秋。',16,'全唐诗/poet.song.81000.json','["恍疑水底長流月，冷覺天圍不剩秋。"]'),
('fcc8eca1-96c5-4b44-9a61-1168bc967149','句  其五','盧襄','宋','宋诗','song-poetry','','[]','紅芭蕉映黑牽牛。',8,'全唐诗/poet.song.81000.json','["紅芭蕉映黑牽牛。"]'),
('9ac88a3d-76c2-4bf7-9058-3287bb510656','句  其六','盧襄','宋','宋诗','song-poetry','','[]','繭足相從南極邊，真機不落野狐涎。',16,'全唐诗/poet.song.81000.json','["繭足相從南極邊，真機不落野狐涎。"]'),
('bd602faf-1615-4248-ab42-81b795651d9d','句  其七','盧襄','宋','宋诗','song-poetry','','[]','強呼膏雨鳩閑管，乍有香泥燕猛忙。',16,'全唐诗/poet.song.81000.json','["強呼膏雨鳩閑管，乍有香泥燕猛忙。"]'),
('12fa8924-e964-4f96-af81-3e032c717a11','句  其八','盧襄','宋','宋诗','song-poetry','','[]','但數十家看鶴戶，與兩三隻釣魚船。',16,'全唐诗/poet.song.81000.json','["但數十家看鶴戶，與兩三隻釣魚船。"]'),
('b1dcaf4e-f06f-4549-88a9-df040bbda061','句  其九','盧襄','宋','宋诗','song-poetry','','[]','花外小樓雲罨畫，杏波晴葉退微紅。',16,'全唐诗/poet.song.81000.json','["花外小樓雲罨畫，杏波晴葉退微紅。"]'),
('d6270553-586e-44ee-afed-25a3d2baa959','句  其一○','盧襄','宋','宋诗','song-poetry','','[]','想行客過梅橋滑，免老農憂麥壠輕。',16,'全唐诗/poet.song.81000.json','["想行客過梅橋滑，免老農憂麥壠輕。"]'),
('07b6e564-1363-4365-a8ac-3a1a5440f181','句  其一一','盧襄','宋','宋诗','song-poetry','','[]','到底此君高韻在，清風兩腋爲渠生。',16,'全唐诗/poet.song.81000.json','["到底此君高韻在，清風兩腋爲渠生。"]'),
('db2f879c-612c-4367-b209-3ba97399903c','句  其一二','盧襄','宋','宋诗','song-poetry','','[]','姑射真人玉骨香，淡月微風惜良夜。',16,'全唐诗/poet.song.81000.json','["姑射真人玉骨香，淡月微風惜良夜。"]'),
('812d3363-085e-4b53-97b5-cf3ecce65959','句  其一三','盧襄','宋','宋诗','song-poetry','','[]','麥秋天氣朝朝變，蠶月人家處處忙。',16,'全唐诗/poet.song.81000.json','["麥秋天氣朝朝變，蠶月人家處處忙。"]'),
('432f5d18-7c8a-4f97-acbc-ab5ace5bc1ff','句  其一四','盧襄','宋','宋诗','song-poetry','','[]','春送人家入畫屏。',8,'全唐诗/poet.song.81000.json','["春送人家入畫屏。"]'),
('a427dfa3-f691-4aff-9cd0-b43ded119800','句  其一五','盧襄','宋','宋诗','song-poetry','','[]','天作人間小畫屏。',8,'全唐诗/poet.song.81000.json','["天作人間小畫屏。"]'),
('1eb7f36b-5b91-4a31-80d3-49606e5ebcf2','句  其一六','盧襄','宋','宋诗','song-poetry','','[]','客來如見小窗扉，便是山翁想山處。',16,'全唐诗/poet.song.81000.json','["客來如見小窗扉，便是山翁想山處。"]'),
('f92b57dd-8ef0-49b7-a404-56f8fcc79679','遊嵩山峻極中院作','王寀','宋','宋诗','song-poetry','','[]','爛紅一點出浮漚，夜坐嵩峰頂上頭。',32,'全唐诗/poet.song.81000.json','["爛紅一點出浮漚，夜坐嵩峰頂上頭。", "笑對僧窗談祖德，當年七十四回遊。"]'),
('b51b0dcf-ea2d-4bbe-a15c-7dd9cf682c98','浪花','王寀','宋','宋诗','song-poetry','','[]','一江秋水浸寒空，漁笛無端弄晚風。',32,'全唐诗/poet.song.81000.json','["一江秋水浸寒空，漁笛無端弄晚風。", "萬里波心誰折得，夕陽影裏碎殘紅。"]'),
('288754b1-8470-4c6b-96d9-71ae6cfb6632','題紫團山三十六景 迎陽峰','王寀','宋','宋诗','song-poetry','','[]','陽燧初升八極車，飛光猶带赤城霞。',32,'全唐诗/poet.song.81000.json','["陽燧初升八極車，飛光猶带赤城霞。", "山英固有葵心在，不許羣峰取次遮。"]'),
('b43bb3f3-263b-4dcf-99f8-7be67de0b9b5','題紫團山三十六景 倚秀峰','王寀','宋','宋诗','song-poetry','','[]','山形疊疊掩禪關，長薄蕭森落照間。',32,'全唐诗/poet.song.81000.json','["山形疊疊掩禪關，長薄蕭森落照間。", "天女欲誇新結束，都將翠藻簇煙鬟。"]'),
('38418711-2ec0-4b3e-9b27-698a13e66cb9','題紫團山三十六景 天杠','王寀','宋','宋诗','song-poetry','','[]','不分蒼梧西北傾，只將一柱與搘撐。',32,'全唐诗/poet.song.81000.json','["不分蒼梧西北傾，只將一柱與搘撐。", "而今六幕安然處，不使斯人樂太平。"]'),
('8a9758f7-a1f3-4fa7-9077-b1d7aa50e5f2','題紫團山三十六景 磨崖','王寀','宋','宋诗','song-poetry','','[]','家山本與語溪接，使節曾過砥柱遊。',32,'全唐诗/poet.song.81000.json','["家山本與語溪接，使節曾過砥柱遊。", "見說紫團銘勒處，西風千里重回頭。"]'),
('0b15e7c9-385f-48f1-8dc5-cdd3c427b2d9','題紫團山三十六景 濯纓溪','王寀','宋','宋诗','song-poetry','','[]','江上老人終獨往，塵中孺子果何知。',32,'全唐诗/poet.song.81000.json','["江上老人終獨往，塵中孺子果何知。", "溪翁欲識滄浪意，看取青霄浸月時。"]'),
('192b3230-7ce6-45d5-b917-53ac169c3b9d','題紫團山三十六景 東華表','王寀','宋','宋诗','song-poetry','','[]','借問遼東鶴，歸來得許悲。',24,'全唐诗/poet.song.81000.json','["借問遼東鶴，歸來得許悲。", "浮生隨念變，何待塚纍纍。"]'),
('5e433d42-004c-4bbf-ad9d-fba7f3a937d7','題紫團山三十六景 西華表','王寀','宋','宋诗','song-poetry','','[]','寄謝西朝相，神奸古有圖。',24,'全唐诗/poet.song.81000.json','["寄謝西朝相，神奸古有圖。", "如何延客處，庭燎照豐狐。"]'),
('03d4b473-7683-4fe4-be1c-04ebd23868ae','題紫團山三十六景 碧羅峰','王寀','宋','宋诗','song-poetry','','[]','風曳山妃带，雲穿木客衣。',48,'全唐诗/poet.song.81000.json','["風曳山妃带，雲穿木客衣。", "青松容嫋嫋，紅葉半飛飛。", "月爲幽人罷，春從舊處歸。", "明朝碧峰外，試與絆斜暉。"]'),
('ef65d75c-3fa4-4b59-938a-56cade4ee172','題紫團山三十六景 金屋山','王寀','宋','宋诗','song-poetry','','[]','雲拂層峰四面朝，朝陽北過更岧峣。',32,'全唐诗/poet.song.81000.json','["雲拂層峰四面朝，朝陽北過更岧峣。", "金仙自合居金屋，不爲膠東貯阿嬌。"]'),
('139ea32f-5df9-4fab-af7d-465740276f2c','題紫團山三十六景 鴟尾山','王寀','宋','宋诗','song-poetry','','[]','天借溪頭奠佛居，全將帝所作規模。',32,'全唐诗/poet.song.81000.json','["天借溪頭奠佛居，全將帝所作規模。", "漢家不識真鴟尾，何笑區區問越巫。"]'),
('b6ccf12f-b3e1-492d-b5fa-b7cd446997a5','題紫團山三十六景 山翁崖','王寀','宋','宋诗','song-poetry','','[]','仙翁愛山居，留形在東嶺。',49,'全唐诗/poet.song.81000.json','["仙翁愛山居，留形在東嶺。", "風林度嘯聲，夢鄉壑漾飛影。", "華髪欲蕭蕭，青瞳猶耿耿。", "追蹤有名流，回首發深省。"]'),
('e184b5af-b146-4e3b-9248-56e39091d7f9','題紫團山三十六景 駐雲亭','王寀','宋','宋诗','song-poetry','','[]','塵跡初從世網收，一邱一壑此優游。',32,'全唐诗/poet.song.81000.json','["塵跡初從世網收，一邱一壑此優游。", "卻應化作飛雲片，長向亭前伴客留。"]'),
('4000d8d2-fb9e-452c-937c-3b58204b9373','題紫團山三十六景 老人峰','王寀','宋','宋诗','song-poetry','','[]','江廬已別游河侶，商洛休陪謁漢寶。',32,'全唐诗/poet.song.81000.json','["江廬已別游河侶，商洛休陪謁漢寶。", "獨立南山千嶂裏，長將萬壽祝巖宸。"]'),
('ba39c663-1d63-4b37-a257-3194a9823d3d','題紫團山三十六景 南極園','王寀','宋','宋诗','song-poetry','','[]','清徵有逸仙，疇昔下南極。',61,'全唐诗/poet.song.81000.json','["清徵有逸仙，疇昔下南極。", "紫氣遠成圖，照此太白域。", "芝田手所耘，地靈亦知嗇。", "雲根一十八，劚握安可得。", "惟餘亂峰間，喬林竦春寒色。"]'),
('85a28e09-0d2b-4b22-86a0-da36e7c8f1d6','謁王寀','鄭州書生','宋','宋诗','song-poetry','','[]','照影空濛山色裏，背人撲鹿水禽飛。',32,'全唐诗/poet.song.81000.json','["照影空濛山色裏，背人撲鹿水禽飛。", "梅花落盡春寒在，細雨斜風點客衣。"]'),
('9249daf5-f156-488e-95b6-45be30cfe555','懷安官舍病起九日作','蘇元老','宋','宋诗','song-poetry','','[]','籬菊今年拆最繁，繞叢新折上雕盤。',64,'全唐诗/poet.song.81000.json','["籬菊今年拆最繁，繞叢新折上雕盤。", "病知佳節霜風冷，喜對高堂骨肉歡。", "久廢笑歌慵飲酒，只聞兒女勸加餐。", "如何猛下蔾牀去，又逐鴛鴻振羽翰。"]'),
('c872ffc9-e95c-483d-ace5-248cae4ccce1','十日菊','蘇元老','宋','宋诗','song-poetry','','[]','寂寞東籬下，凝煙簇簇芳。',48,'全唐诗/poet.song.81000.json','["寂寞東籬下，凝煙簇簇芳。", "無人賞幽艷，有蝶戀清香。", "不伴茱萸飲，空教蟋蟀藏。", "重陽雖已過，來歲可能忘。"]'),
('c6d37e4a-cc86-44cd-8708-6ce65ae6fd59','重陽述懷','蘇元老','宋','宋诗','song-poetry','','[]','屋前寒雀作饑聲，老大都因節物驚。',64,'全唐诗/poet.song.81000.json','["屋前寒雀作饑聲，老大都因節物驚。", "九日縱棄經夕飲，百年能病幾番酲。", "白衣於我似無舊，黄菊對人偏有情。", "醉裏高歌開口笑，世間名利一毫輕。"]'),
('784d32bb-650d-4f7b-ae8f-62fc3a7f7ea1','贈撫琴劉伯華','蘇元老','宋','宋诗','song-poetry','','[]','公子方年少，絲桐長有名。',48,'全唐诗/poet.song.81000.json','["公子方年少，絲桐長有名。", "曲雖仍舊譜，指要發新聲。", "澗落泉初響，風清月正明。", "起予千古意，惻悵不勝情。"]'),
('d9a4f3cd-c532-4152-8fb9-367e563d8224','贈棋士兼相','蘇元老','宋','宋诗','song-poetry','','[]','嵯峨遠遊冠，過我田里居。',144,'全唐诗/poet.song.81000.json','["嵯峨遠遊冠，過我田里居。", "手談達要妙，心計有卷舒。", "把握殺活機，操持開闔樞。", "總總如亂兵，紛紛若奔車。", "觀者皆怵惕，敵人更揶揄。", "一著起疲廢，萬口驚喧呼。", "巧思自神授，智慧非常拘。", "又聞風鑒精，許與且不渝。", "羣公贈詩文，稱述良非虛。", "自昔少兼能，今挾二術俱。", "奕秋與許負，異世同一軀。", "惜哉惟藝名，問學當何時。"]'),
('353af805-1e05-420d-b8cf-18bb360e6de4','夜過鄱陽湖三首  其一','章誼','宋','宋诗','song-poetry','','[]','風驅殘暑月侵衣，仙客乘槎八月歸。',32,'全唐诗/poet.song.81000.json','["風驅殘暑月侵衣，仙客乘槎八月歸。", "萬頃平湖波不動，夜深鳴櫓渡如飛。"]'),
('18ebeee8-e6f7-4c6a-b51d-c3f78eec10cc','夜過鄱陽湖三首  其二','章誼','宋','宋诗','song-poetry','','[]','平湖聞說浪如山，今夜扁舟在還。',31,'全唐诗/poet.song.81000.json','["平湖聞說浪如山，今夜扁舟在還。", "天象水光俱一色，此身安渡斗牛間。"]'),
('0c09a8ee-6a88-4631-9c48-88111324b2c0','夜過鄱陽湖三首  其三','章誼','宋','宋诗','song-poetry','','[]','鄱陽湖面三百里，草樹雲山望裏無。',32,'全唐诗/poet.song.81000.json','["鄱陽湖面三百里，草樹雲山望裏無。", "月夜扁舟訝何許，一天星漢近相趨。"]'),
('eb64a2a8-bcb2-4457-96b3-056361c64b35','題饒州永平監百葉黄梅','章誼','宋','宋诗','song-poetry','','[]','百葉黄梅照小堂，江南春色冠年芳。',64,'全唐诗/poet.song.81000.json','["百葉黄梅照小堂，江南春色冠年芳。", "洛妃不露朝霞臉，秦女聊開散麝粧。", "已薦香風來枕席，更留美實特杯觴。", "一枝今日欲誰贈，且伴釵頭金鳳凰。"]'),
('8220d3e0-343b-4f68-a49c-bbdfe1f82f83','紹興府寒食湖山遊人','章誼','宋','宋诗','song-poetry','','[]','江南春色勝常年，蠶婦耕夫笑語妍。',64,'全唐诗/poet.song.81000.json','["江南春色勝常年，蠶婦耕夫笑語妍。", "日永湖山縱遊屐，夜深簫鼓更劃船。", "羈人半作吳儂語，騷客休吟楚些篇。", "服叛招攜有長算，會移豐樂到齊燕。"]'),
('07eb9d4b-489f-42bf-b945-cb0f41df1f47','謝事東歸史館相公出餞都門寵貺嘉什感舊愴別黯然衰悰謹次疆韻','章誼','宋','宋诗','song-poetry','','[]','平生親契保初終，夢幻凋零念德宮。',64,'全唐诗/poet.song.81000.json','["平生親契保初終，夢幻凋零念德宮。", "朝路時來陪聖相，家山老去逐逋翁。", "珠璣落紙吟豪健，蘭菊浮觴醉面紅。", "台曜轉高無復見，除非書雁到江東。"]');
